const app = document.querySelector("#app");

function routeFromHash() {
  const raw = window.location.hash.replace(/^#\/?/, "").trim();
  const [routePart = "", ...targetParts] = raw.split("/");
  const routeKey = routeAliases[routePart] || routePart || "home";
  return {
    route: Object.prototype.hasOwnProperty.call(ROUTES, routeKey) ? routeKey : "home",
    target: decodeURIComponent(targetParts.join("/") || routeAliasTargets[routePart] || "").trim(),
  };
}

function setHash(path) {
  if (window.location.hash !== path) window.location.hash = path;
}

async function init() {
  updateRouteState();
  bindStaticEvents();
  try {
    const [recipeResponse, profileResponse, familyResponse, invoiceHistoryResponse, packFitResponse, useUpResponse, plannerResponse, registryResponse, macroResponse, optionsPolicyResponse, postboxResponse] = await Promise.all([
      fetch("./data/recipe-index.json", { cache: "no-store" }),
      fetch("./data/profile-index.json", { cache: "no-store" }),
      fetch("./data/sku-pack-families.json", { cache: "no-store" }),
      fetch("./data/recipe-invoice-save-history.json", { cache: "no-store" }).catch(() => null),
      fetch("./data/week-pack-fit/latest.receipt.json", { cache: "no-store" }).catch(() => null),
      fetch("./data/use-up-stock-register.json", { cache: "no-store" }).catch(() => null),
      fetch("./data/planner-week-template.json", { cache: "no-store" }),
      fetch("./data/planner-filter-registry.json", { cache: "no-store" }),
      fetch("./data/planner-macro-policy.json", { cache: "no-store" }),
      fetch("./data/planner-options-policy.json", { cache: "no-store" }),
      fetch("./data/review-postbox-config.json", { cache: "no-store" }).catch(() => null),
    ]);
    if (!recipeResponse.ok) throw new Error(`recipe-index HTTP ${recipeResponse.status}`);
    if (!profileResponse.ok) throw new Error(`profile-index HTTP ${profileResponse.status}`);
    if (!familyResponse.ok) throw new Error(`sku-pack-families HTTP ${familyResponse.status}`);
    if (!plannerResponse.ok) throw new Error(`planner-week-template HTTP ${plannerResponse.status}`);
    if (!registryResponse.ok) throw new Error(`planner-filter-registry HTTP ${registryResponse.status}`);
    if (!macroResponse.ok) throw new Error(`planner-macro-policy HTTP ${macroResponse.status}`);
    if (!optionsPolicyResponse.ok) throw new Error(`planner-options-policy HTTP ${optionsPolicyResponse.status}`);
    state.recipeIndex = await recipeResponse.json();
    state.profileIndex = await profileResponse.json();
    state.skuPackFamilies = await familyResponse.json();
    if (invoiceHistoryResponse && invoiceHistoryResponse.ok) state.recipeInvoiceSaveHistory = await invoiceHistoryResponse.json();
    if (packFitResponse && packFitResponse.ok) {
      state.weekPackFitLatestReceipt = await packFitResponse.json();
      state.weekPackFitReceipt = state.weekPackFitLatestReceipt;
    }
    if (useUpResponse && useUpResponse.ok) state.useUpStockRegister = await useUpResponse.json();
    state.plannerTemplateData = await plannerResponse.json();
    state.plannerFilterRegistry = await registryResponse.json();
    state.macroPolicyData = await macroResponse.json();
    state.plannerOptionsPolicyData = await optionsPolicyResponse.json();
    state.profileGoalDraft = normalizeProfileGoalDraft(state.profileGoalDraft);
    initializePlannerWeekStores();
    state.weekPackFitReceiptStore = normalizeWeekPackFitReceiptStore(state.weekPackFitReceiptStore);
    syncWeekPackFitReceiptForWeek(state.shoppingWeekStart);
    state.plannerRecipeUsageDraft = normalizePlannerRecipeUsageDraft(state.plannerRecipeUsageDraft);
    state.plannerWeekHistory = normalizePlannerWeekHistory(state.plannerWeekHistory);
    pruneStaleRecipeDecisions();
    if (postboxResponse && postboxResponse.ok) state.postboxConfig = await postboxResponse.json();
    chooseInitialSelections();
    render();
  } catch (error) {
    app.innerHTML = `
      <section class="loading-panel">
        <h1>Data could not load</h1>
        <p>${escapeHtml(error.message || "Check the data folder and local preview server.")}</p>
      </section>
    `;
  }
}

function bindStaticEvents() {
  window.addEventListener("hashchange", () => {
    updateRouteState();
    render();
  });

  document.querySelector(".app-header")?.addEventListener("click", (event) => {
    const link = event.target.closest("a[href]");
    if (!link) return;
    event.preventDefault();
    setHash(link.getAttribute("href"));
  });
}

function updateRouteState() {
  const next = routeFromHash();
  state.route = next.route;
  state.target = next.target;
  if (state.route === "collection" && state.target) {
    const [collectionView, ...targetParts] = state.target.split("/");
    if (["recipes", "ingredients"].includes(collectionView)) {
      state.collectionView = collectionView;
      state.target = targetParts.join("/").trim();
    }
  } else if (state.route === "collection") {
    state.collectionView = "recipes";
  }
  document.body.dataset.route = state.route;
  document.title = state.route === "home" ? "Diet Planner V4" : `${ROUTES[state.route]} - Diet Planner V4`;
  const currentRoute = document.querySelector("[data-current-route]");
  if (currentRoute) currentRoute.textContent = ROUTES[state.route] || "Home";
  document.querySelectorAll("[data-route-link]").forEach((link) => {
    link.classList.toggle("active", link.dataset.routeLink === state.route);
  });
}

function chooseInitialSelections() {
  const approved = approvedRecipes();
  const queue = reviewQueue();
  if (!state.selectedCollectionId && approved[0]) state.selectedCollectionId = recipeKey(approved[0]);
  if (!state.selectedShoppingId && approved[0]) state.selectedShoppingId = recipeKey(approved[0]);
  if (state.target) {
    const match = recipes().find((recipe) => recipeMatches(recipe, state.target));
    if (match && state.route === "collection") {
      state.selectedCollectionId = recipeKey(match);
      state.selectedShoppingId = recipeKey(match);
    } else if (match?.status === "approved") {
      state.selectedCollectionId = recipeKey(match);
      state.selectedShoppingId = recipeKey(match);
    }
    if (match && queue.includes(match)) state.selectedCollectionId = recipeKey(match);
  }
  const firstPerson = state.profileIndex?.people?.[0]?.person;
  if (firstPerson && !currentProfile()) state.selectedProfile = firstPerson;
}

function render() {
  updateRouteState();
  if (state.route === "home") renderHome();
  if (state.route === "acceptance") renderAcceptance();
  if (state.route === "collection") renderCollection();
  if (state.route === "shopping") renderShopping();
  if (state.route === "profiles") renderProfiles();
  if (state.route === "planner") renderPlanner();
}

function currentSpotlight() {
  const approved = approvedRecipes();
  const recipe = approved[approved.length - 1];
  if (!recipe) return fallbackSpotlight;
  return {
    id: recipeKey(recipe),
    title: recipe.short_title || recipe.title || "Recipe",
    status: "In database",
    summary: recipe.summary || `${mealTypeLabel(recipe.meal_type)} for ${(recipe.people || []).join(", ") || "the household"}`,
    image: heroImage(recipe),
    cardUrl: recipeCardUrl(recipe, "home"),
    details: spotlightDetails(recipe),
  };
}

function recipeCardUrl(recipe, fromRoute = "home") {
  const raw = recipe?.recipe_card_url || "";
  if (!raw || raw.startsWith("#/")) return raw || "#/";
  const route = Object.prototype.hasOwnProperty.call(ROUTES, fromRoute) ? fromRoute : "home";
  const hashIndex = raw.indexOf("#");
  const base = normalizeRecipeCardPath(hashIndex === -1 ? raw : raw.slice(0, hashIndex));
  const hash = hashIndex === -1 ? "" : raw.slice(hashIndex);
  const separator = base.includes("?") ? "&" : "?";
  const version = recipeCardVersion(recipe);
  const versionParam = version ? `&v=${encodeURIComponent(version)}` : "";
  return `${base}${separator}from=${encodeURIComponent(route)}${versionParam}${hash}`;
}

function normalizeRecipeCardPath(path) {
  const value = String(path || "").trim();
  if (!value || value.startsWith("#/")) return value;
  if (/^(https?:|file:|\/)/i.test(value)) return value;
  const outputMatch = value.match(/^(?:\.{1,2}\/)*(?:V4\/)?output\/(.+)$/);
  if (outputMatch) return `/output/${outputMatch[1]}`;
  return value;
}

function recipeCardVersion(recipe) {
  const history = Array.isArray(recipe?.status_history) ? recipe.status_history : [];
  const latestHistory = history.length ? history[history.length - 1]?.at_uk : "";
  return (
    recipe?.review_revision ||
    recipe?.review_ready_after_repair?.updated_at_uk ||
    recipe?.repair_completed_at_uk ||
    recipe?.last_repair_completed_at_uk ||
    recipe?.updated_at_uk ||
    recipe?.last_updated_uk ||
    latestHistory ||
    (isRepairedReviewRow(recipe) ? state.recipeIndex?.meta?.last_repair_update_uk : "") ||
    ""
  );
}

function isRepairedReviewRow(recipe) {
  const note = String(recipe?.review_note || "");
  return (
    recipe?.status === "needs_review" &&
    ["ready_for_luke_review", "needs_review", "ready_for_review"].includes(String(recipe?.review_status || "")) &&
    /repaired|re-review|repair/i.test(note)
  );
}

function spotlightDetails(recipe) {
  const details = [];
  if (recipe.meal_type) details.push(mealTypeLabel(recipe.meal_type));
  if (Array.isArray(recipe.people) && recipe.people.length) details.push(recipe.people.join(", "));
  if (recipe.timing?.display) details.push(recipe.timing.display);
  Object.entries(recipe.plate || {}).slice(0, 3).forEach(([person, plate]) => {
    const values = Object.values(plate || {}).slice(0, 2).join(", ");
    if (values) details.push(`${person}: ${values}`);
  });
  return details.length ? details.slice(0, 7) : fallbackSpotlight.details;
}

function renderHome() {
  const queue = reviewQueue();
  const repairs = repairQueue();
  const firstReview = queue[0];
  const sections = homeMenuSections(firstReview, queue, repairs);
  app.innerHTML = `
    <section class="home-hero">
      <div>
        <h1>Diet Planner V4</h1>
        <p>Choose where to work. Planner builds the week; Acceptance checks new recipes before they join the database.</p>
      </div>
      ${firstReview ? homeReviewNotice(firstReview, queue.length) : `
        <div class="home-notice ${repairs.length ? "repair" : "calm"}">
          <strong>${repairs.length ? "Recheck queue active" : "No recipe waiting"}</strong>
          <span>${repairs.length ? `${repairs.length} recipe${repairs.length === 1 ? "" : "s"} need recheck before planner use.` : "Acceptance is clear right now."}</span>
        </div>
      `}
    </section>

    <section class="home-tabs" aria-label="Diet Planner sections">
      ${sections.map(homeSectionTab).join("")}
    </section>
  `;
  bindRouteLinks();
}

