function homeReviewNotice(recipe, count) {
  const extra = count > 1 ? `${count} recipes waiting` : "1 recipe waiting";
  return `
    <aside class="home-notice active" aria-label="Recipe review notification">
      <span class="home-notice-image" style="background-image: url('${escapeAttr(heroImage(recipe))}')"></span>
      <span class="notice-dot"></span>
      <span>
        <strong>New recipe available for review</strong>
        <span>${escapeHtml(recipe.short_title || recipe.title || "Recipe")} - ${escapeHtml(extra)}</span>
      </span>
      <a class="primary-action" href="#/acceptance">Review</a>
    </aside>
  `;
}

function homeSectionTab(section) {
  return `
    <a class="home-tab ${escapeAttr(section.tone)}" href="${escapeAttr(section.href)}" aria-label="${escapeAttr(`${section.title}: ${section.action}`)}">
      <span class="home-tab-icon" aria-hidden="true">${homeSectionIcon(section.icon)}</span>
      <span class="home-tab-copy">
        <span>${escapeHtml(section.title)}</span>
        <strong>${escapeHtml(section.action)}</strong>
        <small>${escapeHtml(section.detail)}</small>
      </span>
      <span class="home-tab-arrow" aria-hidden="true"><svg viewBox="0 0 24 24"><path d="M9 5l7 7-7 7" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"/></svg></span>
      ${section.badgeText ? `<em>${escapeHtml(section.badgeText)}</em>` : ""}
    </a>
  `;
}

