    collection: `<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M5 6h14M5 12h14M5 18h14" fill="none" stroke="currentColor" stroke-width="2.6" stroke-linecap="round"/><path d="M8 4.5a1.5 1.5 0 1 1 0 3 1.5 1.5 0 0 1 0-3ZM15 10.5a1.5 1.5 0 1 1 0 3 1.5 1.5 0 0 1 0-3ZM10 16.5a1.5 1.5 0 1 1 0 3 1.5 1.5 0 0 1 0-3Z" fill="currentColor"/></svg>`,
    shopping: `<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M7 9h12l-1.1 8.2a2 2 0 0 1-2 1.8H9.1a2 2 0 0 1-2-1.8L6 9Z" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linejoin="round"/><path d="M9 9a3 3 0 0 1 6 0" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round"/><path d="M5 9h14" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round"/></svg>`,
    profiles: `<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M9 11a3 3 0 1 0 0-6 3 3 0 0 0 0 6ZM16.5 12a2.5 2.5 0 1 0 0-5 2.5 2.5 0 0 0 0 5ZM4.5 19a4.5 4.5 0 0 1 9 0M13.5 18.5a3.5 3.5 0 0 1 6.5 0" fill="none" stroke="currentColor" stroke-width="2.3" stroke-linecap="round"/></svg>`,
