function normalizePlannerOptionsCache(cache) {
  if (!cache || typeof cache !== "object") {
    return {
      schema_version: "v4.planner_options_cache.1",
      draft_only: true,
      status: "not_built",
      day_options: {},
      shopping_horizon: plannerEmptyShoppingHorizon(""),
      week_efficiency: plannerEmptyWeekEfficiencySummary(),
      warnings: [],
    };
  }
  return {
    schema_version: "v4.planner_options_cache.1",
    draft_only: true,
    status: cache.status || "not_built",
    status_label: cache.status_label || "",
    built_at: cache.built_at || "",
    week_view: cache.week_view || "",
    active_week_start: cache.active_week_start || cache.week_start || "",
    week_start: cache.week_start || cache.active_week_start || "",
    week_end: cache.week_end || "",
    template_id: cache.template_id || "",
    policy_id: cache.policy_id || "",
    fingerprint: cache.fingerprint || "",
    stale: Boolean(cache.stale),
    usable_recipe_count: Number(cache.usable_recipe_count || 0),
    review_only_recipe_count: Number(cache.review_only_recipe_count || 0),
    total_stored_options: Number(cache.total_stored_options || 0),
    total_raw_combinations: Number(cache.total_raw_combinations || 0),
    week_efficiency: normalizePlannerWeekEfficiencySummary(cache.week_efficiency),
    week_score: normalizePlannerWeekScore(cache.week_score),
    week_score_alternatives: normalizePlannerWeekScoreAlternatives(cache.week_score_alternatives),
    day_options: cache.day_options && typeof cache.day_options === "object" ? cache.day_options : {},
    shopping_horizon: normalizePlannerShoppingHorizon(cache.shopping_horizon),
    low_waste_build: cache.low_waste_build && typeof cache.low_waste_build === "object" ? cache.low_waste_build : null,
    warnings: Array.isArray(cache.warnings) ? cache.warnings : [],
  };
}

