function plannerSlotRecordLabel(slot) {
  return [slot?.day, slot?.time, slot?.title || slot?.meal_category || "meal"].filter(Boolean).join(" ");
}

function plannerWeekReadinessDetail(summary) {
  if (!summary) return "Week readiness not checked.";
  if (summary.is_complete && summary.needs_stock_confirmation) return `${number(summary.selected_recipe_slot_count)} of ${number(summary.required_recipe_slot_count)} required recipe slots are filled; ${number(summary.assumed_stock_use_count)} assumed leftover item${summary.assumed_stock_use_count === 1 ? "" : "s"} need checking.`;
  if (summary.is_complete) return `${number(summary.selected_recipe_slot_count)} of ${number(summary.required_recipe_slot_count)} required recipe slots are filled.`;
  const parts = [
    `${number(summary.selected_recipe_slot_count)} of ${number(summary.required_recipe_slot_count)} required recipe slots filled`,
  ];
  if (summary.missing_required_recipe_slot_count) parts.push(`${number(summary.missing_required_recipe_slot_count)} missing`);
  if (summary.gap_day_count) parts.push(`${number(summary.gap_day_count)} gap day${summary.gap_day_count === 1 ? "" : "s"}`);
  if (summary.partial_day_count) parts.push(`${number(summary.partial_day_count)} partial day${summary.partial_day_count === 1 ? "" : "s"}`);
  if (summary.missing_slot_labels?.length) parts.push(`first gaps: ${summary.missing_slot_labels.slice(0, 3).join(", ")}`);
  return parts.join("; ");
}

function normalizePlannerWeekEfficiencySummary(summary) {
  const empty = plannerEmptyWeekEfficiencySummary();
  if (!summary || typeof summary !== "object") return empty;
  return Object.fromEntries(Object.keys(empty).map((key) => [key, Number(summary[key] || 0)]));
}

function normalizePlannerWeekScore(score) {
  if (!score || typeof score !== "object") {
    return {
      schema_version: "v4.week_score.1",
      score: 0,
      label: "",
      components: {},
      metrics: {},
      reasons: [],
    };
  }
  return {
    schema_version: "v4.week_score.1",
    score: Math.round(Number(score.score || 0)),
    label: score.label || "",
    components: score.components && typeof score.components === "object" ? score.components : {},
    metrics: score.metrics && typeof score.metrics === "object" ? score.metrics : {},
    reasons: Array.isArray(score.reasons) ? score.reasons.map(String).filter(Boolean).slice(0, 6) : [],
  };
}

function normalizePlannerWeekScoreAlternatives(alternatives) {
  return (Array.isArray(alternatives) ? alternatives : [])
    .map((item) => ({
      label: item?.label || "",
      score: Math.round(Number(item?.score || 0)),
      selected_option_by_day: item?.selected_option_by_day && typeof item.selected_option_by_day === "object" ? item.selected_option_by_day : {},
      reasons: Array.isArray(item?.reasons) ? item.reasons.map(String).filter(Boolean).slice(0, 4) : [],
      metrics: item?.metrics && typeof item.metrics === "object" ? item.metrics : {},
    }))
    .filter((item) => item.score > 0 || Object.keys(item.selected_option_by_day).length)
    .slice(0, Math.max(1, Number(plannerWeekScorePolicy().max_alternatives || 5)));
}

function normalizePlannerReviewDraft(draft) {
  if (!draft || typeof draft !== "object") {
    return {
      schema_version: "v4.planner_review_draft.1",
      draft_only: true,
      selected_option_by_day: {},
      locked_slots: {},
      blocked_recipes_by_slot: {},
      blocked_recipe_ids: [],
      updated_at: "",
    };
  }
  return {
    schema_version: "v4.planner_review_draft.1",
    draft_only: true,
    selected_option_by_day: draft.selected_option_by_day && typeof draft.selected_option_by_day === "object" ? draft.selected_option_by_day : {},
    locked_slots: draft.locked_slots && typeof draft.locked_slots === "object" ? draft.locked_slots : {},
    blocked_recipes_by_slot: draft.blocked_recipes_by_slot && typeof draft.blocked_recipes_by_slot === "object" ? draft.blocked_recipes_by_slot : {},
    blocked_recipe_ids: Array.isArray(draft.blocked_recipe_ids) ? draft.blocked_recipe_ids : [],
    updated_at: draft.updated_at || "",
  };
}

function normalizePlannerRecipeUsageDraft(draft) {
  if (!draft || typeof draft !== "object") {
    return {
      schema_version: "v4.planner_recipe_usage_draft.1",
      draft_only: true,
      last_used_by_recipe_id: {},
      last_used_week_by_recipe_id: {},
      cooldown_days: plannerOptionsPolicy().default_cooldown_days,
      updated_at: "",
    };
  }
  return {
    schema_version: "v4.planner_recipe_usage_draft.1",
    draft_only: true,
    last_used_by_recipe_id: draft.last_used_by_recipe_id && typeof draft.last_used_by_recipe_id === "object" ? draft.last_used_by_recipe_id : {},
    last_used_week_by_recipe_id: draft.last_used_week_by_recipe_id && typeof draft.last_used_week_by_recipe_id === "object" ? draft.last_used_week_by_recipe_id : {},
    cooldown_days: Number(draft.cooldown_days || plannerOptionsPolicy().default_cooldown_days || 7),
    updated_at: draft.updated_at || "",
  };
}

function normalizePlannerWeekHistory(raw) {
  const weeks = raw?.weeks && typeof raw.weeks === "object" ? raw.weeks : {};
  const normalizedWeeks = {};
  Object.entries(weeks).forEach(([weekStart, record]) => {
    const key = plannerNormalizeWeekStartKey(weekStart);
    if (!key || !record || typeof record !== "object") return;
    normalizedWeeks[key] = {
      week_start: key,
      week_end: plannerDateKey(plannerAddDays(plannerDateFromKey(key), 6)),
      status: record.status || "draft",
      template_id: record.template_id || "",
      fingerprint: record.fingerprint || "",
      updated_at: record.updated_at || "",
      built_at: record.built_at || "",
      locked_at: record.locked_at || "",
      total_stored_options: Number(record.total_stored_options || 0),
      week_efficiency: normalizePlannerWeekEfficiencySummary(record.week_efficiency),
      selected_recipe_ids: Array.isArray(record.selected_recipe_ids) ? [...new Set(record.selected_recipe_ids.map(String).filter(Boolean))] : [],
      day_records: Array.isArray(record.day_records) ? record.day_records : [],
      slot_records: Array.isArray(record.slot_records) ? record.slot_records : [],
    };
  });
  return {
    schema_version: "v4.planner_week_history_draft.1",
    draft_only: true,
    weeks: normalizedWeeks,
    updated_at: raw?.updated_at || "",
  };
}

function normalizePlannerDraftWeekStore(raw, template) {
  const activeWeek = plannerActiveWeekStartKey();
  const rawWeeks = raw?.schema_version === "v4.planner_preference_weeks.1" && raw.weeks && typeof raw.weeks === "object" ? raw.weeks : null;
  const weeks = {};
  if (rawWeeks) {
    Object.entries(rawWeeks).forEach(([weekStart, draft]) => {
      const key = plannerNormalizeWeekStartKey(weekStart);
      if (!key) return;
      weeks[key] = normalizePlannerDraft(draft, template);
    });
  } else if (raw && typeof raw === "object") {
    weeks[activeWeek] = normalizePlannerDraft(raw, template);
  }
  if (!weeks[activeWeek]) weeks[activeWeek] = normalizePlannerDraft(null, template);
  return {
    schema_version: "v4.planner_preference_weeks.1",
    draft_only: true,
    active_week_start: activeWeek,
    weeks,
    updated_at: raw?.updated_at || "",
  };
}

function normalizePlannerOptionsCacheWeekStore(raw) {
  const activeWeek = plannerActiveWeekStartKey();
  const rawWeeks = raw?.schema_version === "v4.planner_options_cache_weeks.1" && raw.weeks && typeof raw.weeks === "object" ? raw.weeks : null;
  const weeks = {};
  if (rawWeeks) {
    Object.entries(rawWeeks).forEach(([weekStart, cache]) => {
      const key = plannerNormalizeWeekStartKey(weekStart);
      if (!key) return;
      weeks[key] = normalizePlannerOptionsCache(cache);
    });
  } else if (raw && typeof raw === "object" && raw.status) {
    weeks[activeWeek] = normalizePlannerOptionsCache(raw);
  }
  if (!weeks[activeWeek]) weeks[activeWeek] = normalizePlannerOptionsCache(null);
  return {
    schema_version: "v4.planner_options_cache_weeks.1",
    draft_only: true,
    active_week_start: activeWeek,
    weeks,
    updated_at: raw?.updated_at || "",
  };
}

function normalizePlannerReviewDraftWeekStore(raw) {
  const activeWeek = plannerActiveWeekStartKey();
  const rawWeeks = raw?.schema_version === "v4.planner_review_draft_weeks.1" && raw.weeks && typeof raw.weeks === "object" ? raw.weeks : null;
  const weeks = {};
  if (rawWeeks) {
    Object.entries(rawWeeks).forEach(([weekStart, draft]) => {
      const key = plannerNormalizeWeekStartKey(weekStart);
      if (!key) return;
      weeks[key] = normalizePlannerReviewDraft(draft);
    });
  } else if (raw && typeof raw === "object") {
    weeks[activeWeek] = normalizePlannerReviewDraft(raw);
  }
  if (!weeks[activeWeek]) weeks[activeWeek] = normalizePlannerReviewDraft(null);
  return {
    schema_version: "v4.planner_review_draft_weeks.1",
    draft_only: true,
    active_week_start: activeWeek,
    weeks,
    updated_at: raw?.updated_at || "",
  };
}

function initializePlannerWeekStores() {
  state.plannerActiveWeekStart = plannerNormalizeWeekStartKey(state.plannerActiveWeekStart);
  const template = currentPlannerTemplate() || plannerTemplates()[0] || null;
  state.plannerDraftStore = normalizePlannerDraftWeekStore(state.plannerDraft, template);
  state.plannerOptionsCacheStore = normalizePlannerOptionsCacheWeekStore(state.plannerOptionsCache);
  state.plannerReviewDraftStore = normalizePlannerReviewDraftWeekStore(state.plannerReviewDraft);
  syncActivePlannerWeekState(template);
  saveLocalJson(PLANNER_ACTIVE_WEEK_KEY, state.plannerActiveWeekStart);
}

function syncActivePlannerWeekState(template = currentPlannerTemplate()) {
  const weekStart = plannerActiveWeekStartKey();
  state.plannerDraftStore = normalizePlannerDraftWeekStore(state.plannerDraftStore || state.plannerDraft, template);
  state.plannerOptionsCacheStore = normalizePlannerOptionsCacheWeekStore(state.plannerOptionsCacheStore || state.plannerOptionsCache);
  state.plannerReviewDraftStore = normalizePlannerReviewDraftWeekStore(state.plannerReviewDraftStore || state.plannerReviewDraft);
  if (!state.plannerDraftStore.weeks[weekStart]) state.plannerDraftStore.weeks[weekStart] = normalizePlannerDraft(null, template);
  if (!state.plannerOptionsCacheStore.weeks[weekStart]) state.plannerOptionsCacheStore.weeks[weekStart] = normalizePlannerOptionsCache(null);
  if (!state.plannerReviewDraftStore.weeks[weekStart]) state.plannerReviewDraftStore.weeks[weekStart] = normalizePlannerReviewDraft(null);
  state.plannerDraftStore.active_week_start = weekStart;
  state.plannerOptionsCacheStore.active_week_start = weekStart;
  state.plannerReviewDraftStore.active_week_start = weekStart;
  state.plannerDraft = normalizePlannerDraft(state.plannerDraftStore.weeks[weekStart], template);
  state.plannerOptionsCache = normalizePlannerOptionsCache(state.plannerOptionsCacheStore.weeks[weekStart]);
  state.plannerReviewDraft = normalizePlannerReviewDraft(state.plannerReviewDraftStore.weeks[weekStart]);
}

function savePlannerDraftStore() {
  const weekStart = plannerActiveWeekStartKey();
  state.plannerDraftStore = normalizePlannerDraftWeekStore(state.plannerDraftStore || {}, currentPlannerTemplate());
  state.plannerDraftStore.weeks[weekStart] = normalizePlannerDraft(state.plannerDraft, currentPlannerTemplate());
  state.plannerDraftStore.active_week_start = weekStart;
  state.plannerDraftStore.updated_at = new Date().toISOString();
  saveLocalJson(PLANNER_DRAFT_KEY, state.plannerDraftStore);
  saveLocalJson(PLANNER_ACTIVE_WEEK_KEY, weekStart);
}

function savePlannerOptionsCacheStore() {
  const weekStart = plannerActiveWeekStartKey();
  state.plannerOptionsCacheStore = normalizePlannerOptionsCacheWeekStore(state.plannerOptionsCacheStore || {});
  state.plannerOptionsCacheStore.weeks[weekStart] = normalizePlannerOptionsCache(state.plannerOptionsCache);
  state.plannerOptionsCacheStore.active_week_start = weekStart;
  state.plannerOptionsCacheStore.updated_at = new Date().toISOString();
  saveLocalJson(PLANNER_OPTIONS_CACHE_KEY, state.plannerOptionsCacheStore);
}

function savePlannerReviewDraftStore() {
  const weekStart = plannerActiveWeekStartKey();
  state.plannerReviewDraftStore = normalizePlannerReviewDraftWeekStore(state.plannerReviewDraftStore || {});
  state.plannerReviewDraftStore.weeks[weekStart] = normalizePlannerReviewDraft(state.plannerReviewDraft);
  state.plannerReviewDraftStore.active_week_start = weekStart;
  state.plannerReviewDraftStore.updated_at = new Date().toISOString();
  saveLocalJson(PLANNER_REVIEW_DRAFT_KEY, state.plannerReviewDraftStore);
}

function selectedPlannerRecipeIdsForHistory() {
  const ids = new Set();
  Object.values(state.plannerDraft?.slot_overrides || {}).forEach((override) => {
    if (override?.selected_recipe_id) ids.add(String(override.selected_recipe_id));
  });
  Object.entries(normalizePlannerOptionsCache(state.plannerOptionsCache).day_options || {}).forEach(([dayName]) => {
    const selectedOption = plannerSelectedOptionForDay(dayName);
    Object.values(selectedOption?.recipe_ids_by_slot || {}).forEach((recipeId) => {
      if (recipeId) ids.add(String(recipeId));
    });
  });
  plannerShoppingHorizonSlotRecords(state.plannerOptionsCache, plannerActiveWeekStartKey()).forEach((slot) => {
    if (slot.recipe_id) ids.add(String(slot.recipe_id));
  });
  return [...ids].sort();
}

function plannerSelectedRecipeIdForSlot(slotId, option = null) {
  const manualId = state.plannerDraft?.slot_overrides?.[slotId]?.selected_recipe_id || "";
  if (manualId) return String(manualId);
  return option?.recipe_ids_by_slot?.[slotId] ? String(option.recipe_ids_by_slot[slotId]) : "";
}

function plannerWeekCompletionFromCache(cache = normalizePlannerOptionsCache(state.plannerOptionsCache)) {
  const dayResults = Object.values(cache.day_options || {});
  if (!dayResults.length) return "draft";
  if (cache.status === "blocked_no_usable_recipes" || cache.status === "gaps") return "gap";
  if (dayResults.some((result) => ["gap", "blocked_no_usable_recipes"].includes(result?.status))) return "gap";
  if (dayResults.some((result) => result?.status === "partial" || Number(result?.skipped_slot_count || 0) > 0)) return "partial";
  return "reviewed";
}

function plannerBuildLockedWeekRecord(optionsState = plannerOptionsState()) {
  const cache = normalizePlannerOptionsCache(optionsState.cache || state.plannerOptionsCache);
  const weekStart = plannerActiveWeekStartKey();
  const now = new Date().toISOString();
  const dayRecords = [];
  const slotRecords = [];
  const selectedIds = new Set();
  (currentPlannerTemplate()?.days || []).forEach((day) => {
    const planningDay = plannerPlanningDay(day);
    const result = cache.day_options?.[day.day] || null;
    const option = plannerSelectedOptionForDay(day.day);
    const daySlotRecords = (planningDay.slots || [])
      .filter((slot) => slot.slot_type === "meal")
      .map((slot) => {
        const slotState = plannerSlotState(slot);
        const recipeId = plannerSelectedRecipeIdForSlot(slot.slot_id, option);
        if (recipeId) selectedIds.add(recipeId);
        return {
          slot_id: slot.slot_id,
          day: day.day || "",
          date: plannerDayDateKey(day),
          time: slot.time || "",
          title: slot.title || slot.role || slot.slot_id,
          meal_category: slotState.meal_category || slot.meal_category || "",
          slot_status: slotState.slot_status || "planner_recipe",
          required: Boolean(slotState.required),
          people: Array.isArray(slotState.people) ? slotState.people : [],
          recipe_id: recipeId,
        };
      });
    slotRecords.push(...daySlotRecords);
    dayRecords.push({
      day: day.day || "",
      short_day: day.short_day || day.day || "",
      date: plannerDayDateKey(day),
      status: result?.status || "not_built",
      status_label: result?.status_label || "Not built",
      selected_option_id: option?.option_id || "",
      selected_recipe_ids: [...new Set(daySlotRecords.map((slot) => slot.recipe_id).filter(Boolean))],
      external_slots: daySlotRecords.filter((slot) => slot.slot_status === "external_meal").map((slot) => slot.slot_id),
      skipped_slots: daySlotRecords.filter((slot) => slot.slot_status === "skipped").map((slot) => slot.slot_id),
      gap_slots: (result?.slot_candidates || []).filter((slot) => Number(slot.candidate_count || 0) === 0).map((slot) => slot.slot_id),
      warnings: Array.isArray(result?.warnings) ? result.warnings : [],
    });
  });
  plannerShoppingHorizonSlotRecords(cache, weekStart).forEach((slot) => {
    slotRecords.push(slot);
    if (slot.recipe_id) selectedIds.add(String(slot.recipe_id));
  });
  return {
    week_start: weekStart,
    week_end: plannerDateKey(plannerActiveWeekEndDate()),
    status: plannerWeekCompletionFromCache(cache),
    template_id: state.plannerDraft?.template_id || "",
    fingerprint: cache.fingerprint || "",
    updated_at: now,
    built_at: cache.built_at || "",
    locked_at: now,
    total_stored_options: Number(cache.total_stored_options || 0),
    week_efficiency: cache.week_efficiency || plannerWeekEfficiencySummary(cache.day_options, currentPlannerTemplate()),
    selected_recipe_ids: [...selectedIds].sort(),
    day_records: dayRecords,
    slot_records: slotRecords,
  };
}

function applyPlannerLockedWeekUsage(record) {
  state.plannerRecipeUsageDraft = normalizePlannerRecipeUsageDraft(state.plannerRecipeUsageDraft);
  const usedAt = record.week_end || record.week_start || plannerActiveWeekStartKey();
  (record.selected_recipe_ids || []).forEach((recipeId) => {
    state.plannerRecipeUsageDraft.last_used_by_recipe_id[recipeId] = usedAt;
    state.plannerRecipeUsageDraft.last_used_week_by_recipe_id[recipeId] = record.week_start;
  });
  state.plannerRecipeUsageDraft.updated_at = new Date().toISOString();
  saveLocalJson(PLANNER_RECIPE_USAGE_DRAFT_KEY, state.plannerRecipeUsageDraft);
}

function lockReviewedPlannerWeek() {
  if (!plannerCanEditActiveWeek()) return;
  const optionsState = plannerOptionsState();
  if (!optionsState.has_current_cache || optionsState.stale) return;
  if (plannerWeekLockBlockers(optionsState).length) return;
  const record = plannerBuildLockedWeekRecord(optionsState);
  state.plannerWeekHistory = normalizePlannerWeekHistory(state.plannerWeekHistory);
  state.plannerWeekHistory.weeks[record.week_start] = record;
  state.plannerWeekHistory.updated_at = new Date().toISOString();
  applyPlannerLockedWeekUsage(record);
  saveLocalJson(PLANNER_WEEK_HISTORY_KEY, state.plannerWeekHistory);
  refreshPlannerWeekPackFitReceipt(record.week_start, "planner_locked");
  renderPlanner();
}

function resetPlannerWeekHistoryDraftRecord(weekStart, templateId = "", updatedAt = new Date().toISOString()) {
  const startDate = plannerDateFromKey(weekStart);
  state.plannerWeekHistory = normalizePlannerWeekHistory(state.plannerWeekHistory);
  state.plannerWeekHistory.weeks[weekStart] = {
    week_start: weekStart,
    week_end: plannerDateKey(plannerAddDays(startDate || plannerActiveWeekStartDate(), 6)),
    status: "draft",
    template_id: templateId || state.plannerDraft?.template_id || "",
    fingerprint: "",
    updated_at: updatedAt,
    built_at: "",
    locked_at: "",
    total_stored_options: 0,
    selected_recipe_ids: [],
    day_records: [],
    slot_records: [],
  };
  state.plannerWeekHistory.updated_at = updatedAt;
  saveLocalJson(PLANNER_WEEK_HISTORY_KEY, state.plannerWeekHistory);
}

function recordPlannerWeekHistory(status = "draft") {
  const weekStart = plannerActiveWeekStartKey();
  const cache = normalizePlannerOptionsCache(state.plannerOptionsCache);
  state.plannerWeekHistory = normalizePlannerWeekHistory(state.plannerWeekHistory);
  const existing = state.plannerWeekHistory.weeks[weekStart] || {};
  state.plannerWeekHistory.weeks[weekStart] = {
    ...existing,
    week_start: weekStart,
    week_end: plannerDateKey(plannerAddDays(plannerDateFromKey(weekStart), 6)),
    status,
    template_id: state.plannerDraft?.template_id || "",
    fingerprint: cache.fingerprint || existing.fingerprint || "",
    updated_at: new Date().toISOString(),
    built_at: cache.built_at || "",
    locked_at: ["reviewed", "partial", "gap"].includes(status) ? existing.locked_at || "" : "",
    total_stored_options: Number(cache.total_stored_options || 0),
    selected_recipe_ids: selectedPlannerRecipeIdsForHistory(),
  };
  state.plannerWeekHistory.updated_at = new Date().toISOString();
  saveLocalJson(PLANNER_WEEK_HISTORY_KEY, state.plannerWeekHistory);
}

function plannerClearTransientWeekMessages() {
  state.plannerLowWasteNotice = "";
  state.plannerBuildProgress = null;
  state.plannerGapPacketNotice = "";
  state.plannerGapPacketFallbackOpen = false;
}

function changePlannerActiveWeek(deltaWeeks) {
  savePlannerDraftStore();
  savePlannerOptionsCacheStore();
  savePlannerReviewDraftStore();
  const current = plannerActiveWeekStartDate();
  state.plannerActiveWeekStart = plannerDateKey(plannerAddDays(current, Number(deltaWeeks || 0) * 7));
  plannerClearTransientWeekMessages();
  syncActivePlannerWeekState();
  state.selectedPlannerSlotId = "";
  state.plannerRecipePickerSlotId = "";
  state.plannerResetConfirmOpen = false;
  state.plannerMacroModalDay = "";
  saveLocalJson(PLANNER_ACTIVE_WEEK_KEY, state.plannerActiveWeekStart);
  syncWeekPackFitReceiptForWeek(state.plannerActiveWeekStart);
  renderPlanner();
}

function jumpPlannerToCurrentWeek() {
  savePlannerDraftStore();
  savePlannerOptionsCacheStore();
  savePlannerReviewDraftStore();
  state.plannerActiveWeekStart = plannerCurrentWeekStartKey();
  plannerClearTransientWeekMessages();
  syncActivePlannerWeekState();
  state.selectedPlannerSlotId = "";
  state.plannerRecipePickerSlotId = "";
  state.plannerResetConfirmOpen = false;
  state.plannerMacroModalDay = "";
  saveLocalJson(PLANNER_ACTIVE_WEEK_KEY, state.plannerActiveWeekStart);
  syncWeekPackFitReceiptForWeek(state.plannerActiveWeekStart);
  renderPlanner();
}

function jumpPlannerToWeek(weekStart) {
  const nextWeek = plannerNormalizeWeekStartKey(weekStart);
  if (!nextWeek) return;
  savePlannerDraftStore();
  savePlannerOptionsCacheStore();
  savePlannerReviewDraftStore();
  state.plannerActiveWeekStart = nextWeek;
  plannerClearTransientWeekMessages();
  syncActivePlannerWeekState();
  state.selectedPlannerSlotId = "";
  state.plannerRecipePickerSlotId = "";
  state.plannerResetConfirmOpen = false;
  state.plannerMacroModalDay = "";
  saveLocalJson(PLANNER_ACTIVE_WEEK_KEY, state.plannerActiveWeekStart);
  syncWeekPackFitReceiptForWeek(state.plannerActiveWeekStart);
  renderPlanner();
}

function currentPlannerOptionsFingerprint() {
  const template = currentPlannerTemplate();
  if (!template) return "";
  const usableRecipeKeys = plannerUsableRecipes()
    .map((recipe) => [
      recipeKey(recipe),
      recipe.status,
      recipe.review_status,
      recipe.algorithmic_planning_allowed,
      recipe.planner_ready_status,
      recipe.meal_type,
      recipe.meal_category,
      recipe.meal_slot,
      recipe.batch_count,
      recipe.batch_size,
      recipe.cuisine,
      JSON.stringify(recipe.people || []),
      JSON.stringify(recipe.planner_filters || []),
      JSON.stringify(recipe.macro_bands || []),
      JSON.stringify(recipe.person_totals || recipe.nutrition_and_cost || []),
      JSON.stringify(recipe.timing || {}),
    ].join(":"))
    .sort();
  return hashString(JSON.stringify({
    template_id: template.template_id,
    active_week_start: plannerActiveWeekStartKey(),
    today: plannerTodayKey(),
    slot_overrides: plannerOptionsFingerprintSlotOverrides(template),
    goal_draft: state.profileGoalDraft || {},
      calculator_version: "efficient_week_builder_v4_ingredient_targets_fatigue_gaps_budget_prep_bands",
      policy: plannerOptionsPolicy(),
      usable_recipe_keys: usableRecipeKeys,
      locked: state.plannerReviewDraft?.locked_slots || {},
      blocked: state.plannerReviewDraft?.blocked_recipes_by_slot || {},
      cooldown: plannerCooldownFingerprintForActiveWeek(),
      draft_history: plannerDraftHistoryFingerprintForActiveWeek(),
      inventory: plannerInventoryFingerprint(),
    }));
}

function plannerOptionsFingerprintSlotOverrides(template = currentPlannerTemplate()) {
  const slots = new Map(allPlannerSlots(template).map((slot) => [slot.slot_id, slot]));
  return Object.fromEntries(
    Object.entries(state.plannerDraft?.slot_overrides || {})
      .map(([slotId, override]) => {
        const slot = slots.get(slotId);
        const shapeOverride = {
          ...(override || {}),
          selected_recipe_id: "",
        };
        if (!slot || plannerOverrideMatchesSlotDefault(slot, shapeOverride)) return null;
        delete shapeOverride.selected_recipe_id;
        return [slotId, shapeOverride];
      })
      .filter(Boolean)
      .sort(([left], [right]) => left.localeCompare(right))
  );
}

function plannerOptionsState() {
  state.plannerOptionsCache = normalizePlannerOptionsCache(state.plannerOptionsCache);
  let cache = state.plannerOptionsCache;
  const currentFingerprint = currentPlannerOptionsFingerprint();
  if (cache.stale && cache.fingerprint && currentFingerprint && cache.fingerprint === currentFingerprint) {
    cache = {
      ...cache,
      stale: false,
    };
    state.plannerOptionsCache = cache;
    savePlannerOptionsCacheStore();
  }
  const stale = Boolean(cache.fingerprint && currentFingerprint && cache.fingerprint !== currentFingerprint);
  const hasCache = Boolean(cache.fingerprint);
  if (!hasCache) {
    return {
      value: "Draft",
      label: "Not built",
      note: "Press Create week",
      has_cache: false,
      has_current_cache: false,
      stale: false,
      cache,
    };
  }
  if (stale || cache.stale) {
    return {
      value: "Needs refresh",
      label: "Needs refresh",
      note: "Run Create week again",
      has_cache: true,
      has_current_cache: false,
      stale: true,
      cache,
    };
  }
  if (cache.status === "blocked_no_usable_recipes") {
    return {
      value: "Blocked",
      label: "Blocked",
      note: "No usable recipes",
      has_cache: true,
      has_current_cache: true,
      stale: false,
      cache,
    };
  }
  if (cache.status === "options_built") {
    return {
      value: "Built",
      label: "Matches found",
      note: `${cache.total_stored_options} day versions kept`,
      has_cache: true,
      has_current_cache: true,
      stale: false,
      cache,
    };
  }
  return {
    value: "Gaps",
    label: "Gaps",
    note: "Some days cannot fill",
    has_cache: true,
    has_current_cache: true,
    stale: false,
    cache,
  };
}

function invalidatePlannerOptionsCache() {
  if (!state.plannerOptionsCache?.fingerprint) return;
  state.plannerOptionsCache = {
    ...normalizePlannerOptionsCache(state.plannerOptionsCache),
    stale: true,
  };
  savePlannerOptionsCacheStore();
}

function buildPlannerOptions() {
  if (!plannerCanEditActiveWeek()) return;
  state.plannerDraft = normalizePlannerDraft(state.plannerDraft, currentPlannerTemplate());
  state.plannerReviewDraft = normalizePlannerReviewDraft(state.plannerReviewDraft);
  state.plannerRecipeUsageDraft = normalizePlannerRecipeUsageDraft(state.plannerRecipeUsageDraft);
  plannerSyncAssumedReceiptUseUpItems(plannerActiveWeekStartKey());
  state.plannerLowWasteNotice = "";
  plannerApplyBuiltOptionsCache(calculatePlannerWeekOptions(), "built", "planner_built");
  renderPlanner();
}

function plannerApplyBuiltOptionsCache(cache, historyStatus = "built", packFitReason = "planner_built") {
  state.plannerOptionsCache = normalizePlannerOptionsCache(cache);
  for (const [dayName, dayResult] of Object.entries(state.plannerOptionsCache.day_options || {})) {
    if (dayResult.selected_option_id) state.plannerReviewDraft.selected_option_by_day[dayName] = dayResult.selected_option_id;
  }
  state.plannerReviewDraft.updated_at = new Date().toISOString();
  savePlannerOptionsCacheStore();
  savePlannerReviewDraftStore();
  saveLocalJson(PLANNER_RECIPE_USAGE_DRAFT_KEY, state.plannerRecipeUsageDraft);
  recordPlannerWeekHistory(historyStatus);
  refreshPlannerWeekPackFitReceipt(plannerActiveWeekStartKey(), packFitReason);
}

async function buildPlannerLowWasteWeek() {
  if (!plannerCanEditActiveWeek()) return;
  if (plannerBuildInProgress()) return;
  const totalSteps = 23;
  plannerShowImmediateBuildProgress(totalSteps);
  await plannerWaitForPaint();
  try {
    state.plannerDraft = normalizePlannerDraft(state.plannerDraft, currentPlannerTemplate());
    state.plannerReviewDraft = normalizePlannerReviewDraft(state.plannerReviewDraft);
    state.plannerRecipeUsageDraft = normalizePlannerRecipeUsageDraft(state.plannerRecipeUsageDraft);
    const weekStart = plannerActiveWeekStartKey();
    state.plannerLowWasteNotice = "";

    await plannerSetBuildProgress({
      step: 1,
      total_steps: totalSteps,
      title: "Preparing the week",
      detail: "Reading the current template, saved preferences, recipe rules, and fresh use-up list.",
      note: "This stays local. No shopping export or calendar write is created.",
    });

    await plannerSetBuildProgress({
      step: 2,
      total_steps: totalSteps,
      title: "Clearing old carryover",
      detail: "Removing any generated Monday-to-Wednesday leftover stock from the previous draft before rebuilding.",
    });
    plannerClearSplitWeekPart1Inventory(weekStart);

    await plannerSetBuildProgress({
      step: 3,
      total_steps: totalSteps,
      title: "Checking receipt leftovers",
      detail: "Adding previous-plan leftovers as assumed stock for this draft. They must be checked before lock or final shopping.",
    });
    const receiptBuildState = plannerSyncAssumedReceiptUseUpItems(weekStart);
    const importedReceiptCount = receiptBuildState.trusted_count;
    const assumedReceiptCount = receiptBuildState.assumed_count;

    const firstPassResult = await calculatePlannerWeekOptionsWithProgress({
      phaseLabel: "First pass",
      phaseDetail: "Building a complete week before creating Monday-to-Wednesday carryover stock.",
      startStep: 4,
      totalSteps,
    });
    const firstPassCache = firstPassResult.cache;

    await plannerSetBuildProgress({
      step: 12,
      total_steps: totalSteps,
      title: "Creating part-1 leftovers",
      detail: "Checking Monday-to-Wednesday packs and turning real spare fresh food into Thursday-to-Sunday use-up stock.",
    });
    const splitUseUp = plannerBuildSplitWeekUseUpInventory(firstPassCache, weekStart);

    await plannerSetBuildProgress({
      step: 13,
      total_steps: totalSteps,
      title: "Saving carryover stock",
      detail: `${number(splitUseUp.inventory_items.length)} part-1 leftover item${splitUseUp.inventory_items.length === 1 ? "" : "s"} can be offered to the second half of the week.`,
    });
    if (splitUseUp.inventory_items.length) {
      const retainedItems = plannerInventoryItems(weekStart).filter((item) => item.source_type !== "split_week_part_1");
      setPlannerInventoryWeekItems(weekStart, [...retainedItems, ...splitUseUp.inventory_items]);
    }

    const finalResult = await calculatePlannerWeekOptionsWithProgress({
      phaseLabel: "Second pass",
      phaseDetail: "Rebuilding the week with part-1 leftovers available for Thursday through Sunday.",
      startStep: 14,
      totalSteps,
    });
    const finalCache = finalResult.cache;

    await plannerSetBuildProgress({
      step: 22,
      total_steps: totalSteps,
      title: "Saving the draft week",
      detail: "Saving selected recipes, low-waste proof markers, and the local pack-fit receipt.",
    });
    const finalIngredientTargets = plannerIngredientTargetsForWeek(weekStart).targets || [];
    const finalReadiness = plannerActiveWeekReadinessSummary(finalCache);
    finalCache.low_waste_build = {
      schema_version: "v4.live_low_waste_week_build.1",
      built_at: new Date().toISOString(),
      week_start: weekStart,
      rule: "part_1_monday_to_wednesday_part_2_thursday_to_sunday_sunday_always_part_2",
      imported_receipt_use_up_count: importedReceiptCount,
      assumed_receipt_use_up_count: assumedReceiptCount,
      assumed_receipt_use_up_added_count: receiptBuildState.assumed_added_count || 0,
      stock_count_reviewed: receiptBuildState.reviewed,
      unchecked_receipt_recommendation_count: receiptBuildState.pending_unchecked_count,
      part_1_use_up_created_count: splitUseUp.created_count,
      part_1_use_up_available_count: splitUseUp.inventory_items.length,
      part_1_receipt_status: splitUseUp.receipt_status,
      part_1_receipt_blocker_count: splitUseUp.blocker_count,
      ingredient_target_count: finalIngredientTargets.length,
      ingredient_target_score: Number(finalCache.week_efficiency?.ingredient_target_score || 0),
      week_readiness: finalReadiness,
      local_only: true,
    };
    plannerApplyBuiltOptionsCache(finalCache, "built", "low_waste_built");
    const filledSlots = finalReadiness.selected_recipe_slot_count;
    state.plannerLowWasteNotice = `${number(filledSlots)} recipe slots filled; ${number(importedReceiptCount)} counted receipt leftovers used; ${number(assumedReceiptCount)} assumed leftovers available for draft planning; ${number(splitUseUp.inventory_items.length)} part-1 leftovers carried into part 2.`;
    const completionDetail = finalReadiness.is_complete
      ? state.plannerLowWasteNotice
      : `${state.plannerLowWasteNotice} ${plannerWeekReadinessDetail(finalReadiness)}.`;
    plannerFinishBuildProgress({
      step: 23,
      total_steps: totalSteps,
      title: finalReadiness.is_complete ? "Week created" : "Partial week created",
      detail: completionDetail,
      note: finalReadiness.is_complete
        ? "Review the draft before locking. No live shopping export or calendar write was made."
        : "Do not lock or shop yet. Fix the missing required meals first.",
    });
  } catch (error) {
    console.error("Create week failed", error);
    plannerFailBuildProgress(error);
  }
}

function plannerBuildSplitWeekUseUpInventory(cache, weekStart) {
  const selectedSlots = plannerSelectedSlotRecordsForCache(cache, weekStart)
    .filter((slot) => slot.recipe_id && plannerSplitWeekUseUpWindowForSlot(slot) === "part_1");
  const selectedRecipeIds = [...new Set(selectedSlots.map((slot) => slot.recipe_id).filter(Boolean))];
  const usageRows = shoppingRecipeUsageRows(selectedSlots, selectedRecipeIds);
  const demandSlots = weekPackFitDemandSlotsForUsageRows(weekStart, usageRows)
    .filter((slot) => plannerSplitWeekUseUpWindowForSlot(slot) === "part_1");
  if (!demandSlots.length) {
    return {
      receipt_status: "not_needed",
      blocker_count: 0,
      created_count: 0,
      inventory_items: [],
    };
  }
  const part2Start = plannerDateKey(plannerAddDays(plannerDateFromKey(weekStart), 4));
  const weekId = `planner-pack-fit-${weekStart}-part-1`;
  const part1Week = {
    schema_version: "v4.live_planner_pack_fit_input.1",
    week_id: weekId,
    week_start: weekStart,
    week_end: plannerDateKey(plannerAddDays(plannerDateFromKey(weekStart), 3)),
    source_calendar_id: "v4_app_planner_split_week_part_1",
    local_only: true,
    split_week_window: "part_1",
    slots: demandSlots,
  };
  const receipt = buildAppWeekPackFitReceipt(part1Week, state.recipeIndex);
  const created = Array.isArray(receipt.use_up_stock_created) ? receipt.use_up_stock_created : [];
  const inventoryItems = created
    .map((item) => plannerInventoryItemFromSplitWeekPart1(item, weekId, part2Start))
    .filter(Boolean);
  return {
    receipt_status: receipt.status || "",
    blocker_count: Array.isArray(receipt.blockers) ? receipt.blockers.length : 0,
    created_count: created.length,
    inventory_items: inventoryItems,
  };
}

function plannerClearSplitWeekPart1Inventory(weekStart) {
  const currentItems = plannerInventoryItems(weekStart);
  const retainedItems = currentItems.filter((item) => item.source_type !== "split_week_part_1");
  if (retainedItems.length !== currentItems.length) setPlannerInventoryWeekItems(weekStart, retainedItems);
}

function plannerInventoryItemFromSplitWeekPart1(item, sourceWeekId, part2Start) {
  const useByDate = plannerNormalizeDateKey(item.use_by_date);
  if (useByDate && part2Start && useByDate < part2Start) return null;
  const now = new Date().toISOString();
  const availableFrom = plannerMaxDateKey(plannerNormalizeDateKey(item.available_from_date), part2Start);
  return plannerNormalizeInventoryItem({
    inventory_id: item.inventory_id || `${sourceWeekId}-${item.family_id || item.item_name || "use-up"}`,
    item_name: item.item_name,
    family_id: item.family_id,
    sku_code: item.sku_code,
    amount: item.amount,
    unit: item.unit,
    storage_class: item.storage_class,
    available_from_date: availableFrom,
    available_from_at: availableFrom ? `${availableFrom}T00:00:00` : "",
    opened_on_date: item.opened_on_date,
    use_by_date: useByDate || plannerDateKey(plannerActiveWeekEndDate()),
    shelf_life_days: item.shelf_life_days,
    shelf_life_basis: item.shelf_life_basis,
    location: item.location,
    status: "available",
    priority: item.priority,
    source_type: "split_week_part_1",
    source_receipt_week_id: sourceWeekId,
    source_inventory_id: item.inventory_id,
    source_receipt_use_up_id: `${sourceWeekId}::${item.inventory_id || item.family_id || item.item_name || "use-up"}`,
    imported_at: now,
    created_at: now,
    updated_at: now,
  });
}

function plannerMaxDateKey(left, right) {
  const dates = [plannerNormalizeDateKey(left), plannerNormalizeDateKey(right)].filter(Boolean);
  return dates.length ? dates.sort().at(-1) : "";
}

function plannerSelectedOptionReviewDraftForCache(cache) {
  const review = normalizePlannerReviewDraft(state.plannerReviewDraft);
  review.selected_option_by_day = {
    ...(review.selected_option_by_day || {}),
  };
  Object.entries(cache?.day_options || {}).forEach(([dayName, dayResult]) => {
    if (dayResult?.selected_option_id) review.selected_option_by_day[dayName] = dayResult.selected_option_id;
  });
  return review;
}

function plannerSelectedSlotRecordsForCache(cache, weekStart) {
  return shoppingSlotRecordsFromPlannerStores(
    currentPlannerTemplate(),
    state.plannerDraft,
    cache,
    plannerSelectedOptionReviewDraftForCache(cache),
    plannerNormalizeWeekStartKey(weekStart)
  );
}

async function calculatePlannerWeekOptionsWithProgress({ phaseLabel = "Build", phaseDetail = "", startStep = 1, totalSteps = 1 } = {}) {
  const template = currentPlannerTemplate();
  const policy = plannerOptionsPolicy();
  const usable = plannerUsableRecipes();
  const dayOptions = {};
  const warnings = [];
  let totalStored = 0;
  let totalRaw = 0;
  let step = Number(startStep || 1);
  const days = template?.days || [];
  for (const day of days) {
    const planningDay = plannerPlanningDay(day);
    await plannerSetBuildProgress({
      step,
      total_steps: totalSteps,
      title: `${phaseLabel}: ${day.day || "day"}`,
      detail: phaseDetail || "Checking recipe combinations for this day.",
    });
    const result = plannerDayFrozen(day)
      ? {
          status: "frozen_past",
          status_label: "Frozen history",
          frozen: true,
          raw_combination_count: 0,
          raw_option_count: 0,
          stored_option_count: 0,
          slot_candidates: [],
          options: [],
          warnings: [],
        }
      : calculatePlannerDayOptions(planningDay, usable, policy);
    dayOptions[day.day] = result;
    totalStored += result.stored_option_count;
    totalRaw += result.raw_combination_count;
    warnings.push(...(result.warnings || []));
    step += 1;
  }
  await plannerSetBuildProgress({
    step,
    total_steps: totalSteps,
    title: `${phaseLabel}: weekly handoff`,
    detail: "Checking batch continuity, breakfast/dinner repeat limits, and the Monday-to-Saturday route.",
  });
  const weeklySequenceResult = plannerApplyBatchContinuityToWeekOptions(dayOptions, template);
  warnings.push(...weeklySequenceResult.warnings);
  totalStored = Object.values(dayOptions).reduce((sum, result) => sum + Number(result?.stored_option_count || 0), 0);
  const weekEfficiency = plannerWeekEfficiencySummary(dayOptions, template);
  const weekScore = plannerWeekScoreSummaryForSelectedOptions(plannerWeekSelectedOptions(dayOptions), { metrics: weekEfficiency });
  const weekScoreAlternatives = plannerWeekScoreAlternativesFromSequence(weeklySequenceResult.sequence_result, weekScore);
  weekEfficiency.week_score_alternative_count = weekScoreAlternatives.length;
  const shoppingHorizon = plannerBuildFollowingSundayBreakfastHorizon(plannerActiveWeekStartKey(), template, usable, policy);
  const blockedByUsable = usable.length === 0;
  const status = blockedByUsable ? "blocked_no_usable_recipes" : totalStored > 0 ? "options_built" : "gaps";
  return {
    cache: {
      schema_version: "v4.planner_options_cache.1",
      draft_only: true,
      status,
      status_label: blockedByUsable ? "Blocked: no usable recipes" : totalStored > 0 ? "Matches found" : "Gaps need recipes",
      built_at: new Date().toISOString(),
      active_week_start: plannerActiveWeekStartKey(),
      week_start: plannerActiveWeekStartKey(),
      week_end: plannerDateKey(plannerActiveWeekEndDate()),
      template_id: template?.template_id || "",
      policy_id: policy.policy_id || "",
      fingerprint: currentPlannerOptionsFingerprint(),
      stale: false,
      usable_recipe_count: usable.length,
      review_only_recipe_count: recipes().filter((recipe) => recipe.status === "needs_review").length,
      total_stored_options: totalStored,
      total_raw_combinations: totalRaw,
      week_efficiency: weekEfficiency,
      week_score: weekScore,
      week_score_alternatives: weekScoreAlternatives,
      day_options: dayOptions,
      shopping_horizon: shoppingHorizon,
      warnings: [...new Set(warnings)],
    },
    next_step: step + 1,
  };
}

function calculatePlannerWeekOptions() {
  const template = currentPlannerTemplate();
  const policy = plannerOptionsPolicy();
  const usable = plannerUsableRecipes();
  const dayOptions = {};
  const warnings = [];
  let totalStored = 0;
  let totalRaw = 0;
  (template?.days || []).forEach((day) => {
    const planningDay = plannerPlanningDay(day);
    const result = plannerDayFrozen(day)
      ? {
          status: "frozen_past",
          status_label: "Frozen history",
          frozen: true,
          raw_combination_count: 0,
          raw_option_count: 0,
          stored_option_count: 0,
          slot_candidates: [],
          options: [],
          warnings: [],
        }
      : calculatePlannerDayOptions(planningDay, usable, policy);
    dayOptions[day.day] = result;
    totalStored += result.stored_option_count;
    totalRaw += result.raw_combination_count;
    warnings.push(...(result.warnings || []));
  });
  const weeklySequenceResult = plannerApplyBatchContinuityToWeekOptions(dayOptions, template);
  warnings.push(...weeklySequenceResult.warnings);
  totalStored = Object.values(dayOptions).reduce((sum, result) => sum + Number(result?.stored_option_count || 0), 0);
  const weekEfficiency = plannerWeekEfficiencySummary(dayOptions, template);
  const weekScore = plannerWeekScoreSummaryForSelectedOptions(plannerWeekSelectedOptions(dayOptions), { metrics: weekEfficiency });
  const weekScoreAlternatives = plannerWeekScoreAlternativesFromSequence(weeklySequenceResult.sequence_result, weekScore);
  weekEfficiency.week_score_alternative_count = weekScoreAlternatives.length;
  const shoppingHorizon = plannerBuildFollowingSundayBreakfastHorizon(plannerActiveWeekStartKey(), template, usable, policy);
  const blockedByUsable = usable.length === 0;
  const status = blockedByUsable ? "blocked_no_usable_recipes" : totalStored > 0 ? "options_built" : "gaps";
  return {
    schema_version: "v4.planner_options_cache.1",
    draft_only: true,
    status,
    status_label: blockedByUsable ? "Blocked: no usable recipes" : totalStored > 0 ? "Matches found" : "Gaps need recipes",
    built_at: new Date().toISOString(),
    active_week_start: plannerActiveWeekStartKey(),
    week_start: plannerActiveWeekStartKey(),
    week_end: plannerDateKey(plannerActiveWeekEndDate()),
    template_id: template?.template_id || "",
    policy_id: policy.policy_id || "",
    fingerprint: currentPlannerOptionsFingerprint(),
    stale: false,
    usable_recipe_count: usable.length,
    review_only_recipe_count: recipes().filter((recipe) => recipe.status === "needs_review").length,
    total_stored_options: totalStored,
    total_raw_combinations: totalRaw,
    week_efficiency: weekEfficiency,
    week_score: weekScore,
    week_score_alternatives: weekScoreAlternatives,
    day_options: dayOptions,
    shopping_horizon: shoppingHorizon,
    warnings: [...new Set(warnings)],
  };
}

function plannerWeekEfficiencySummary(dayOptions, template) {
  const days = template?.days || [];
  const selectedOptions = plannerWeekSelectedOptions(dayOptions);
  const assumedUseSummary = plannerAssumedInventoryUseSummaryForSelectedOptions(selectedOptions, plannerActiveWeekStartKey());
  const statuses = Object.values(dayOptions || {});
  const budgetBounds = plannerWeekBudgetBounds(dayOptions);
  const workloadBounds = plannerWeekWorkloadBounds(dayOptions);
  const packCleanWaste = plannerPackCleanWasteSummary(selectedOptions);
  const carryForwardWaste = plannerCarryForwardWasteAvoidanceMetrics(selectedOptions, plannerActiveWeekStartKey());
  const recipeUseCounts = {};
  selectedOptions.forEach(({ option }) => {
    Object.entries(plannerOptionRecipeUseCounts(option)).forEach(([recipeId, useCount]) => {
      recipeUseCounts[recipeId] = Number(recipeUseCounts[recipeId] || 0) + Number(useCount || 0);
    });
  });
  const slotMetrics = plannerRequiredRecipeSlotMetricsFromDayOptions(dayOptions, template);
  const base = {
    full_ready_days: statuses.filter((result) => ["valid", "reserved_external"].includes(result?.status)).length,
    partial_days: statuses.filter((result) => result?.status === "partial").length,
    gap_days: Math.max(
      statuses.filter((result) => ["gap", "blocked_no_usable_recipes"].includes(result?.status)).length,
      Number(slotMetrics.missing_required_recipe_day_count || 0)
    ),
    selected_day_count: selectedOptions.length,
    visible_day_count: days.length,
    ...slotMetrics,
    completed_batch_blocks: plannerCompletedBatchBlockCount(recipeUseCounts),
    repeat_fatigue_score: plannerWeeklyRepeatFatigueScore(recipeUseCounts),
    adjacent_dinner_protein_repeat_score: plannerAdjacentDinnerProteinRepeatScore(selectedOptions),
    inventory_use_up_score: plannerWeeklyInventoryUseUpScore(selectedOptions),
    assumed_stock_use_count: assumedUseSummary.item_count,
    ingredient_target_score: plannerWeeklyIngredientTargetScore(selectedOptions),
    carry_forward_waste_count: Number(carryForwardWaste.carry_forward_waste_count || 0),
    carry_forward_waste_gbp: roundMoney(carryForwardWaste.carry_forward_waste_gbp || 0),
    carry_forward_waste_score: Math.round(Number(carryForwardWaste.carry_forward_waste_score || 0) * 10) / 10,
    ...plannerCarryForwardObligationMetrics(selectedOptions, plannerActiveWeekStartKey(), dayOptions, days),
    ...plannerExpensiveBeefMinceWasteMetrics(selectedOptions),
    pack_clean_awkward_leftover_count: Number(packCleanWaste.awkward_leftover_count || 0),
    pack_clean_awkward_leftover_value_gbp: roundMoney(packCleanWaste.awkward_leftover_value_gbp || 0),
    pack_clean_waste_score: Math.round(Number(packCleanWaste.score || 0) * 10) / 10,
    shopping_efficiency_score: plannerShoppingEfficiencyScore(selectedOptions),
    workload_score: selectedOptions.reduce((sum, { option }) => sum + plannerOptionWorkloadScore(option), 0),
    cost_score: selectedOptions.reduce((sum, { option }) => sum + plannerOptionCostScore(option), 0),
    ...workloadBounds,
    ...budgetBounds,
  };
  const dinnerFatigueSummary = plannerDinnerFatigueSummaryForSelectedOptions(selectedOptions);
  const score = plannerWeekScoreSummaryForSelectedOptions(selectedOptions, { metrics: base });
  return {
    ...base,
    dinner_fatigue_penalty: Math.round(Number(dinnerFatigueSummary.penalty || 0) * 10) / 10,
    dinner_fatigue_hard_count: Number(dinnerFatigueSummary.hard_warning_count || 0),
    dinner_fatigue_warning_count: Number(dinnerFatigueSummary.warning_count || 0),
    previous_week_dinner_exact_repeat_count: Number(score.metrics?.previous_week_dinner_exact_repeat_count || 0),
    week_score: score.score,
    week_score_low_waste: Number(score.components.low_waste || 0),
    week_score_fatigue: Number(score.components.fatigue || 0),
    week_score_macro_fit: Number(score.components.macro_fit || 0),
    week_score_cook_time: Number(score.components.cook_time || 0),
    week_score_budget: Number(score.components.budget || 0),
    week_score_pack_batch: Number(score.components.pack_batch || 0),
  };
}

function plannerFindWeeklyOptionSequence(dayOptions, template) {
  const days = template?.days || [];
  const policy = plannerOptionsPolicy();
  const maxOptionsPerDay = Math.max(1, Number(policy.max_weekly_sequence_options_per_day || 120));
  const deadline = Date.now() + Math.max(3000, Number(policy.max_weekly_sequence_search_ms || 900));
  const initialStockState = plannerInitialSequentialStockState(plannerActiveWeekStartKey());
  const sequenceContext = {
    recipeById: new Map(recipes().map((recipe) => [recipeKey(recipe), recipe])),
    issueCache: new Map(),
    remainingCapacityCache: new Map(),
    batchCompletionCache: new Map(),
    batchCompletionLookaheadCache: new Map(),
    proteinFamilyCache: new Map(),
    fatigueProfileCache: new Map(),
    remainingExpensiveBeefPotentialCache: new Map(),
  };
  const best = {
    metrics: null,
    selected_option_by_day: {},
    leaderboard: [],
  };
  const memo = new Map();

  function keepBest(dayIndex, selectedByDay, score, activeBatches = [], weeklyUseCounts = {}) {
    if (plannerBlockingActiveBatches(activeBatches).length) return;
    const metrics = plannerWeeklySequenceMetrics({
      dayIndex,
      selectedByDay,
      optionScore: score,
      activeBatches,
      weeklyUseCounts,
      dayOptions,
      days,
      context: sequenceContext,
    });
    plannerAddWeeklyScoreCandidate(best.leaderboard, metrics, selectedByDay);
    if (plannerWeeklySequenceBeats(metrics, best.metrics)) {
      best.metrics = metrics;
      best.selected_option_by_day = { ...selectedByDay };
    }
  }

  function stateKey(dayIndex, activeBatches, weeklyUseCounts, sequentialStockState, previousDinnerProfiles = []) {
    const activeKey = (activeBatches || [])
      .map((batch) => `${batch.recipe_id}:${batch.remaining}:${batch.carryover_allowed ? "carry" : "strict"}`)
      .sort()
      .join("|");
    const useKey = Object.entries(weeklyUseCounts || {})
      .filter(([, count]) => Number(count || 0) > 0)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([recipeId, count]) => `${recipeId}:${count}`)
      .join("|");
    const dinnerKey = (previousDinnerProfiles || [])
      .map((profile) => [profile.primary_protein, profile.main_starch, profile.meal_format, profile.cuisine_or_sauce].filter(Boolean).join("+"))
      .join(">");
    return `${dayIndex}::${activeKey}::${useKey}::${plannerSequentialStockStateKey(sequentialStockState)}::${dinnerKey}`;
  }

  function walk(dayIndex, activeBatches, weeklyUseCounts, selectedByDay, score, sequentialStockState, previousDinnerProfiles = []) {
    if (Date.now() > deadline) {
      keepBest(dayIndex, selectedByDay, score, activeBatches, weeklyUseCounts);
      return false;
    }
    if (dayIndex >= days.length) {
      keepBest(dayIndex, selectedByDay, score, activeBatches, weeklyUseCounts);
      return plannerActiveBatchesResolved(activeBatches);
    }
    const key = stateKey(dayIndex, activeBatches, weeklyUseCounts, sequentialStockState, previousDinnerProfiles);
    if (memo.has(key) && memo.get(key) <= score) return false;
    memo.set(key, score);

    const day = days[dayIndex];
    const result = dayOptions[day.day];
    if (!result?.options?.length) {
      if (activeBatches.length && !plannerActiveBatchesResolved(activeBatches)) return false;
      return walk(dayIndex + 1, [], weeklyUseCounts, selectedByDay, score, sequentialStockState, []);
    }

    const options = plannerWeeklySequenceOptions(result.options, activeBatches, weeklyUseCounts, sequentialStockState, sequenceContext, previousDinnerProfiles)
      .slice(0, maxOptionsPerDay);
    let foundFullSequence = false;
    options.forEach((option) => {
      if (Date.now() > deadline) return;
      const issues = plannerWeeklyOptionIssues(option, dayIndex, days, dayOptions, activeBatches, new Set(), weeklyUseCounts, {}, sequenceContext);
      if (issues.length) return;
      const nextState = plannerAdvanceWeeklySequenceState(option, activeBatches, weeklyUseCounts, { dayIndex, days, dayOptions, recipeById: sequenceContext.recipeById });
      const nextStockState = plannerAdvanceSequentialStockState(option, sequentialStockState);
      const nextDinnerProfiles = plannerNextDinnerFatigueWindow(previousDinnerProfiles, option, sequenceContext.recipeById, sequenceContext);
      const optionScore = Number(option?.score || 0);
      const nextSelected = { ...selectedByDay, [day.day]: option.option_id };
      if (walk(dayIndex + 1, nextState.activeBatches, nextState.weeklyUseCounts, nextSelected, score + optionScore, nextStockState, nextDinnerProfiles)) {
        foundFullSequence = true;
      }
    });
    if (!foundFullSequence && !activeBatches.length) {
      walk(dayIndex + 1, [], weeklyUseCounts, selectedByDay, score + 10000, sequentialStockState, []);
    }
    if (!foundFullSequence) keepBest(dayIndex, selectedByDay, score, activeBatches, weeklyUseCounts);
    return foundFullSequence;
  }

  walk(0, [], {}, {}, 0, initialStockState, []);
  return {
    selected_option_by_day: best.selected_option_by_day,
    metrics: best.metrics,
    leaderboard: best.leaderboard,
  };
}

function plannerCarryoverActiveBatches(activeBatches = []) {
  return (activeBatches || []).filter((batch) => {
    const remaining = Number(batch?.remaining || 0);
    const plannedCarryover = Number(batch?.carryover_servings || 0);
    return Boolean(batch?.carryover_allowed) && remaining > 0 && plannedCarryover > 0 && remaining <= plannedCarryover && Number(batch?.missed || 0) <= 0;
  });
}

function plannerBlockingActiveBatches(activeBatches = []) {
  return (activeBatches || []).filter((batch) => !plannerCarryoverActiveBatches([batch]).length);
}

function plannerActiveBatchesResolved(activeBatches = []) {
  return plannerBlockingActiveBatches(activeBatches).length === 0;
}

const plannerOptionRecipeIdsWeakCache = new WeakMap();
const plannerOptionRecipeIdSetWeakCache = new WeakMap();
const plannerOptionRecipeUseCountsWeakCache = new WeakMap();

function plannerOptionRecipeIds(option) {
  if (!option || typeof option !== "object") return [];
  if (plannerOptionRecipeIdsWeakCache.has(option)) return plannerOptionRecipeIdsWeakCache.get(option);
  const ids = [...new Set(Object.values(option.recipe_ids_by_slot || {}).filter(Boolean))];
  plannerOptionRecipeIdsWeakCache.set(option, ids);
  return ids;
}

function plannerOptionRecipeIdSet(option) {
  if (!option || typeof option !== "object") return new Set();
  if (plannerOptionRecipeIdSetWeakCache.has(option)) return plannerOptionRecipeIdSetWeakCache.get(option);
  const idSet = new Set(plannerOptionRecipeIds(option));
  plannerOptionRecipeIdSetWeakCache.set(option, idSet);
  return idSet;
}

function plannerOptionRecipeUseCounts(option) {
  if (!option || typeof option !== "object") return {};
  if (plannerOptionRecipeUseCountsWeakCache.has(option)) return plannerOptionRecipeUseCountsWeakCache.get(option);
  const counts = Object.values(option.recipe_ids_by_slot || {}).filter(Boolean).reduce((acc, recipeId) => {
    acc[recipeId] = Number(acc[recipeId] || 0) + 1;
    return acc;
  }, {});
  plannerOptionRecipeUseCountsWeakCache.set(option, counts);
  return counts;
}

function plannerOptionRecipeUseCount(option, recipeId) {
  if (!recipeId) return 0;
  return Number(plannerOptionRecipeUseCounts(option)?.[recipeId] || 0);
}

function plannerRecipeById(recipeId, recipeById = null) {
  return recipeById?.get(recipeId) || recipes().find((item) => recipeKey(item) === recipeId) || null;
}

function plannerWeeklyStateSignature(activeBatches = [], weeklyUseCounts = {}, blockedBatchRecipeIds = null, settings = {}) {
  const activeKey = (activeBatches || [])
    .map((batch) => `${batch.recipe_id}:${Number(batch.remaining || 0)}:${Number(batch.missed || 0)}:${batch.carryover_allowed ? "carry" : "strict"}`)
    .sort()
    .join("|");
  const useKey = Object.entries(weeklyUseCounts || {})
    .filter(([, count]) => Number(count || 0) > 0)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([recipeId, count]) => `${recipeId}:${count}`)
    .join("|");
  const blockedKey = [...(blockedBatchRecipeIds || [])].sort().join("|");
  return `${activeKey}::${useKey}::${blockedKey}::${settings?.skipBatchStartLookahead ? "skip-lookahead" : "full"}`;
}

function plannerWeeklySequenceMetrics({ dayIndex, selectedByDay, optionScore, activeBatches, weeklyUseCounts, dayOptions, days, context = {} }) {
  const selectedOptions = plannerWeekSelectedOptions(dayOptions, selectedByDay);
  const fullReadyDays = selectedOptions.filter(({ option }) => option?.valid && !option?.partial).length;
  const partialDays = selectedOptions.filter(({ option }) => option?.partial).length;
  const selectedDayCount = selectedOptions.length;
  const slotMetrics = plannerRequiredRecipeSlotMetricsFromDayOptions(dayOptions, { days }, selectedByDay);
  const budgetBounds = plannerWeekBudgetBounds(dayOptions);
  const workloadBounds = plannerWeekWorkloadBounds(dayOptions);
  const gapDays = Math.max(0, (days || []).length - selectedDayCount, Number(slotMetrics.missing_required_recipe_day_count || 0));
  const recipeUseCounts = weeklyUseCounts || {};
  const repeatFatigueScore = plannerWeeklyRepeatFatigueScore(recipeUseCounts);
  const completedBatchBlocks = plannerCompletedBatchBlockCount(recipeUseCounts);
  const workloadScore = selectedOptions.reduce((sum, { option }) => sum + plannerOptionWorkloadScore(option, context.recipeById), 0);
  const costScore = selectedOptions.reduce((sum, { option }) => sum + plannerOptionCostScore(option), 0);
  const shoppingEfficiencyScore = plannerShoppingEfficiencyScore(selectedOptions);
  const expensiveBeefMinceWaste = plannerExpensiveBeefMinceWasteSummary(selectedOptions);
  const expensiveBeefMinceWasteScore = Number(expensiveBeefMinceWaste.score || 0);
  const packCleanWaste = plannerPackCleanWasteSummary(selectedOptions);
  const carryForwardWaste = plannerCarryForwardWasteAvoidanceMetrics(selectedOptions, plannerActiveWeekStartKey());
  const carryForwardObligations = plannerCarryForwardObligationMetrics(selectedOptions, plannerActiveWeekStartKey(), dayOptions, days);
  const inventoryUseUpScore = plannerWeeklyInventoryUseUpScore(selectedOptions);
  const ingredientTargetScore = plannerWeeklyIngredientTargetScore(selectedOptions);
  const adjacentDinnerProteinRepeatScore = plannerAdjacentDinnerProteinRepeatScore(selectedOptions);
  const dinnerFatigueSummary = plannerDinnerFatigueSummaryForSelectedOptions(selectedOptions, context.recipeById);
  const baseMetrics = {
    day_index: dayIndex,
    selected_day_count: selectedDayCount,
    visible_day_count: (days || []).length,
    full_ready_days: fullReadyDays,
    partial_days: partialDays,
    gap_days: gapDays,
    ...slotMetrics,
    completed_batch_blocks: completedBatchBlocks,
    unfinished_batch_count: plannerBlockingActiveBatches(activeBatches).length,
    carried_batch_count: plannerCarryoverActiveBatches(activeBatches).length,
    macro_score: Math.round(Number(optionScore || 0) * 10) / 10,
    repeat_fatigue_score: Math.round(repeatFatigueScore * 10) / 10,
    adjacent_dinner_protein_repeat_score: Math.round(adjacentDinnerProteinRepeatScore * 10) / 10,
    dinner_fatigue_penalty: Math.round(Number(dinnerFatigueSummary.penalty || 0) * 10) / 10,
    dinner_fatigue_hard_count: Number(dinnerFatigueSummary.hard_warning_count || 0),
    dinner_fatigue_warning_count: Number(dinnerFatigueSummary.warning_count || 0),
    inventory_use_up_score: Math.round(inventoryUseUpScore * 10) / 10,
    ingredient_target_score: Math.round(ingredientTargetScore * 10) / 10,
    carry_forward_waste_count: Number(carryForwardWaste.carry_forward_waste_count || 0),
    carry_forward_waste_gbp: roundMoney(carryForwardWaste.carry_forward_waste_gbp || 0),
    carry_forward_waste_score: Math.round(Number(carryForwardWaste.carry_forward_waste_score || 0) * 10) / 10,
    carry_forward_obligation_count: Number(carryForwardObligations.carry_forward_obligation_count || 0),
    carry_forward_obligation_unmet_count: Number(carryForwardObligations.carry_forward_obligation_unmet_count || 0),
    carry_forward_silent_ignore_count: Number(carryForwardObligations.carry_forward_silent_ignore_count || 0),
    carry_forward_obligation_blocked_count: Number(carryForwardObligations.carry_forward_obligation_blocked_count || 0),
    carry_forward_obligation_score: Math.round(Number(carryForwardObligations.carry_forward_obligation_score || 0) * 10) / 10,
    carry_forward_obligation_labels: carryForwardObligations.carry_forward_obligation_labels || [],
    carry_forward_obligation_outcomes: carryForwardObligations.carry_forward_obligation_outcomes || [],
    expensive_beef_mince_waste_line_count: Number(expensiveBeefMinceWaste.line_count || 0),
    expensive_beef_mince_waste_amount_g: Math.round(Number(expensiveBeefMinceWaste.leftover_amount_g || 0) * 10) / 10,
    expensive_beef_mince_waste_cost_gbp: Math.round(Number(expensiveBeefMinceWaste.leftover_cost_gbp || 0) * 100) / 100,
    expensive_beef_mince_waste_score: Math.round(expensiveBeefMinceWasteScore * 10) / 10,
    pack_clean_awkward_leftover_count: Number(packCleanWaste.awkward_leftover_count || 0),
    pack_clean_awkward_leftover_value_gbp: roundMoney(packCleanWaste.awkward_leftover_value_gbp || 0),
    pack_clean_waste_score: Math.round(Number(packCleanWaste.score || 0) * 10) / 10,
    shopping_efficiency_score: Math.round(shoppingEfficiencyScore * 10) / 10,
    workload_score: Math.round(workloadScore * 10) / 10,
    cost_score: Math.round(costScore * 10) / 10,
    ...workloadBounds,
    ...budgetBounds,
  };
  const weekScore = plannerWeekScoreSummaryForSelectedOptions(selectedOptions, {
    metrics: baseMetrics,
    recipeById: context.recipeById,
  });
  return {
    ...baseMetrics,
    week_score: weekScore.score,
    week_score_low_waste: Number(weekScore.components.low_waste || 0),
    week_score_fatigue: Number(weekScore.components.fatigue || 0),
    week_score_macro_fit: Number(weekScore.components.macro_fit || 0),
    week_score_cook_time: Number(weekScore.components.cook_time || 0),
    week_score_budget: Number(weekScore.components.budget || 0),
    week_score_pack_batch: Number(weekScore.components.pack_batch || 0),
    previous_week_dinner_exact_repeat_count: Number(weekScore.metrics?.previous_week_dinner_exact_repeat_count || 0),
    week_score_summary: weekScore,
  };
}

function plannerWeeklySequenceBeats(candidate, current) {
  if (!candidate) return false;
  if (!current) return true;
  const checks = [
    ["unfinished_batch_count", "lower"],
    ["missing_required_recipe_slot_count", "lower"],
    ["selected_recipe_slot_count", "higher"],
    ["gap_days", "lower"],
    ["carry_forward_silent_ignore_count", "lower"],
    ["carry_forward_obligation_unmet_count", "lower"],
    ["carry_forward_obligation_score", "lower"],
    ["carry_forward_waste_score", "lower"],
    ["carry_forward_waste_gbp", "lower"],
    ["carry_forward_waste_count", "lower"],
    ["dinner_fatigue_hard_count", "lower"],
    ["previous_week_dinner_exact_repeat_count", "lower"],
    ["dinner_fatigue_penalty", "lower"],
    ["partial_days", "lower"],
    ["full_ready_days", "higher"],
    ["selected_day_count", "higher"],
    ["carried_batch_count", "lower"],
    ["expensive_beef_mince_waste_line_count", "lower"],
    ["expensive_beef_mince_waste_amount_g", "lower"],
    ["expensive_beef_mince_waste_score", "lower"],
    ["pack_clean_awkward_leftover_count", "lower"],
    ["pack_clean_waste_score", "lower"],
    ["week_score", "higher"],
    ["completed_batch_blocks", "higher"],
    ["adjacent_dinner_protein_repeat_score", "lower"],
    ["repeat_fatigue_score", "lower"],
    ["ingredient_target_score", "higher"],
    ["macro_score", "lower"],
    ["inventory_use_up_score", "higher"],
    ["shopping_efficiency_score", "lower"],
    ["workload_score", "lower"],
    ["cost_score", "lower"],
    ["day_index", "higher"],
  ];
  for (const [key, direction] of checks) {
    const a = Number(candidate?.[key] || 0);
    const b = Number(current?.[key] || 0);
    if (a === b) continue;
    return direction === "higher" ? a > b : a < b;
  }
  return false;
}

function plannerWeekSelectedOptions(dayOptions, selectedByDay = null) {
  const hasSelectedMap = selectedByDay && typeof selectedByDay === "object";
  return Object.entries(dayOptions || {}).map(([dayName, result]) => {
    const selectedId = hasSelectedMap ? selectedByDay[dayName] : result?.selected_option_id;
    const option = (result?.options || []).find((item) => item.option_id === selectedId) || null;
    return option ? { dayName, result, option } : null;
  }).filter(Boolean);
}

function plannerWeeklyRepeatFatigueScore(recipeUseCounts) {
  return Object.values(recipeUseCounts || {}).reduce((sum, count) => {
    const repeatCount = Math.max(0, Number(count || 0) - 1);
    return sum + (repeatCount * repeatCount);
  }, 0);
}

function plannerAdjacentDinnerProteinRepeatScore(selectedOptions = [], recipeById = null) {
  let previousFamilies = [];
  return (selectedOptions || []).reduce((sum, { option }) => {
    const currentFamilies = plannerOptionDinnerProteinFamilies(option, recipeById);
    const repeated = currentFamilies.filter((family) => previousFamilies.includes(family)).length;
    previousFamilies = currentFamilies;
    return sum + repeated;
  }, 0);
}

function plannerWeekScorePolicy() {
  const policy = plannerOptionsPolicy().week_score_policy || {};
  return {
    history_window_weeks: Math.max(1, Number(policy.history_window_weeks || 4)),
    max_alternatives: Math.max(1, Number(policy.max_alternatives || 5)),
    meal_fatigue_weights: {
      dinner: 1,
      lunch: 0.35,
      breakfast: 0.2,
      finisher: 0,
      ...(policy.meal_fatigue_weights || {}),
    },
    recent_week_weights: {
      1: 1,
      2: 0.65,
      3: 0.35,
      4: 0.15,
      ...(policy.recent_week_weights || {}),
    },
    score_weights: {
      low_waste: 25,
      fatigue: 30,
      macro_fit: 15,
      cook_time: 10,
      budget: 10,
      pack_batch: 10,
      ...(policy.score_weights || {}),
    },
    balanced_low_waste_mode: policy.balanced_low_waste_mode !== false,
  };
}

function plannerWeekScoreClamp(value, min = 0, max = 100) {
  const numberValue = Number(value || 0);
  if (!Number.isFinite(numberValue)) return min;
  return Math.min(max, Math.max(min, numberValue));
}

function plannerWeekScorePositive(value, target) {
  return plannerWeekScoreClamp((Number(value || 0) / Math.max(1, Number(target || 1))) * 100);
}

function plannerWeekScoreNegative(value, target) {
  return plannerWeekScoreClamp(100 - ((Number(value || 0) / Math.max(1, Number(target || 1))) * 100));
}

function plannerNormalBandRawScore(selectedValue, lowValue, typicalValue, highValue, fallbackTarget = 1) {
  const selected = Number(selectedValue || 0);
  const low = Number(lowValue || 0);
  const typical = Number(typicalValue || 0);
  const high = Number(highValue || 0);
  if (low > 0 && typical > low && selected <= typical) {
    return 50 + (((typical - selected) / Math.max(0.01, typical - low)) * 50);
  }
  if (typical > 0 && high > typical) {
    return 50 - (((selected - typical) / Math.max(0.01, high - typical)) * 50);
  }
  if (high > low) {
    return 100 - (((selected - low) / Math.max(0.01, high - low)) * 100);
  }
  if (low > 0 && selected <= low) return 100;
  return 100 - ((selected / Math.max(1, Number(fallbackTarget || 1))) * 100);
}

function plannerWorkloadRawScoreForMetrics(metrics = {}) {
  return plannerNormalBandRawScore(
    metrics.workload_score,
    metrics.workload_min_minutes,
    metrics.workload_typical_minutes,
    metrics.workload_max_minutes,
    650
  );
}

function plannerWorkloadScoreForMetrics(metrics = {}) {
  return plannerWeekScoreClamp(plannerWorkloadRawScoreForMetrics(metrics));
}

function plannerBudgetRawScoreForMetrics(metrics = {}) {
  return plannerNormalBandRawScore(
    metrics.cost_score,
    metrics.budget_min_cost,
    metrics.budget_typical_cost,
    metrics.budget_max_cost,
    70
  );
}

function plannerBudgetScoreForMetrics(metrics = {}) {
  return plannerWeekScoreClamp(plannerBudgetRawScoreForMetrics(metrics));
}

function plannerWeekScoreReadinessBlocked(metrics = {}) {
  const requiredCount = Number(metrics.required_recipe_slot_count || 0);
  const selectedRequiredCount = Number(metrics.selected_recipe_slot_count || 0);
  const missingRequiredCount = Number(metrics.missing_required_recipe_slot_count || 0);
  const hasSelectedDayCount = Object.prototype.hasOwnProperty.call(metrics, "selected_day_count");
  const hasFullReadyDays = Object.prototype.hasOwnProperty.call(metrics, "full_ready_days");
  const hasVisibleDayCount = Object.prototype.hasOwnProperty.call(metrics, "visible_day_count");
  return Number(metrics.gap_days || 0) > 0
    || Number(metrics.partial_days || 0) > 0
    || missingRequiredCount > 0
    || (requiredCount > 0 && selectedRequiredCount < requiredCount)
    || (
      Number(metrics.selected_day_count || 0) > 0
      && hasFullReadyDays
      && Number(metrics.full_ready_days || 0) < Number(metrics.selected_day_count || 0)
    )
    || (
      requiredCount <= 0
      && hasSelectedDayCount
      && hasVisibleDayCount
      && Number(metrics.visible_day_count || 0) > 0
      && Number(metrics.selected_day_count || 0) < Number(metrics.visible_day_count || 0)
    );
}

function plannerWeekScoreSummaryForSelectedOptions(selectedOptions = [], context = {}) {
  const policy = plannerWeekScorePolicy();
  const currentDinnerFatigueSummary = plannerDinnerFatigueSummaryForSelectedOptions(selectedOptions, context.recipeById);
  const packCleanWaste = plannerPackCleanWasteSummary(selectedOptions);
  const carryForwardWaste = plannerCarryForwardWasteAvoidanceMetrics(selectedOptions, plannerActiveWeekStartKey());
  const carryForwardObligations = context.metrics
    ? {}
    : plannerCarryForwardObligationMetrics(selectedOptions, plannerActiveWeekStartKey(), {}, currentPlannerTemplate()?.days || []);
  const metrics = {
    selected_day_count: selectedOptions.length,
    macro_score: selectedOptions.reduce((sum, { option }) => sum + Number(option?.score || 0), 0),
    inventory_use_up_score: plannerWeeklyInventoryUseUpScore(selectedOptions),
    ingredient_target_score: plannerWeeklyIngredientTargetScore(selectedOptions),
    carry_forward_waste_count: Number(carryForwardWaste.carry_forward_waste_count || 0),
    carry_forward_waste_gbp: roundMoney(carryForwardWaste.carry_forward_waste_gbp || 0),
    carry_forward_waste_score: Math.round(Number(carryForwardWaste.carry_forward_waste_score || 0) * 10) / 10,
    carry_forward_obligation_count: Number(carryForwardObligations.carry_forward_obligation_count || 0),
    carry_forward_obligation_unmet_count: Number(carryForwardObligations.carry_forward_obligation_unmet_count || 0),
    carry_forward_silent_ignore_count: Number(carryForwardObligations.carry_forward_silent_ignore_count || 0),
    carry_forward_obligation_blocked_count: Number(carryForwardObligations.carry_forward_obligation_blocked_count || 0),
    carry_forward_obligation_score: Math.round(Number(carryForwardObligations.carry_forward_obligation_score || 0) * 10) / 10,
    carry_forward_obligation_labels: carryForwardObligations.carry_forward_obligation_labels || [],
    carry_forward_obligation_outcomes: carryForwardObligations.carry_forward_obligation_outcomes || [],
    ...plannerExpensiveBeefMinceWasteMetrics(selectedOptions),
    pack_clean_awkward_leftover_count: Number(packCleanWaste.awkward_leftover_count || 0),
    pack_clean_awkward_leftover_value_gbp: roundMoney(packCleanWaste.awkward_leftover_value_gbp || 0),
    pack_clean_waste_score: Math.round(Number(packCleanWaste.score || 0) * 10) / 10,
    shopping_efficiency_score: plannerShoppingEfficiencyScore(selectedOptions),
    workload_score: selectedOptions.reduce((sum, { option }) => sum + plannerOptionWorkloadScore(option), 0),
    cost_score: selectedOptions.reduce((sum, { option }) => sum + plannerOptionCostScore(option), 0),
    completed_batch_blocks: plannerCompletedBatchBlockCount(plannerWeeklyRecipeUseCounts(selectedOptions)),
    adjacent_dinner_protein_repeat_score: plannerAdjacentDinnerProteinRepeatScore(selectedOptions, context.recipeById),
    dinner_fatigue_penalty: Number(currentDinnerFatigueSummary.penalty || 0),
    dinner_fatigue_hard_count: Number(currentDinnerFatigueSummary.hard_warning_count || 0),
    dinner_fatigue_warning_count: Number(currentDinnerFatigueSummary.warning_count || 0),
    ...(context.metrics || {}),
  };
  const targetCount = (plannerIngredientTargetsForWeek(plannerActiveWeekStartKey()).targets || []).length;
  const lowWasteRaw = Number(metrics.inventory_use_up_score || 0) + Number(metrics.ingredient_target_score || 0);
  const useUpScore = lowWasteRaw > 0
    ? plannerWeekScoreClamp(72 + (plannerWeekScorePositive(lowWasteRaw, 400) * 0.28))
    : targetCount ? 40 : 75;
  const wastePenaltyScore = plannerWeekScoreNegative(
    Number(metrics.shopping_efficiency_score || 0)
    + Number(metrics.carry_forward_waste_score || 0)
    + Number(metrics.carry_forward_obligation_score || 0),
    900
  );
  const lowWaste = plannerWeekScoreClamp((useUpScore * 0.72) + (wastePenaltyScore * 0.28));
  const fatigueSummary = plannerWeekLongTermFatigueSummary(selectedOptions, {
    policy,
    recipeById: context.recipeById,
    adjacentDinnerRepeatScore: Number(metrics.adjacent_dinner_protein_repeat_score || 0),
    currentDinnerFatigueSummary,
  });
  const fatigue = fatigueSummary.score;
  const requiredSlotCount = Number(metrics.required_recipe_slot_count || 0);
  const selectedSlotCount = Number(metrics.selected_recipe_slot_count || 0);
  const macroFit = requiredSlotCount > 0
    ? plannerWeekScoreClamp((selectedSlotCount / Math.max(1, requiredSlotCount)) * 100)
    : Number(metrics.selected_day_count || 0)
    ? plannerWeekScoreClamp((Number(metrics.full_ready_days ?? metrics.selected_day_count ?? 0) / Math.max(1, Number(metrics.selected_day_count || 0))) * 100)
    : plannerWeekScoreNegative(metrics.macro_score, 2500);
  const workloadRawScore = plannerWorkloadRawScoreForMetrics(metrics);
  const cookTime = plannerWorkloadScoreForMetrics(metrics);
  const workloadOverNormalMinutes = Math.max(0, Number(metrics.workload_score || 0) - Number(metrics.workload_max_minutes || 0));
  const budgetRawScore = plannerBudgetRawScoreForMetrics(metrics);
  const budget = plannerBudgetScoreForMetrics(metrics);
  const budgetOverNormalCost = Math.max(0, Number(metrics.cost_score || 0) - Number(metrics.budget_max_cost || 0));
  const batchScore = Number(metrics.completed_batch_blocks || 0) ? plannerWeekScoreClamp(72 + (Number(metrics.completed_batch_blocks || 0) * 12)) : 75;
  const packBatch = plannerWeekScoreClamp((batchScore * 0.45) + (wastePenaltyScore * 0.55));
  const components = {
    low_waste: Math.round(lowWaste),
    fatigue: Math.round(fatigue),
    macro_fit: Math.round(macroFit),
    cook_time: Math.round(cookTime),
    budget: Math.round(budget),
    pack_batch: Math.round(packBatch),
  };
  const weights = policy.score_weights;
  const totalWeight = Object.values(weights).reduce((sum, value) => sum + Number(value || 0), 0) || 1;
  const rawScore = Math.round(Object.entries(weights).reduce((sum, [key, weight]) => {
    return sum + (Number(components[key] || 0) * Number(weight || 0));
  }, 0) / totalWeight);
  const readinessBlocked = plannerWeekScoreReadinessBlocked(metrics);
  const score = readinessBlocked ? Math.min(rawScore, 45) : rawScore;
  const normalizedMetrics = {
    selected_day_count: Number(metrics.selected_day_count || 0),
    visible_day_count: Number(metrics.visible_day_count || 0),
    full_ready_days: Number(metrics.full_ready_days || 0),
    partial_days: Number(metrics.partial_days || 0),
    gap_days: Number(metrics.gap_days || 0),
    required_recipe_slot_count: Number(metrics.required_recipe_slot_count || 0),
    selected_recipe_slot_count: Number(metrics.selected_recipe_slot_count || 0),
    missing_required_recipe_slot_count: Number(metrics.missing_required_recipe_slot_count || 0),
    missing_required_recipe_day_count: Number(metrics.missing_required_recipe_day_count || 0),
    completed_batch_blocks: Number(metrics.completed_batch_blocks || 0),
    adjacent_dinner_protein_repeat_score: Number(metrics.adjacent_dinner_protein_repeat_score || 0),
    dinner_fatigue_penalty: Math.round(Number(metrics.dinner_fatigue_penalty || 0) * 10) / 10,
    dinner_fatigue_hard_count: Number(metrics.dinner_fatigue_hard_count || 0),
    dinner_fatigue_warning_count: Number(metrics.dinner_fatigue_warning_count || 0),
    assumed_stock_use_count: Number(metrics.assumed_stock_use_count || 0),
    inventory_use_up_score: Math.round(Number(metrics.inventory_use_up_score || 0) * 10) / 10,
    ingredient_target_score: Math.round(Number(metrics.ingredient_target_score || 0) * 10) / 10,
    carry_forward_waste_count: Number(metrics.carry_forward_waste_count || 0),
    carry_forward_waste_gbp: Math.round(Number(metrics.carry_forward_waste_gbp || 0) * 100) / 100,
    carry_forward_waste_score: Math.round(Number(metrics.carry_forward_waste_score || 0) * 10) / 10,
    carry_forward_obligation_count: Number(metrics.carry_forward_obligation_count || 0),
    carry_forward_obligation_unmet_count: Number(metrics.carry_forward_obligation_unmet_count || 0),
    carry_forward_silent_ignore_count: Number(metrics.carry_forward_silent_ignore_count || 0),
    carry_forward_obligation_blocked_count: Number(metrics.carry_forward_obligation_blocked_count || 0),
    carry_forward_obligation_score: Math.round(Number(metrics.carry_forward_obligation_score || 0) * 10) / 10,
    carry_forward_obligation_labels: Array.isArray(metrics.carry_forward_obligation_labels) ? metrics.carry_forward_obligation_labels.slice(0, 6) : [],
    carry_forward_obligation_outcomes: Array.isArray(metrics.carry_forward_obligation_outcomes) ? metrics.carry_forward_obligation_outcomes.slice(0, 12) : [],
    expensive_beef_mince_waste_line_count: Number(metrics.expensive_beef_mince_waste_line_count || 0),
    expensive_beef_mince_waste_amount_g: Math.round(Number(metrics.expensive_beef_mince_waste_amount_g || 0) * 10) / 10,
    expensive_beef_mince_waste_cost_gbp: Math.round(Number(metrics.expensive_beef_mince_waste_cost_gbp || 0) * 100) / 100,
    expensive_beef_mince_waste_score: Math.round(Number(metrics.expensive_beef_mince_waste_score || 0) * 10) / 10,
    pack_clean_awkward_leftover_count: Number(metrics.pack_clean_awkward_leftover_count || 0),
    pack_clean_awkward_leftover_value_gbp: Math.round(Number(metrics.pack_clean_awkward_leftover_value_gbp || 0) * 100) / 100,
    pack_clean_waste_score: Math.round(Number(metrics.pack_clean_waste_score || 0) * 10) / 10,
    shopping_efficiency_score: Math.round(Number(metrics.shopping_efficiency_score || 0) * 10) / 10,
    workload_score: Math.round(Number(metrics.workload_score || 0) * 10) / 10,
    workload_min_minutes: roundPlannerMinutes(metrics.workload_min_minutes),
    workload_typical_minutes: roundPlannerMinutes(metrics.workload_typical_minutes),
    workload_max_minutes: roundPlannerMinutes(metrics.workload_max_minutes),
    workload_range_width: roundPlannerMinutes(metrics.workload_range_width),
    workload_outlier_max_minutes: roundPlannerMinutes(metrics.workload_outlier_max_minutes),
    workload_outlier_candidate_count: Number(metrics.workload_outlier_candidate_count || 0),
    workload_over_normal_minutes: roundPlannerMinutes(workloadOverNormalMinutes),
    workload_raw_score: Math.round(Number(workloadRawScore || 0) * 10) / 10,
    workload_priced_slot_count: Number(metrics.workload_priced_slot_count || 0),
    workload_slot_count: Number(metrics.workload_slot_count || 0),
    cost_score: Math.round(Number(metrics.cost_score || 0) * 10) / 10,
    budget_min_cost: Math.round(Number(metrics.budget_min_cost || 0) * 100) / 100,
    budget_typical_cost: Math.round(Number(metrics.budget_typical_cost || 0) * 100) / 100,
    budget_max_cost: Math.round(Number(metrics.budget_max_cost || 0) * 100) / 100,
    budget_range_width: Math.round(Number(metrics.budget_range_width || 0) * 100) / 100,
    budget_outlier_max_cost: Math.round(Number(metrics.budget_outlier_max_cost || 0) * 100) / 100,
    budget_outlier_candidate_count: Number(metrics.budget_outlier_candidate_count || 0),
    budget_over_normal_cost: Math.round(budgetOverNormalCost * 100) / 100,
    budget_raw_score: Math.round(Number(budgetRawScore || 0) * 10) / 10,
    budget_priced_slot_count: Number(metrics.budget_priced_slot_count || 0),
    budget_slot_count: Number(metrics.budget_slot_count || 0),
    exact_recent_repeat_penalty: Math.round(Number(fatigueSummary.exact_repeat_penalty || 0) * 10) / 10,
    family_recent_repeat_penalty: Math.round(Number(fatigueSummary.family_repeat_penalty || 0) * 10) / 10,
    current_week_fatigue_penalty: Math.round(Number(fatigueSummary.current_week_penalty || 0) * 10) / 10,
    fatigue_hard_warning_count: Number(fatigueSummary.hard_warning_count || 0),
    previous_week_dinner_exact_repeat_count: Number(fatigueSummary.previous_week_dinner_exact_repeat_count || 0),
  };
  return {
    schema_version: "v4.week_score.1",
    score,
    label: readinessBlocked ? "not ready" : plannerWeekScoreLabel(score),
    components,
    metrics: normalizedMetrics,
    reasons: plannerWeekScoreReasons(score, components, normalizedMetrics, fatigueSummary, targetCount),
  };
}

function plannerWeeklyRecipeUseCounts(selectedOptions = []) {
  const counts = {};
  (selectedOptions || []).forEach(({ option }) => {
    Object.entries(plannerOptionRecipeUseCounts(option)).forEach(([recipeId, useCount]) => {
      counts[recipeId] = Number(counts[recipeId] || 0) + Number(useCount || 0);
    });
  });
  return counts;
}

function plannerWeekScoreLabel(score) {
  if (score >= 85) return "strong";
  if (score >= 72) return "balanced";
  if (score >= 58) return "acceptable";
  return "weak";
}

function plannerWeekScoreReasons(score, components, metrics, fatigueSummary, targetCount = 0) {
  const reasons = [];
  if (plannerWeekScoreReadinessBlocked(metrics)) {
    if (Number(metrics.missing_required_recipe_slot_count || 0) > 0 || Number(metrics.gap_days || 0) > 0) {
      reasons.push("Not ready yet; required meals are still missing.");
    } else {
      reasons.push("Meals are filled; stock or partial-day checks still need review.");
    }
  } else if (score >= 85) reasons.push("Strong balanced week.");
  else if (score >= 72) reasons.push("Balanced week with a few tradeoffs.");
  else reasons.push("Valid week, but the score shows tradeoffs.");
  if (components.low_waste >= 84) reasons.push("Uses stock and low-waste targets well.");
  else if (targetCount) reasons.push("Some stock or use-up targets are still not ideal.");
  else reasons.push("No urgent counted stock is driving this week.");
  if (components.fatigue >= 85 && Number(fatigueSummary.current_dinner_count || 0) > 0) reasons.push("Keeps dinners varied against recent weeks.");
  if (Number(fatigueSummary.exact_dinner_repeat_count || 0) > 0) reasons.push("Recent dinner repeats drag the score down.");
  else if (Number(fatigueSummary.current_dinner_count || 0) > 0) reasons.push("Avoids exact dinner repeats from the recent history window.");
  (fatigueSummary.hard_warnings || []).slice(0, 2).forEach((warning) => reasons.push(warning.message || warning));
  if (Number(fatigueSummary.use_up_breach_count || 0) > 0) reasons.push("Use-up override accepted for urgent stock.");
  if (metrics.adjacent_dinner_protein_repeat_score) reasons.push("Back-to-back dinner protein repeats reduce variety.");
  if (Number(metrics.workload_over_normal_minutes || 0) > 0) reasons.push("Kitchen time is above the normal band for these meal slots.");
  else if (components.cook_time < 65) reasons.push("Kitchen time is heavier than typical options.");
  if (Number(metrics.budget_over_normal_cost || 0) > 0) reasons.push("This route is above the normal budget band for these meal slots.");
  else if (components.budget < 65) reasons.push("This route is more expensive than typical options.");
  if (Number(metrics.carry_forward_silent_ignore_count || 0) > 0) reasons.push("Some usable previous-week food had a matching recipe but was not selected.");
  else if (Number(metrics.carry_forward_obligation_blocked_count || 0) > 0) reasons.push("Some previous-week food could not be matched to a valid early recipe.");
  if (Number(metrics.carry_forward_waste_gbp || 0) > 0) reasons.push("Some previous-week fresh food is still expected to be wasted.");
  if (Number(metrics.pack_clean_awkward_leftover_count || 0) > 0) reasons.push("Awkward fresh leftovers still need a cleaner recipe route.");
  if (components.pack_batch < 65) reasons.push("Awkward packs or weak batch efficiency reduce the score.");
  return [...new Set(reasons)].slice(0, 5);
}

function plannerWeekLongTermFatigueSummary(selectedOptions = [], { policy = plannerWeekScorePolicy(), recipeById = null, adjacentDinnerRepeatScore = 0, currentDinnerFatigueSummary = null } = {}) {
  const currentRecords = plannerWeekScoreSelectedRecipeRecords(selectedOptions, recipeById);
  const historyRecords = plannerWeekScoreHistoryRecipeRecords(policy, recipeById);
  const dinnerFatigueSummary = currentDinnerFatigueSummary || plannerDinnerFatigueSummaryForSelectedOptions(selectedOptions, recipeById);
  const urgentUseUpCount = plannerSelectedOptionsUrgentUseUpCount(selectedOptions);
  let exactRepeatPenalty = 0;
  let familyRepeatPenalty = 0;
  let exactDinnerRepeatCount = 0;
  let previousWeekDinnerExactRepeatCount = 0;
  currentRecords.forEach((current) => {
    const mealWeight = plannerWeekScoreMealFatigueWeight(current.meal_category, policy);
    if (mealWeight <= 0) return;
    historyRecords.forEach((past) => {
      const recentWeight = plannerWeekScoreRecentWeight(past.week_distance, policy);
      if (current.recipe_id === past.recipe_id) {
        exactRepeatPenalty += 42 * mealWeight * recentWeight;
        if (current.meal_category === "dinner") exactDinnerRepeatCount += 1;
        if (current.meal_category === "dinner" && Number(past.week_distance || 0) === 1) previousWeekDinnerExactRepeatCount += 1;
        return;
      }
      if (current.meal_category !== "dinner" || past.meal_category !== "dinner") return;
      if (current.variety_family_key && current.variety_family_key === past.variety_family_key) {
        familyRepeatPenalty += 8 * recentWeight;
      }
    });
  });
  const adjacentPenalty = Number(adjacentDinnerRepeatScore || 0) * 35;
  const currentWeekPenalty = Number(dinnerFatigueSummary.penalty || 0);
  const rawHardWarningCount = Number(dinnerFatigueSummary.hard_warning_count || 0) + previousWeekDinnerExactRepeatCount;
  const useUpBreachCount = Math.min(1, rawHardWarningCount, urgentUseUpCount);
  const hardWarningCount = Math.max(0, rawHardWarningCount - useUpBreachCount);
  const hardPenalty = hardWarningCount * 28;
  const penalty = exactRepeatPenalty + familyRepeatPenalty + adjacentPenalty + currentWeekPenalty + hardPenalty;
  return {
    score: plannerWeekScoreClamp(100 - penalty),
    exact_repeat_penalty: exactRepeatPenalty,
    family_repeat_penalty: familyRepeatPenalty,
    adjacent_repeat_penalty: adjacentPenalty,
    current_week_penalty: currentWeekPenalty,
    hard_warning_count: hardWarningCount,
    use_up_breach_count: useUpBreachCount,
    hard_warnings: dinnerFatigueSummary.hard_warnings || [],
    warnings: dinnerFatigueSummary.warnings || [],
    exact_dinner_repeat_count: exactDinnerRepeatCount,
    previous_week_dinner_exact_repeat_count: previousWeekDinnerExactRepeatCount,
    current_dinner_count: currentRecords.filter((record) => record.meal_category === "dinner").length,
  };
}

function plannerWeekScoreSelectedRecipeRecords(selectedOptions = [], recipeById = null) {
  const slots = new Map(allPlannerSlots(currentPlannerTemplate()).map((slot) => [slot.slot_id, slot]));
  const bestByRecipe = new Map();
  (selectedOptions || []).forEach(({ dayName, option }) => {
    Object.entries(option?.recipe_ids_by_slot || {}).forEach(([slotId, recipeId]) => {
      if (!recipeId) return;
      const recipe = plannerRecipeById(recipeId, recipeById);
      const slot = slots.get(slotId);
      const category = plannerValidMealCategory(slot?.meal_category || slot?.category || recipeMealCategory(recipe)) || recipeMealCategory(recipe);
      const record = {
        recipe_id: String(recipeId),
        day_name: dayName || "",
        meal_category: category,
        variety_family_key: plannerRecipeDinnerVarietyFamilyKey(recipe),
      };
      const existing = bestByRecipe.get(record.recipe_id);
      if (!existing || plannerWeekScoreMealFatigueWeight(record.meal_category) > plannerWeekScoreMealFatigueWeight(existing.meal_category)) {
        bestByRecipe.set(record.recipe_id, record);
      }
    });
  });
  return [...bestByRecipe.values()];
}

function plannerWeekScoreHistoryRecipeRecords(policy = plannerWeekScorePolicy(), recipeById = null) {
  const activeWeek = plannerActiveWeekStartKey();
  const activeDate = plannerDateFromKey(activeWeek);
  const records = [];
  Object.values(normalizePlannerWeekHistory(state.plannerWeekHistory).weeks || {}).forEach((record) => {
    const weekStart = plannerNormalizeWeekStartKey(record?.week_start || "");
    if (!weekStart || weekStart === activeWeek) return;
    const recordDate = plannerDateFromKey(weekStart);
    if (!activeDate || !recordDate) return;
    const distanceDays = (activeDate.getTime() - recordDate.getTime()) / (24 * 60 * 60 * 1000);
    const weekDistance = Math.round(distanceDays / 7);
    if (!Number.isFinite(weekDistance) || weekDistance < 1 || weekDistance > Number(policy.history_window_weeks || 4)) return;
    const seen = new Set();
    const slotRecords = Array.isArray(record.slot_records) && record.slot_records.length
      ? record.slot_records
      : (record.selected_recipe_ids || []).map((recipeId) => ({ recipe_id: recipeId }));
    slotRecords.forEach((slotRecord) => {
      const recipeId = String(slotRecord?.recipe_id || "");
      if (!recipeId || seen.has(recipeId)) return;
      seen.add(recipeId);
      const recipe = plannerRecipeById(recipeId, recipeById);
      const category = plannerValidMealCategory(slotRecord?.meal_category || slotRecord?.category || recipeMealCategory(recipe)) || recipeMealCategory(recipe);
      records.push({
        week_start: weekStart,
        week_distance: weekDistance,
        recipe_id: recipeId,
        meal_category: category,
        variety_family_key: plannerRecipeDinnerVarietyFamilyKey(recipe),
      });
    });
  });
  return records;
}

function plannerWeekScoreMealFatigueWeight(category, policy = plannerWeekScorePolicy()) {
  const normalized = plannerValidMealCategory(category || "") || "recipe";
  return Number(policy.meal_fatigue_weights?.[normalized] ?? 0.2);
}

function plannerWeekScoreRecentWeight(weekDistance, policy = plannerWeekScorePolicy()) {
  const key = String(Math.max(1, Math.round(Number(weekDistance || 1))));
  return Number(policy.recent_week_weights?.[key] ?? 0);
}

function plannerRecipeDinnerVarietyFamilyKey(recipe) {
  if (!recipe || recipeMealCategory(recipe) !== "dinner") return "";
  const filters = plannerNormalizeFilterList(recipe.planner_filters || recipe.filters || recipe.tags || []);
  const protein = plannerRecipePrimaryProteinFamily(recipe);
  const cuisine = filters.find((filter) => String(filter).startsWith("cuisine:")) || (recipe.cuisine ? `cuisine:${recipe.cuisine}` : "");
  const style = filters.find((filter) => ["fakeaway", "comfort", "salad", "bowl", "traybake", "one-pan", "pasta"].includes(filter)) || "";
  return [protein, cuisine, style].filter(Boolean).join("|");
}

function plannerAddWeeklyScoreCandidate(leaderboard, metrics, selectedByDay) {
  if (!Array.isArray(leaderboard) || !metrics) return;
  const selected = selectedByDay && typeof selectedByDay === "object" ? { ...selectedByDay } : {};
  const key = plannerWeekScoreSelectedByDayKey(selected);
  if (!key) return;
  const existingIndex = leaderboard.findIndex((item) => item.key === key);
  const record = {
    key,
    selected_option_by_day: selected,
    score: Number(metrics.week_score || 0),
    reasons: metrics.week_score_summary?.reasons || [],
    metrics: plannerWeekScorePublicMetrics(metrics),
  };
  if (existingIndex >= 0) {
    if (plannerWeeklySequenceBeats(metrics, leaderboard[existingIndex].metrics)) leaderboard[existingIndex] = record;
  } else {
    leaderboard.push(record);
  }
  const limit = Math.max(8, Number(plannerWeekScorePolicy().max_alternatives || 5) * 4);
  leaderboard.sort((a, b) => (
    plannerWeeklySequenceBeats(a.metrics, b.metrics) ? -1
      : plannerWeeklySequenceBeats(b.metrics, a.metrics) ? 1
        : a.key.localeCompare(b.key)
  ));
  if (leaderboard.length > limit) leaderboard.splice(limit);
}

function plannerWeekScorePublicMetrics(metrics = {}) {
  return {
    week_score: Number(metrics.week_score || 0),
    selected_day_count: Number(metrics.selected_day_count || 0),
    full_ready_days: Number(metrics.full_ready_days || 0),
    gap_days: Number(metrics.gap_days || 0),
    completed_batch_blocks: Number(metrics.completed_batch_blocks || 0),
    adjacent_dinner_protein_repeat_score: Number(metrics.adjacent_dinner_protein_repeat_score || 0),
    dinner_fatigue_penalty: Number(metrics.dinner_fatigue_penalty || 0),
    dinner_fatigue_hard_count: Number(metrics.dinner_fatigue_hard_count || 0),
    dinner_fatigue_warning_count: Number(metrics.dinner_fatigue_warning_count || 0),
    previous_week_dinner_exact_repeat_count: Number(metrics.previous_week_dinner_exact_repeat_count || 0),
    inventory_use_up_score: Number(metrics.inventory_use_up_score || 0),
    assumed_stock_use_count: Number(metrics.assumed_stock_use_count || 0),
    ingredient_target_score: Number(metrics.ingredient_target_score || 0),
    carry_forward_waste_count: Number(metrics.carry_forward_waste_count || 0),
    carry_forward_waste_gbp: Number(metrics.carry_forward_waste_gbp || 0),
    carry_forward_waste_score: Number(metrics.carry_forward_waste_score || 0),
    carry_forward_obligation_count: Number(metrics.carry_forward_obligation_count || 0),
    carry_forward_obligation_unmet_count: Number(metrics.carry_forward_obligation_unmet_count || 0),
    carry_forward_silent_ignore_count: Number(metrics.carry_forward_silent_ignore_count || 0),
    carry_forward_obligation_blocked_count: Number(metrics.carry_forward_obligation_blocked_count || 0),
    carry_forward_obligation_score: Number(metrics.carry_forward_obligation_score || 0),
    carry_forward_obligation_labels: Array.isArray(metrics.carry_forward_obligation_labels) ? metrics.carry_forward_obligation_labels.slice(0, 6) : [],
    carry_forward_obligation_outcomes: Array.isArray(metrics.carry_forward_obligation_outcomes) ? metrics.carry_forward_obligation_outcomes.slice(0, 12) : [],
    pack_clean_awkward_leftover_count: Number(metrics.pack_clean_awkward_leftover_count || 0),
    pack_clean_awkward_leftover_value_gbp: Number(metrics.pack_clean_awkward_leftover_value_gbp || 0),
    pack_clean_waste_score: Number(metrics.pack_clean_waste_score || 0),
    shopping_efficiency_score: Number(metrics.shopping_efficiency_score || 0),
    workload_score: Number(metrics.workload_score || 0),
    cost_score: Number(metrics.cost_score || 0),
  };
}

function plannerWeekScoreSelectedByDayKey(selectedByDay = {}) {
  return Object.entries(selectedByDay || {})
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([dayName, optionId]) => `${dayName}:${optionId}`)
    .join("|");
}

function plannerWeekScoreAlternativesFromSequence(sequenceResult, winningScore = null) {
  const policy = plannerWeekScorePolicy();
  const winnerKey = plannerWeekScoreSelectedByDayKey(sequenceResult?.selected_option_by_day || {});
  const alternatives = (sequenceResult?.leaderboard || [])
    .filter((item) => item.key && item.key !== winnerKey)
    .slice(0, Number(policy.max_alternatives || 5))
    .map((item) => ({
      label: plannerWeekScoreAlternativeLabel(item, winningScore),
      score: Math.round(Number(item.score || item.metrics?.week_score || 0)),
      selected_option_by_day: item.selected_option_by_day || {},
      reasons: (item.reasons || []).slice(0, 3),
      metrics: item.metrics || {},
    }));
  return normalizePlannerWeekScoreAlternatives(alternatives);
}

function plannerWeekScoreAlternativeLabel(alternative, winningScore = null) {
  const metrics = alternative?.metrics || {};
  const winnerMetrics = winningScore?.metrics || {};
  if (Number(metrics.cost_score || Infinity) < Number(winnerMetrics.cost_score || Infinity)) return "Cheaper route";
  if (Number(metrics.workload_score || Infinity) < Number(winnerMetrics.workload_score || Infinity)) return "Lower cook time";
  if (Number(metrics.dinner_fatigue_hard_count || 0) < Number(winnerMetrics.dinner_fatigue_hard_count || 0)) return "More varied dinners";
  if (Number(metrics.dinner_fatigue_penalty || 0) < Number(winnerMetrics.dinner_fatigue_penalty || 0)) return "More varied dinners";
  if (Number(metrics.adjacent_dinner_protein_repeat_score || 0) < Number(winnerMetrics.adjacent_dinner_protein_repeat_score || 0)) return "More varied dinners";
  if (Number(metrics.inventory_use_up_score || 0) + Number(metrics.ingredient_target_score || 0) > Number(winnerMetrics.inventory_use_up_score || 0) + Number(winnerMetrics.ingredient_target_score || 0)) return "More use-up";
  return "Alternative route";
}

function plannerCompletedBatchBlockCount(recipeUseCounts) {
  return Object.entries(recipeUseCounts || {}).reduce((sum, [recipeId, count]) => {
    const recipe = recipes().find((item) => recipeKey(item) === recipeId);
    const blockSize = plannerRecipeBlockSize(recipe);
    return sum + (plannerRecipeTracksBatchContinuity(recipe, blockSize) && Number(count || 0) >= blockSize ? 1 : 0);
  }, 0);
}

function plannerSelectionWorkloadScore(selection = [], scoringContext = {}) {
  return roundPlannerMinutes((selection || []).reduce((sum, item) => {
    return sum + plannerRecipeActiveMinutesPerUse(item?.recipe, scoringContext);
  }, 0));
}

function plannerOptionWorkloadScore(option, recipeById = null) {
  const entries = Object.entries(option?.recipe_ids_by_slot || {}).filter(([, recipeId]) => recipeId);
  if (entries.length) {
    const total = entries.reduce((sum, [, recipeId]) => {
      const recipe = plannerRecipeById(recipeId, recipeById);
      return sum + plannerRecipeActiveMinutesPerUse(recipe);
    }, 0);
    if (total > 0) return roundPlannerMinutes(total);
  }
  return roundPlannerMinutes(Object.values(option?.totals_by_person || {})
    .reduce((sum, total) => sum + Number(total?.active_minutes || 0), 0));
}

function plannerOptionCostScore(option) {
  return Object.values(option?.totals_by_person || {})
    .reduce((sum, total) => sum + Number(total?.cost_gbp || 0), 0);
}

function plannerSelectedOptionsCacheKey(selectedOptions = []) {
  return (selectedOptions || []).map(({ dayName, option }) => {
    const optionId = option?.option_id || Object.values(option?.recipe_ids_by_slot || {}).sort().join(",");
    return `${dayName || ""}:${optionId}`;
  }).sort().join("|");
}

function plannerInventoryUpdateMarker(weekStart = plannerActiveWeekStartKey()) {
  const week = plannerInventoryWeek(weekStart);
  return `${state.weekInventoryDraft?.updated_at || ""}:${week.updated_at || ""}`;
}

function plannerInitialSequentialStockState(weekStart = plannerActiveWeekStartKey()) {
  const normalizedWeekStart = plannerNormalizeWeekStartKey(weekStart);
  const targets = plannerIngredientTargetsForWeek(normalizedWeekStart);
  const targetMap = targets.by_inventory_id || {};
  const byInventoryId = {};
  plannerMatchedInventoryItems(normalizedWeekStart).forEach((item) => {
    const amount = Number(item.amount || 0);
    if (!Number.isFinite(amount) || amount <= 0) return;
    const target = targetMap[item.inventory_id] || null;
    byInventoryId[item.inventory_id] = {
      inventory_id: item.inventory_id,
      item_name: item.item_name,
      amount,
      remaining: amount,
      unit: shoppingNormalizeAmountUnit(item.unit) || "g",
      target,
      source_type: item.source_type || "",
    };
  });
  return {
    week_start: normalizedWeekStart,
    by_inventory_id: byInventoryId,
  };
}

function plannerCloneSequentialStockState(stockState) {
  if (!stockState || typeof stockState !== "object") return plannerInitialSequentialStockState(plannerActiveWeekStartKey());
  return {
    week_start: stockState.week_start || plannerActiveWeekStartKey(),
    by_inventory_id: Object.fromEntries(Object.entries(stockState.by_inventory_id || {}).map(([inventoryId, record]) => [
      inventoryId,
      { ...record, target: record.target ? { ...record.target } : null },
    ])),
  };
}

function plannerSequentialStockStateKey(stockState) {
  return Object.entries(stockState?.by_inventory_id || {})
    .filter(([, record]) => record?.target && Number(record.remaining || 0) > 0)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([inventoryId, record]) => {
      const remaining = Math.round(Number(record.remaining || 0) * 100) / 100;
      return `${inventoryId}:${remaining}:${shoppingNormalizeAmountUnit(record.unit)}`;
    })
    .join("|");
}

function plannerSequentialStockOptionScore(option, stockState) {
  return (option?.inventory_use_up || []).reduce((sum, use) => {
    const record = stockState?.by_inventory_id?.[use.inventory_id];
    const target = record?.target || null;
    if (!target || record.unit !== shoppingNormalizeAmountUnit(use.unit) || Number(record.remaining || 0) <= 0) return sum;
    const used = Math.min(Number(record.remaining || 0), Number(use.used_amount || 0));
    if (used <= 0) return sum;
    return sum + plannerIngredientTargetUseValue({ ...use, used_amount: used }, target);
  }, 0);
}

function plannerAdvanceSequentialStockState(option, stockState) {
  const next = plannerCloneSequentialStockState(stockState);
  (option?.inventory_use_up || []).forEach((use) => {
    const record = next.by_inventory_id?.[use.inventory_id];
    if (!record || record.unit !== shoppingNormalizeAmountUnit(use.unit) || Number(record.remaining || 0) <= 0) return;
    const used = Math.min(Number(record.remaining || 0), Number(use.used_amount || 0));
    if (used <= 0) return;
    record.remaining = Math.max(0, Number(record.remaining || 0) - used);
  });
  return next;
}

function plannerSequentialInventoryUseLedger(selectedOptions = [], weekStart = plannerActiveWeekStartKey()) {
  const stockState = plannerInitialSequentialStockState(weekStart);
  const byInventoryId = {};
  let inventoryUseUpScore = 0;
  let ingredientTargetScore = 0;
  (selectedOptions || []).forEach(({ dayName, option }) => {
    (option?.inventory_use_up || []).forEach((use) => {
      const record = stockState.by_inventory_id?.[use.inventory_id];
      if (!record || record.unit !== shoppingNormalizeAmountUnit(use.unit) || Number(record.remaining || 0) <= 0) return;
      const used = Math.min(Number(record.remaining || 0), Number(use.used_amount || 0));
      if (used <= 0) return;
      record.remaining = Math.max(0, Number(record.remaining || 0) - used);
      inventoryUseUpScore += plannerInventoryUseWeight(used, use.unit);
      if (record.target) ingredientTargetScore += plannerIngredientTargetUseValue({ ...use, used_amount: used }, record.target);
      const current = byInventoryId[use.inventory_id] || {
        inventory_id: use.inventory_id,
        item_name: use.item_name || record.item_name || "",
        amount: Number(record.amount || 0),
        used_amount: 0,
        remaining_amount: Number(record.amount || 0),
        unit: record.unit,
        target: record.target || null,
        source_type: record.source_type || "",
        uses: [],
      };
      current.used_amount += used;
      current.remaining_amount = record.remaining;
      current.uses.push({ ...use, used_amount: used, day_name: dayName || use.day_name || "" });
      byInventoryId[use.inventory_id] = current;
    });
  });
  return {
    by_inventory_id: byInventoryId,
    inventory_use_up_score: inventoryUseUpScore,
    ingredient_target_score: ingredientTargetScore,
  };
}

function plannerAssumedInventoryUseSummaryForSelectedOptions(selectedOptions = [], weekStart = plannerActiveWeekStartKey()) {
  const ledger = plannerSequentialInventoryUseLedger(selectedOptions, weekStart);
  const items = Object.values(ledger.by_inventory_id || {}).filter((item) => (
    plannerNormalizeInventorySourceType(item.source_type || item.target?.source_type) === "assumed_receipt_use_up"
  ));
  return {
    item_count: items.length,
    labels: items.map((item) => item.item_name || item.inventory_id || "assumed leftover").filter(Boolean).slice(0, 6),
  };
}

function plannerWeeklyInventoryUseUpScore(selectedOptions = []) {
  const key = `${plannerActiveWeekStartKey()}::${plannerInventoryUpdateMarker()}::${plannerSelectedOptionsCacheKey(selectedOptions)}`;
  const cache = plannerWeeklyInventoryUseUpScore.cache || new Map();
  plannerWeeklyInventoryUseUpScore.cache = cache;
  if (cache.has(key)) return cache.get(key);
  const score = plannerSequentialInventoryUseLedger(selectedOptions, plannerActiveWeekStartKey()).inventory_use_up_score;
  cache.set(key, score);
  return score;
}

function plannerWeeklyIngredientTargetScore(selectedOptions = []) {
  const key = `${plannerActiveWeekStartKey()}::${plannerInventoryUpdateMarker()}::${plannerSelectedOptionsCacheKey(selectedOptions)}`;
  const cache = plannerWeeklyIngredientTargetScore.cache || new Map();
  plannerWeeklyIngredientTargetScore.cache = cache;
  if (cache.has(key)) return cache.get(key);
  const targets = plannerIngredientTargetsForWeek(plannerActiveWeekStartKey()).targets || [];
  if (!targets.length) {
    cache.set(key, 0);
    return 0;
  }
  const score = plannerSequentialInventoryUseLedger(selectedOptions, plannerActiveWeekStartKey()).ingredient_target_score;
  cache.set(key, score);
  return score;
}

function plannerShoppingEfficiencyScore(selectedOptions = []) {
  if (!Array.isArray(selectedOptions) || !selectedOptions.length) return 0;
  const key = `${plannerActiveWeekStartKey()}::${plannerInventoryUpdateMarker()}::${plannerSelectedOptionsCacheKey(selectedOptions)}`;
  const cache = plannerShoppingEfficiencyScore.cache || new Map();
  plannerShoppingEfficiencyScore.cache = cache;
  if (cache.has(key)) return cache.get(key);
  const lines = plannerShoppingTripLinesForSelectedOptions(selectedOptions);
  const awkwardPackScore = lines.reduce((sum, line) => {
    if (!line.warning_label) return sum;
    const amount = shoppingPackNeedAmount(line.amount_total, line.amount_unit);
    const plan = shoppingLinePackCoverage(line);
    const left = Math.max(0, Number(plan?.totalQuantity || 0) - amount);
    return sum + 100 + Math.min(100, left / Math.max(1, amount || 1));
  }, 0);
  const score = awkwardPackScore + plannerExpensiveBeefMinceWastePenalty(lines) + plannerPackCleanWasteScore(selectedOptions);
  cache.set(key, score);
  return score;
}

function plannerSelectedOptionsSlotRecords(selectedOptions = []) {
  const template = currentPlannerTemplate();
  const slots = new Map(allPlannerSlots(template).map((slot) => [slot.slot_id, slot]));
  const days = new Map((template?.days || []).map((day) => [day.day, day]));
  const slotRecords = [];
  const recipeIds = new Set();
  selectedOptions.forEach(({ dayName, option }) => {
    const day = days.get(dayName);
    Object.entries(option?.recipe_ids_by_slot || {}).forEach(([slotId, recipeId]) => {
      const slot = slots.get(slotId);
      if (!slot || !recipeId) return;
      const slotState = plannerSlotState(slot);
      recipeIds.add(String(recipeId));
      slotRecords.push({
        slot_id: slot.slot_id,
        day: day?.day || slot.day || dayName || "",
        date: day ? plannerDayDateKey(day) : "",
        time: slot.time || "",
        title: slot.title || slot.role || slot.slot_id,
        meal_category: slotState.meal_category || slot.meal_category || "",
        slot_status: "planner_recipe",
        required: true,
        people: Array.isArray(slotState.people) ? slotState.people : [],
        recipe_id: String(recipeId),
      });
    });
  });
  return { slotRecords, recipeIds: [...recipeIds] };
}

function plannerShoppingTripLinesForSelectedOptions(selectedOptions = []) {
  if (!Array.isArray(selectedOptions) || !selectedOptions.length) return [];
  const key = `${plannerActiveWeekStartKey()}::${plannerInventoryUpdateMarker()}::${plannerSelectedOptionsCacheKey(selectedOptions)}`;
  const cache = plannerShoppingTripLinesForSelectedOptions.cache || new Map();
  plannerShoppingTripLinesForSelectedOptions.cache = cache;
  if (cache.has(key)) return cache.get(key);
  const { slotRecords, recipeIds } = plannerSelectedOptionsSlotRecords(selectedOptions);
  const usageRows = shoppingRecipeUsageRows(slotRecords, recipeIds);
  const baseLines = shoppingApplyInventoryUseUp(
    plannerActiveWeekStartKey(),
    shoppingAggregateLines(plannerActiveWeekStartKey(), usageRows)
  );
  const tripModel = shoppingTripModel(plannerActiveWeekStartKey(), baseLines, true);
  const lines = tripModel.lines || [];
  cache.set(key, lines);
  return lines;
}

function plannerPackFitPreviewReceiptForSelectedOptions(selectedOptions = []) {
  if (!Array.isArray(selectedOptions) || !selectedOptions.length) return null;
  const weekStart = plannerActiveWeekStartKey();
  const key = `${weekStart}::${plannerInventoryUpdateMarker()}::${plannerSelectedOptionsCacheKey(selectedOptions)}`;
  const cache = plannerPackFitPreviewReceiptForSelectedOptions.cache || new Map();
  plannerPackFitPreviewReceiptForSelectedOptions.cache = cache;
  if (cache.has(key)) return cache.get(key);
  const { slotRecords, recipeIds } = plannerSelectedOptionsSlotRecords(selectedOptions);
  const usageRows = shoppingRecipeUsageRows(slotRecords, recipeIds);
  const demandSlots = weekPackFitDemandSlotsForUsageRows(weekStart, usageRows);
  if (!demandSlots.length) {
    cache.set(key, null);
    return null;
  }
  const week = {
    schema_version: "v4.live_planner_pack_fit_input.1",
    week_id: `planner-pack-fit-preview-${weekStart}`,
    week_start: weekStart,
    week_end: plannerDateKey(plannerActiveWeekEndDate()),
    source_calendar_id: "v4_app_planner_pack_fit_preview",
    local_only: true,
    slots: demandSlots,
  };
  const receipt = buildAppWeekPackFitReceipt(week, state.recipeIndex);
  cache.set(key, receipt);
  return receipt;
}

function plannerPackCleanWasteScore(selectedOptions = []) {
  return plannerPackCleanWasteSummary(selectedOptions).score;
}

function plannerPackCleanWasteSummary(selectedOptions = []) {
  const receipt = plannerPackFitPreviewReceiptForSelectedOptions(selectedOptions);
  return plannerPackCleanWasteSummaryFromReceipt(receipt);
}

function plannerPackCleanWasteSummaryFromReceipt(receipt = null) {
  const familyIndex = shoppingSkuFamilyIndex().byId;
  const packChoiceByFamily = new Map((Array.isArray(receipt?.pack_choices) ? receipt.pack_choices : [])
    .map((choice) => [`${choice.family_id || ""}:${shoppingNormalizeAmountUnit(choice.unit || "")}`, choice]));
  const summary = {
    score: 0,
    awkward_leftover_count: 0,
    awkward_leftover_value_gbp: 0,
    warnings: [],
  };
  (Array.isArray(receipt?.leftovers) ? receipt.leftovers : []).forEach((leftover) => {
    const family = familyIndex.get(leftover.family_id);
    const policy = appPackFitPackCleanPolicy(family || {});
    if (!policy.mode) return;
    const key = `${leftover.family_id || ""}:${shoppingNormalizeAmountUnit(leftover.unit || "")}`;
    const choice = packChoiceByFamily.get(key) || {};
    const penalty = appPackFitPackCleanRemainderPenalty(policy, leftover.leftover_amount, choice.pack_total_quantity, choice.amount_after);
    if (penalty <= 0) return;
    const packCost = Number(choice.pack_cost_gbp || 0);
    const packTotal = Number(choice.pack_total_quantity || 0);
    const leftoverValue = packCost > 0 && packTotal > 0
      ? (Number(leftover.leftover_amount || 0) / packTotal) * packCost
      : 0;
    summary.score += penalty;
    summary.awkward_leftover_count += 1;
    summary.awkward_leftover_value_gbp += leftoverValue;
    summary.warnings.push({
      family_id: leftover.family_id,
      family_label: leftover.family_label,
      leftover_amount: appPackFitRoundNumber(leftover.leftover_amount),
      unit: leftover.unit,
      amount_after: appPackFitRoundNumber(choice.amount_after),
      pack_total_quantity: appPackFitRoundNumber(choice.pack_total_quantity),
      reason: policy.reason_label || "Awkward fresh leftover",
      penalty: appPackFitRoundNumber(penalty),
      value_gbp: roundMoney(leftoverValue),
    });
  });
  return {
    ...summary,
    score: appPackFitRoundNumber(summary.score),
    awkward_leftover_value_gbp: roundMoney(summary.awkward_leftover_value_gbp),
  };
}

function plannerExpensiveBeefMinceWasteScore(selectedOptions = []) {
  if (!Array.isArray(selectedOptions) || !selectedOptions.length) return 0;
  return Number(plannerExpensiveBeefMinceWasteSummary(selectedOptions).score || 0);
}

function plannerExpensiveFreshWastePolicy() {
  const policy = plannerOptionsPolicy().expensive_fresh_waste_policy || {};
  return {
    beef_mince_family_id: String(policy.beef_mince_family_id || "ING-V1-BRITISH-LEAN-BEEF-STEAK-MINCE-5-PERCENT-F"),
    beef_mince_pack_size_g: Math.max(1, Number(policy.beef_mince_pack_size_g || 750)),
    max_beef_mince_dinners_per_week: Math.max(0, Number(policy.max_beef_mince_dinners_per_week || 2)),
    block_stranded_beef_mince_pack: policy.block_stranded_beef_mince_pack === true,
  };
}

function plannerExpensiveBeefMinceWasteMetrics(selectedOptions = []) {
  const summary = plannerExpensiveBeefMinceWasteSummary(selectedOptions);
  return {
    expensive_beef_mince_waste_line_count: Number(summary.line_count || 0),
    expensive_beef_mince_waste_amount_g: Math.round(Number(summary.leftover_amount_g || 0) * 10) / 10,
    expensive_beef_mince_waste_cost_gbp: Math.round(Number(summary.leftover_cost_gbp || 0) * 100) / 100,
    expensive_beef_mince_waste_score: Math.round(Number(summary.score || 0) * 10) / 10,
  };
}

function plannerExpensiveBeefMinceWasteSummary(selectedOptions = []) {
  if (!Array.isArray(selectedOptions) || !selectedOptions.length) {
    return { score: 0, line_count: 0, leftover_amount_g: 0, leftover_cost_gbp: 0 };
  }
  const key = `${plannerActiveWeekStartKey()}::${plannerInventoryUpdateMarker()}::${plannerSelectedOptionsCacheKey(selectedOptions)}`;
  const cache = plannerExpensiveBeefMinceWasteSummary.cache || new Map();
  plannerExpensiveBeefMinceWasteSummary.cache = cache;
  if (cache.has(key)) return cache.get(key);
  const summary = plannerExpensiveBeefMinceWasteSummaryFromLines(plannerShoppingTripLinesForSelectedOptions(selectedOptions));
  cache.set(key, summary);
  return summary;
}

function plannerExpensiveBeefMinceWastePenalty(lines = []) {
  return plannerExpensiveBeefMinceWasteSummaryFromLines(lines).score;
}

function plannerExpensiveBeefMinceWasteSummaryFromLines(lines = []) {
  return (lines || []).reduce((summary, line) => {
    if (!plannerLineIsExpensiveBeefMince(line)) return summary;
    if (line.trip_key === "pantry" || line.is_carryover_check || line.is_inventory_use_up) return summary;
    const amount = shoppingPackNeedAmount(line.amount_total, line.amount_unit);
    const plan = shoppingLinePackCoverage(line);
    if (!amount || !plan?.totalQuantity) return summary;
    if (shoppingNormalizeAmountUnit(plan.unit || "") !== shoppingNormalizeAmountUnit(line.amount_unit || "")) return summary;
    const left = Math.max(0, Number(plan.totalQuantity || 0) - amount);
    if (left <= 1) return summary;
    const leftoverCost = Number(plan.totalCost || 0) > 0 && Number(plan.totalQuantity || 0) > 0
      ? (left / Number(plan.totalQuantity || 1)) * Number(plan.totalCost || 0)
      : 0;
    return {
      score: summary.score + Math.min(1500, 150 + (left * 1.8) + (leftoverCost * 120)),
      line_count: summary.line_count + 1,
      leftover_amount_g: summary.leftover_amount_g + (shoppingNormalizeAmountUnit(line.amount_unit || "") === "g" ? left : 0),
      leftover_cost_gbp: summary.leftover_cost_gbp + leftoverCost,
    };
  }, { score: 0, line_count: 0, leftover_amount_g: 0, leftover_cost_gbp: 0 });
}

function plannerLineIsExpensiveBeefMince(line) {
  const familyId = String(line?.family_id || line?.family?.family_id || "").trim();
  if (familyId === plannerExpensiveFreshWastePolicy().beef_mince_family_id) return true;
  const text = [
    line?.item_name,
    line?.sku_code,
    line?.family?.shopping_name,
    line?.family?.display_name,
    Array.isArray(line?.raw_names) ? line.raw_names.join(" ") : "",
  ].filter(Boolean).join(" ").toLowerCase();
  return /\bbeef\b/.test(text) && /\bmince\b/.test(text);
}

function plannerRecipeExpensiveBeefMinceDemand(recipe) {
  const key = recipeKey(recipe);
  const cache = plannerRecipeExpensiveBeefMinceDemand.cache || new Map();
  plannerRecipeExpensiveBeefMinceDemand.cache = cache;
  if (key && cache.has(key)) return cache.get(key);
  const amount = (recipe?.recipe_invoice_lines || []).reduce((sum, line) => {
    if (!plannerRecipeLineIsExpensiveBeefMince(line)) return sum;
    const amountData = line.calculation_amount && typeof line.calculation_amount === "object" ? line.calculation_amount : {};
    const rawAmount = Number(amountData.amount ?? line.calculation_amount ?? line.recipe_uses_amount ?? line.amount ?? 0);
    const rawUnit = shoppingNormalizeAmountUnit(amountData.unit || line.calculation_unit || line.recipe_uses_unit || line.unit || "");
    const normalized = shoppingNormalizeAmountValue(rawAmount, rawUnit || "g");
    return sum + (shoppingNormalizeAmountUnit(normalized.unit || rawUnit || "") === "g" ? Number(normalized.amount || 0) : 0);
  }, 0);
  if (key) cache.set(key, amount);
  return amount;
}

function plannerRecipeLineIsExpensiveBeefMince(line) {
  if (!line || typeof line !== "object") return false;
  const family = shoppingFamilyForSku(line.sku_code || "") || {};
  if (String(family.family_id || "").trim() === plannerExpensiveFreshWastePolicy().beef_mince_family_id) return true;
  const text = [
    line.ingredient,
    line.ingredient_name,
    line.item_name,
    line.sku_code,
    family.shopping_name,
    family.display_name,
  ].filter(Boolean).join(" ").toLowerCase();
  return /\bbeef\b/.test(text) && /\bmince\b/.test(text);
}

function plannerOptionExpensiveBeefMinceDemand(option, recipeById = null) {
  if (!option || typeof option !== "object") return 0;
  const cache = plannerOptionExpensiveBeefMinceDemand.cache || new WeakMap();
  plannerOptionExpensiveBeefMinceDemand.cache = cache;
  if (cache.has(option)) return cache.get(option);
  const demand = Object.entries(plannerOptionRecipeUseCounts(option)).reduce((sum, [recipeId, useCount]) => {
    const recipe = plannerRecipeById(recipeId, recipeById);
    if (!recipe) return sum;
    const blockSize = plannerRecipeBlockSize(recipe);
    const cookingUnits = plannerRecipeTracksBatchContinuity(recipe, blockSize)
      ? Math.max(1, Math.ceil(Number(useCount || 0) / Math.max(1, blockSize)))
      : Number(useCount || 0);
    return sum + (plannerRecipeExpensiveBeefMinceDemand(recipe) * cookingUnits);
  }, 0);
  cache.set(option, demand);
  return demand;
}

function plannerExpensiveBeefMinceDemandBand(amount) {
  const grams = Math.max(0, Number(amount || 0));
  if (grams <= 1) return "beef-0g";
  const rounded = Math.round(grams / 25) * 25;
  const known = [375, 500, 750, 1000, 1125, 1250, 1500, 1750, 2000, 2250];
  const nearest = known.find((value) => Math.abs(value - rounded) <= 12.5);
  return nearest ? `beef-${nearest}g` : "beef-other";
}

function plannerWeeklySequenceOptions(options, activeBatches, weeklyUseCounts, sequentialStockState = null, context = {}, previousDinnerProfiles = []) {
  const activeRecipeIds = new Set((activeBatches || []).map((batch) => batch.recipe_id).filter(Boolean));
  return [...(options || [])]
    .map((option, index) => {
      const dinnerFatigueTransition = plannerOptionDinnerFatigueTransitionScore(option, previousDinnerProfiles, context.recipeById, context);
      return {
        option,
        index,
        continuity: [...activeRecipeIds].reduce((sum, recipeId) => sum + Math.min(1, plannerOptionRecipeUseCount(option, recipeId)), 0),
        sequentialTargetScore: plannerSequentialStockOptionScore(option, sequentialStockState),
        targetScore: Number(option?.ingredient_target_score || 0),
        expensiveBeefMincePackShapeScore: plannerOptionExpensiveBeefMincePackShapeScore(option, context.recipeById),
        adjacentDinnerProteinRepeat: plannerOptionAdjacentDinnerProteinRepeatScore(
          option,
          (previousDinnerProfiles || []).flatMap((profile) => profile.primary_protein ? [profile.primary_protein] : []),
          context.recipeById,
          context
        ),
        dinnerFatigueTransition,
        repeatPressure: plannerOptionRepeatPressure(option, weeklyUseCounts, context.recipeById),
        score: Number(option?.score || 0),
      };
    })
    .sort((a, b) => (
      b.continuity - a.continuity
      || a.dinnerFatigueTransition - b.dinnerFatigueTransition
      || a.adjacentDinnerProteinRepeat - b.adjacentDinnerProteinRepeat
      || b.sequentialTargetScore - a.sequentialTargetScore
      || b.targetScore - a.targetScore
      || a.expensiveBeefMincePackShapeScore - b.expensiveBeefMincePackShapeScore
      || a.repeatPressure - b.repeatPressure
      || a.score - b.score
      || a.index - b.index
    ))
    .map((entry) => entry.option);
}

function plannerOptionExpensiveBeefMincePackShapeScore(option, recipeById = null) {
  const demand = plannerOptionExpensiveBeefMinceDemand(option, recipeById);
  if (demand <= 1) return 0;
  const packSize = plannerExpensiveFreshWastePolicy().beef_mince_pack_size_g;
  const remainder = demand % packSize;
  const waste = Math.min(remainder, packSize - remainder);
  if (waste <= 1) return 0;
  return 25 + waste;
}

function plannerOptionAdjacentDinnerProteinRepeatScore(option, previousDinnerProteinFamilies = [], recipeById = null, context = {}) {
  const previous = new Set(previousDinnerProteinFamilies || []);
  if (!previous.size) return 0;
  return plannerOptionDinnerProteinFamilies(option, recipeById, context)
    .filter((family) => previous.has(family))
    .length;
}

function plannerOptionDinnerProteinFamilies(option, recipeById = null, context = {}) {
  const families = new Set();
  plannerOptionRecipeIds(option).forEach((recipeId) => {
    const recipe = plannerRecipeById(recipeId, recipeById);
    if (!recipe || recipeMealCategory(recipe) !== "dinner") return;
    const family = plannerRecipePrimaryProteinFamily(recipe, context);
    if (family) families.add(family);
  });
  return [...families].sort();
}

const PLANNER_FATIGUE_IGNORED_BASE_ITEMS = new Set([
  "onion",
  "garlic",
  "oil",
  "salt",
  "pepper",
  "spice",
  "herb",
  "stock",
  "flour",
  "cornflour",
  "water",
  "vinegar",
  "sugar",
  "honey",
]);

const PLANNER_FATIGUE_PROFILE_LABELS = {
  "cod-white-fish": "white fish",
  "mash-potato": "mash/potato",
  potato: "potato/mash",
  rice: "rice",
  pasta: "pasta/noodles",
  noodles: "pasta/noodles",
  wrap: "wraps/bread",
  bread: "wraps/bread",
  pastry: "pastry/pie",
  couscous: "couscous",
  "stir-fry": "stir fry",
  "one-pan": "one-pan",
  traybake: "traybake",
  fakeaway: "fakeaway",
  "lemon-herb": "lemon/herb",
  "soy-ginger": "soy/ginger",
};

function plannerOptionDinnerFatigueProfiles(option, recipeById = null, context = {}) {
  return plannerOptionRecipeIds(option).map((recipeId) => {
    const recipe = plannerRecipeById(recipeId, recipeById);
    if (!recipe || recipeMealCategory(recipe) !== "dinner") return null;
    return plannerRecipeFatigueProfile(recipe, context);
  }).filter(Boolean);
}

function plannerOptionDinnerFatigueTransitionScore(option, previousDinnerProfiles = [], recipeById = null, context = {}) {
  const currentProfiles = plannerOptionDinnerFatigueProfiles(option, recipeById, context);
  if (!currentProfiles.length || !previousDinnerProfiles.length) return 0;
  const recent = previousDinnerProfiles.slice(-2);
  return currentProfiles.reduce((sum, profile) => {
    let score = 0;
    const previous = recent[recent.length - 1] || null;
    if (previous) score += plannerFatiguePairPenalty(previous, profile) * 1.8;
    if (recent.length >= 2) {
      if (profile.primary_protein && recent.every((item) => item.primary_protein === profile.primary_protein)) score += 1200;
      if (profile.main_starch && recent.every((item) => item.main_starch === profile.main_starch)) score += 850;
      if (plannerFatigueCommonHero([...recent, profile]).length) score += 700;
    }
    return sum + score;
  }, 0);
}

function plannerNextDinnerFatigueWindow(previousDinnerProfiles = [], option, recipeById = null, context = {}) {
  const currentProfiles = plannerOptionDinnerFatigueProfiles(option, recipeById, context);
  if (!currentProfiles.length) return previousDinnerProfiles.slice(-2);
  return [...previousDinnerProfiles, ...currentProfiles].slice(-2);
}

function plannerRecipeFatigueProfile(recipe, context = {}) {
  const recipeId = recipeKey(recipe);
  const cache = context?.fatigueProfileCache instanceof Map ? context.fatigueProfileCache : null;
  if (cache?.has(recipeId)) return cache.get(recipeId);
  const filters = plannerNormalizeFilterList(recipe?.planner_filters || recipe?.filters || recipe?.tags || []);
  const shoppingRows = Array.isArray(recipe?.shopping_rows) ? recipe.shopping_rows : [];
  const titleText = [recipe?.title, recipe?.short_title, recipeId].filter(Boolean).join(" ").toLowerCase();
  const searchText = plannerRecipeFatigueSearchText(recipe, filters, shoppingRows);
  const profile = {
    exact_recipe: recipeId,
    primary_protein: plannerRecipePrimaryProteinFamily(recipe, context) || plannerFatigueProteinFromText(searchText),
    main_starch: plannerFatigueMainStarch(searchText),
    meal_format: plannerFatigueMealFormat(searchText, filters),
    cuisine_or_sauce: plannerFatigueCuisineOrSauce(searchText, filters, recipe),
    hero_ingredients: plannerFatigueHeroIngredients(recipe, searchText, titleText, shoppingRows),
    ignored_base_items: [...PLANNER_FATIGUE_IGNORED_BASE_ITEMS],
  };
  if (cache) cache.set(recipeId, profile);
  return profile;
}

function plannerRecipeFatigueSearchText(recipe, filters = null, shoppingRows = null) {
  const normalizedFilters = filters || plannerNormalizeFilterList(recipe?.planner_filters || recipe?.filters || recipe?.tags || []);
  const rows = shoppingRows || (Array.isArray(recipe?.shopping_rows) ? recipe.shopping_rows : []);
  return [
    recipe?.title,
    recipe?.short_title,
    recipe?.cuisine,
    normalizedFilters.join(" "),
    rows.map((row) => [
      row?.ingredient_name,
      row?.ingredient,
      row?.item_name,
      row?.product_name,
      row?.shopping_family_label,
      row?.shopping_family_id,
      row?.substitution_group_id,
      row?.recipe_uses,
      row?.sku_code,
    ].filter(Boolean).join(" ")).join(" "),
  ].filter(Boolean).join(" ").toLowerCase();
}

function plannerFatigueProteinFromText(text) {
  return plannerProteinFamilyFromText(text);
}

function plannerFatigueMainStarch(text) {
  const value = String(text || "").toLowerCase();
  const patterns = [
    ["mash-potato", /\b(mash|mashed potato|potato mash)\b/],
    ["potato", /\b(potato|potatoes|wedges|chips|fries|roasties|loaded potatoes)\b/],
    ["rice", /\b(rice|biryani|risotto)\b/],
    ["noodles", /\b(noodle|noodles|ramen)\b/],
    ["pasta", /\b(pasta|spaghetti|penne|fusilli|macaroni|lasagne)\b/],
    ["wrap", /\b(wrap|wraps|tortilla|tortillas|pitta|flatbread)\b/],
    ["bread", /\b(bread|toast|bun|roll|bagel)\b/],
    ["pastry", /\b(pastry|pie|pies)\b/],
    ["couscous", /\bcouscous\b/],
    ["oats", /\b(oats|porridge)\b/],
  ];
  const match = patterns.find(([, pattern]) => pattern.test(value));
  return match ? match[0] : "";
}

function plannerFatigueMealFormat(text, filters = []) {
  const value = String(text || "").toLowerCase();
  const filterSet = new Set(filters || []);
  const filterPriority = ["fakeaway", "pasta", "wrap", "salad", "bowl", "traybake", "one-pan", "comfort"];
  if (/\b(stir[- ]?fry|noodle stir)\b/.test(value)) return "stir-fry";
  if (/\b(pie|pies)\b/.test(value)) return "pie";
  if (/\b(curry|dhal|dal)\b/.test(value)) return "curry";
  if (/\b(skillet|one[- ]?pan)\b/.test(value)) return "one-pan";
  if (/\b(traybake|tray bake|roast tray)\b/.test(value)) return "traybake";
  if (/\b(wrap|wraps|burrito|taco|tacos|fajita)\b/.test(value)) return "wrap";
  if (/\b(pasta|spaghetti|penne|noodle|noodles)\b/.test(value)) return "pasta";
  if (/\b(schnitzel|breaded|fishcake|fish cake)\b/.test(value)) return "breaded-plate";
  if (/\b(salad|slaw)\b/.test(value)) return "salad";
  if (/\b(bowl|bowls|loaded potato)\b/.test(value)) return "bowl";
  return filterPriority.find((filter) => filterSet.has(filter)) || "";
}

function plannerFatigueCuisineOrSauce(text, filters = [], recipe = null) {
  const cuisine = (filters || []).find((filter) => String(filter).startsWith("cuisine:") && filter !== "cuisine:none");
  if (cuisine) return cuisine.replace(/^cuisine:/, "");
  const recipeCuisine = String(recipe?.cuisine || "").trim().toLowerCase();
  if (recipeCuisine && recipeCuisine !== "none") return plannerNormalizeFatigueToken(recipeCuisine);
  const value = String(text || "").toLowerCase();
  const patterns = [
    ["creamy", /\b(creamy|cream|yoghurt sauce|yogurt sauce)\b/],
    ["tomato", /\b(tomato|ragu|ragù|bolognese|marinara)\b/],
    ["lemon-herb", /\b(lemon|mint|herb|oregano|thyme|dill)\b/],
    ["gravy", /\b(gravy|peppercorn)\b/],
    ["spicy", /\b(chipotle|chilli|chili|spicy|cajun|paprika)\b/],
    ["pesto", /\bpesto\b/],
    ["soy-ginger", /\b(soy|ginger|teriyaki|hoisin)\b/],
    ["bbq", /\b(bbq|barbecue)\b/],
  ];
  const match = patterns.find(([, pattern]) => pattern.test(value));
  return match ? match[0] : "";
}

function plannerFatigueHeroIngredients(recipe, searchText, titleText, shoppingRows = []) {
  const heroes = new Set();
  const textToken = plannerFatigueIngredientTokenFromText(titleText);
  if (textToken && !plannerFatigueIngredientIsIgnoredBase(textToken, searchText, titleText, Infinity)) heroes.add(textToken);
  (shoppingRows || []).forEach((row) => {
    const rowText = [
      row?.ingredient_name,
      row?.ingredient,
      row?.item_name,
      row?.product_name,
      row?.shopping_family_label,
      row?.shopping_family_id,
      row?.substitution_group_id,
      row?.recipe_uses,
      row?.sku_code,
    ].filter(Boolean).join(" ").toLowerCase();
    const token = plannerFatigueIngredientTokenFromText(rowText);
    if (!token) return;
    const amount = plannerFatigueAmountFromRow(row);
    if (plannerFatigueIngredientIsIgnoredBase(token, searchText, titleText, amount)) return;
    if (amount >= 80 || titleText.includes(token.replace(/-/g, " ")) || plannerFatigueTokenIsProteinOrStarch(token)) heroes.add(token);
  });
  const primary = plannerRecipePrimaryProteinFamily(recipe);
  const starch = plannerFatigueMainStarch(searchText);
  if (primary) heroes.add(primary);
  if (starch) heroes.add(starch);
  return [...heroes].sort();
}

function plannerFatigueIngredientTokenFromText(text) {
  const value = String(text || "").toLowerCase();
  const patterns = [
    ["green-beans", /\bgreen beans?\b/],
    ["salmon", /\bsalmon\b/],
    ["tuna", /\btuna\b/],
    ["mackerel", /\bmackerel\b/],
    ["cod-white-fish", /\b(cod|hake|pollock|white fish|fish fillets?|fishcake|fish cake)\b/],
    ["prawn", /\b(prawn|shrimp)\b/],
    ["chicken", /\bchicken\b/],
    ["turkey", /\bturkey\b/],
    ["beef", /\b(beef|steak|mince|sirloin|rump)\b/],
    ["pork", /\b(pork|bacon|ham|sausage|sausages|chorizo|pepperoni)\b/],
    ["egg", /\b(egg|eggs|omelette)\b/],
    ["lentil", /\blentils?\b/],
    ["chickpea", /\bchickpeas?\b/],
    ["beans", /\b(beans|bean)\b/],
    ["mash-potato", /\b(mash|mashed potato)\b/],
    ["potato", /\b(potato|potatoes|wedges|chips|fries)\b/],
    ["rice", /\brice\b/],
    ["noodles", /\bnoodles?\b/],
    ["pasta", /\bpasta|spaghetti|penne|fusilli\b/],
    ["wrap", /\b(wrap|wraps|tortilla|flatbread)\b/],
    ["pastry", /\b(pastry|pie|pies)\b/],
    ["couscous", /\bcouscous\b/],
    ["broccoli", /\bbroccoli\b/],
    ["carrot", /\bcarrots?\b/],
    ["celery", /\bcelery\b/],
    ["pepper", /\b(peppers?|capsicum)\b/],
    ["peas", /\bpeas?\b/],
    ["spinach", /\bspinach\b/],
    ["cabbage", /\bcabbage|slaw\b/],
    ["apple", /\bapples?\b/],
    ["avocado", /\bavocado\b/],
    ["feta", /\bfeta\b/],
    ["cheese", /\bcheese|cheddar|mozzarella|parmesan\b/],
    ["yoghurt", /\byoghurt|yogurt\b/],
    ["tomato", /\btomatoes?|passata\b/],
    ["mushroom", /\bmushrooms?\b/],
    ["sweetcorn", /\b(corn|sweetcorn)\b/],
    ["onion", /\bonions?\b/],
    ["garlic", /\bgarlic\b/],
    ["oil", /\boil\b/],
    ["salt", /\bsalt\b/],
    ["pepper-seasoning", /\bblack pepper|peppercorns?\b/],
    ["spice", /\b(paprika|cumin|turmeric|cinnamon|seasoning|spice|chilli flakes)\b/],
    ["herb", /\b(oregano|thyme|dill|mint|parsley|coriander|herbs?)\b/],
    ["stock", /\bstock\b/],
    ["flour", /\bflour\b/],
    ["cornflour", /\bcornflour\b/],
  ];
  const match = patterns.find(([, pattern]) => pattern.test(value));
  return match ? match[0] : "";
}

function plannerFatigueAmountFromRow(row) {
  const direct = Number(row?.recipe_uses_amount || row?.amount_g || row?.amount_ml || row?.recipe_amount || 0);
  if (Number.isFinite(direct) && direct > 0) return direct;
  const text = String(row?.recipe_uses || row?.recipe_amount || "").toLowerCase();
  const match = text.match(/(\d+(?:\.\d+)?)\s*(kg|g|ml|l)\b/);
  if (!match) return 0;
  const value = Number(match[1] || 0);
  const unit = match[2];
  if (!Number.isFinite(value)) return 0;
  if (unit === "kg" || unit === "l") return value * 1000;
  return value;
}

function plannerFatigueIngredientIsIgnoredBase(token, searchText = "", titleText = "", amount = 0) {
  const normalized = plannerNormalizeFatigueToken(token);
  if (!normalized) return true;
  const title = String(titleText || "").toLowerCase();
  if (normalized === "pepper") return false;
  if (title.includes(normalized.replace(/-/g, " "))) return false;
  if (["carrot", "celery"].includes(normalized) && /\b(mirepoix|sofrito|ragu|ragù|bolognese|chilli|chili|stew|soup|sauce)\b/.test(String(searchText || "").toLowerCase())) {
    return Number(amount || 0) < 260;
  }
  if (normalized === "pepper-seasoning") return true;
  return PLANNER_FATIGUE_IGNORED_BASE_ITEMS.has(normalized);
}

function plannerFatigueTokenIsProteinOrStarch(token) {
  return /^(salmon|tuna|mackerel|cod-white-fish|prawn|chicken|turkey|beef|pork|egg|lentil|chickpea|beans|mash-potato|potato|rice|noodles|pasta|wrap|bread|pastry|couscous|oats)$/.test(String(token || ""));
}

function plannerNormalizeFatigueToken(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/^protein[:_-]+/, "")
    .replace(/^cuisine[:_-]+/, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function plannerFatiguePairPenalty(left, right) {
  if (!left || !right) return 0;
  let penalty = 0;
  if (left.exact_recipe && left.exact_recipe === right.exact_recipe) penalty += 75;
  if (left.primary_protein && left.primary_protein === right.primary_protein) penalty += 24;
  if (left.main_starch && left.main_starch === right.main_starch) penalty += 16;
  if (left.meal_format && left.meal_format === right.meal_format) penalty += 10;
  if (left.cuisine_or_sauce && left.cuisine_or_sauce === right.cuisine_or_sauce) penalty += 8;
  const heroOverlap = (left.hero_ingredients || []).filter((item) => (right.hero_ingredients || []).includes(item));
  penalty += Math.min(18, heroOverlap.length * 6);
  return penalty;
}

function plannerFatigueCommonHero(profiles = []) {
  const heroSets = (profiles || [])
    .map((profile) => new Set((profile?.hero_ingredients || []).filter((item) => item && !PLANNER_FATIGUE_IGNORED_BASE_ITEMS.has(item))))
    .filter((set) => set.size);
  if (heroSets.length < profiles.length || !heroSets.length) return [];
  return [...heroSets[0]].filter((item) => heroSets.every((set) => set.has(item)));
}

function plannerFatigueValueLabel(value) {
  const key = String(value || "");
  return PLANNER_FATIGUE_PROFILE_LABELS[key] || key.replace(/-/g, " ");
}

function plannerDinnerFatigueSummaryForSelectedOptions(selectedOptions = [], recipeById = null) {
  const records = plannerDinnerFatigueRecordsForSelectedOptions(selectedOptions, recipeById);
  let penalty = 0;
  const warnings = [];
  const hardWarnings = [];
  for (let index = 1; index < records.length; index += 1) {
    const left = records[index - 1];
    const right = records[index];
    const pairPenalty = plannerFatiguePairPenalty(left.profile, right.profile);
    penalty += pairPenalty;
    if (left.profile.primary_protein && left.profile.primary_protein === right.profile.primary_protein) {
      warnings.push(`Back-to-back ${plannerFatigueValueLabel(left.profile.primary_protein)} dinners reduce variety.`);
    }
    if (left.profile.main_starch && left.profile.main_starch === right.profile.main_starch) {
      warnings.push(`${plannerFatigueValueLabel(left.profile.main_starch)} appears on nearby dinners.`);
    }
  }
  for (let index = 2; index < records.length; index += 1) {
    const window = records.slice(index - 2, index + 1);
    const profiles = window.map((record) => record.profile);
    const days = window.map((record) => record.day_name).filter(Boolean).join("-");
    const protein = profiles[0].primary_protein;
    const starch = profiles[0].main_starch;
    if (protein && profiles.every((profile) => profile.primary_protein === protein)) {
      hardWarnings.push({
        type: "protein_streak",
        key: protein,
        message: `Too much ${plannerFatigueValueLabel(protein)} ${days}.`,
      });
      penalty += 90;
    }
    if (starch && profiles.every((profile) => profile.main_starch === starch)) {
      hardWarnings.push({
        type: "starch_streak",
        key: starch,
        message: `${plannerFatigueValueLabel(starch)} appears 3 dinners close together.`,
      });
      penalty += 70;
    }
    plannerFatigueCommonHero(profiles).forEach((hero) => {
      if (hero === protein || hero === starch) return;
      hardWarnings.push({
        type: "hero_streak",
        key: hero,
        message: `${plannerFatigueValueLabel(hero)} appears too often this week.`,
      });
      penalty += 55;
    });
  }
  const uniqueHardWarnings = plannerUniqueFatigueWarnings(hardWarnings);
  return {
    records,
    penalty,
    hard_warning_count: uniqueHardWarnings.length,
    warning_count: [...new Set(warnings)].length + uniqueHardWarnings.length,
    hard_warnings: uniqueHardWarnings,
    warnings: [...new Set([...uniqueHardWarnings.map((item) => item.message), ...warnings])],
  };
}

function plannerDinnerFatigueRecordsForSelectedOptions(selectedOptions = [], recipeById = null) {
  const template = currentPlannerTemplate();
  const dayOrder = new Map((template?.days || []).map((day, index) => [day.day, index]));
  const slots = new Map(allPlannerSlots(template).map((slot) => [slot.slot_id, slot]));
  const records = [];
  (selectedOptions || []).forEach(({ dayName, option }) => {
    Object.entries(option?.recipe_ids_by_slot || {}).forEach(([slotId, recipeId]) => {
      const slot = slots.get(slotId);
      const recipe = plannerRecipeById(recipeId, recipeById);
      if (!slot || !recipe) return;
      const slotState = plannerSlotState(slot);
      const category = plannerValidMealCategory(slotState.meal_category || slot?.meal_category || recipeMealCategory(recipe)) || recipeMealCategory(recipe);
      if (category !== "dinner") return;
      records.push({
        day_name: dayName || slot.day || "",
        day_index: dayOrder.has(dayName) ? dayOrder.get(dayName) : 999,
        slot_id: slotId,
        recipe_id: String(recipeId),
        profile: plannerRecipeFatigueProfile(recipe, { fatigueProfileCache: null, proteinFamilyCache: null }),
      });
    });
  });
  return records.sort((a, b) => a.day_index - b.day_index || String(a.slot_id).localeCompare(String(b.slot_id)));
}

function plannerUniqueFatigueWarnings(warnings = []) {
  const seen = new Set();
  return (warnings || []).filter((warning) => {
    const key = `${warning.type}:${warning.key}:${warning.message}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function plannerSelectedOptionsUrgentUseUpCount(selectedOptions = []) {
  return (selectedOptions || []).reduce((sum, { option }) => {
    const useUpScore = Number(option?.inventory_use_up_score || 0) + Number(option?.ingredient_target_score || 0);
    return sum + (useUpScore > 0 ? 1 : 0);
  }, 0);
}

function plannerRecipePrimaryProteinFamily(recipe, context = {}) {
  const recipeId = recipeKey(recipe);
  const cache = context?.proteinFamilyCache instanceof Map ? context.proteinFamilyCache : null;
  if (cache?.has(recipeId)) return cache.get(recipeId);
  const explicit = plannerNormalizeProteinFamily(
    recipe?.primary_protein_family ||
    recipe?.protein_family ||
    recipe?.primary_protein ||
    recipe?.protein ||
    recipe?.main_protein
  );
  const shoppingText = plannerRecipeShoppingProteinSearchText(recipe);
  const family = explicit || plannerProteinFamilyFromText(shoppingText) || plannerProteinFamilyFromText(recipePlannerSearchText(recipe));
  if (cache) cache.set(recipeId, family);
  return family;
}

function plannerRecipeShoppingProteinSearchText(recipe) {
  return (Array.isArray(recipe?.shopping_rows) ? recipe.shopping_rows : [])
    .map((row) => [
      row?.shopping_family_id,
      row?.shopping_family_label,
      row?.substitution_group_id,
      row?.ingredient_id,
      row?.ingredient_name,
      row?.ingredient,
      row?.item_name,
      row?.product_name,
      row?.sku_code,
      row?.recipe_uses,
      row?.recipe_amount,
    ].filter(Boolean).join(" "))
    .join(" ")
    .toLowerCase();
}

function plannerNormalizeProteinFamily(value) {
  const family = String(value || "")
    .trim()
    .toLowerCase()
    .replace(/^protein[:_-]+/, "")
    .replace(/^ing[:_-]+/, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  if (!family || family === "fish" || family === "oily-fish" || family === "protein-led") return "";
  if (family === "steak" || family === "mince") return "beef";
  if (family === "shrimp") return "prawn";
  return family;
}

function plannerProteinFamilyFromText(text) {
  const value = String(text || "").toLowerCase();
  const patterns = [
    ["salmon", /\b(?:ing[-_ ]*)?salmon\b/],
    ["tuna", /\b(?:ing[-_ ]*)?tuna\b/],
    ["mackerel", /\bmackerel\b/],
    ["sardine", /\bsardines?\b/],
    ["cod-white-fish", /\b(cod|hake|pollock|white fish|fish fillets?|fish goujons?)\b/],
    ["prawn", /\b(prawn|shrimp)\b/],
    ["chicken", /\bchicken\b/],
    ["turkey", /\bturkey\b/],
    ["lamb", /\blamb\b/],
    ["pork", /\b(pork|bacon|ham|sausage|sausages|chorizo|pepperoni)\b/],
    ["beef", /\b(beef|steak|mince|sirloin|rump)\b/],
    ["egg", /\b(egg|eggs|omelette)\b/],
  ];
  const match = patterns.find(([, pattern]) => pattern.test(value));
  return match ? match[0] : "";
}

function plannerOptionRepeatPressure(option, weeklyUseCounts, recipeById = null) {
  return Object.entries(plannerOptionRecipeUseCounts(option))
    .reduce((sum, [recipeId, optionUseCount]) => {
      const recipe = plannerRecipeById(recipeId, recipeById);
      const cap = Math.max(1, plannerRecipeWeeklyUseCap(recipe));
      const nextUseCount = Number(weeklyUseCounts?.[recipeId] || 0) + Number(optionUseCount || 0);
      return sum + (nextUseCount / cap) + (plannerRecipeDraftFatiguePenalty(recipeId) / 450);
    }, 0);
}

function plannerAdvanceWeeklySequenceState(option, activeBatches, weeklyUseCounts, context = {}) {
  const optionUseCounts = plannerOptionRecipeUseCounts(option);
  const nextActiveBatches = (activeBatches || [])
    .map((batch) => ({
      ...batch,
      remaining: Number(batch.remaining || 0) - Number(optionUseCounts[batch.recipe_id] || 0),
      missed: Number(optionUseCounts[batch.recipe_id] || 0) > 0 ? 0 : Number(batch.missed || 0) + 1,
    }))
    .filter((batch) => batch.remaining > 0 && batch.missed <= 0);
  const nextWeeklyUseCounts = { ...(weeklyUseCounts || {}) };
  Object.entries(optionUseCounts).forEach(([recipeId, optionUseCount]) => {
    const previousUseCount = Number(nextWeeklyUseCounts[recipeId] || 0);
    nextWeeklyUseCounts[recipeId] = previousUseCount + Number(optionUseCount || 0);
    if (previousUseCount !== 0) return;
    if (nextActiveBatches.some((batch) => batch.recipe_id === recipeId)) return;
    const recipe = plannerRecipeById(recipeId, context.recipeById);
    const useCount = plannerRecipeBlockSize(recipe);
    const remaining = useCount - Number(optionUseCount || 0);
    if (plannerRecipeTracksBatchContinuity(recipe, useCount)) {
      const carryoverPlan = plannerLateStartBatchCarryoverPlan(option, recipeId, context.dayIndex, context.days, context.dayOptions, useCount, context.recipeById);
      if (remaining > 0) nextActiveBatches.push({
        recipe_id: recipeId,
        label: recipe?.short_title || recipe?.title || recipeId,
        remaining,
        missed: 0,
        batch_size: useCount,
        carryover_allowed: carryoverPlan.allowed,
        carryover_servings: carryoverPlan.carryover_servings,
        carryover_reason: carryoverPlan.reason,
      });
    }
  });
  return {
    activeBatches: nextActiveBatches,
    weeklyUseCounts: nextWeeklyUseCounts,
  };
}

function plannerLateStartBatchCarryoverPlan(option, recipeId, dayIndex, days, dayOptions, batchUseCount = 1, recipeById = null) {
  const size = Math.max(1, Number(batchUseCount || 1));
  const empty = { allowed: false, carryover_servings: 0, reason: "" };
  if (size <= 1 || !recipeId || !option) return empty;
  if (!plannerIsLateStartActiveWeek()) return empty;
  const recipe = plannerRecipeById(recipeId, recipeById);
  if (recipeMealCategory(recipe) !== "lunch") return empty;
  if (!plannerOptionRecipeUsesLukeLunchTrack(option, recipeId)) return empty;
  const optionUseCount = plannerOptionRecipeUseCount(option, recipeId);
  if (optionUseCount <= 0) return empty;
  const remainingCapacity = plannerRemainingRecipeCapacity(recipeId, dayIndex, days, dayOptions);
  const carryoverServings = size - remainingCapacity;
  if (remainingCapacity < optionUseCount) return empty;
  if (carryoverServings <= 0 || carryoverServings >= size) return empty;
  return {
    allowed: true,
    carryover_servings: carryoverServings,
    reason: "late_start_current_week_luke_lunch_batch_carryover",
  };
}

function plannerIsLateStartActiveWeek() {
  const activeStart = plannerActiveWeekStartKey();
  const currentStart = plannerCurrentWeekStartKey();
  const today = plannerTodayKey();
  return activeStart === currentStart && today > activeStart;
}

function plannerOptionRecipeUsesLukeLunchTrack(option, recipeId) {
  return Object.entries(option?.recipe_ids_by_slot || {}).some(([slotId, optionRecipeId]) => {
    if (optionRecipeId !== recipeId) return false;
    const slot = findPlannerSlot(slotId);
    if (!slot) return false;
    const track = plannerSlotMealTrack(slot, plannerSlotState(slot));
    return track === "luke_lunch_1" || track === "luke_lunch_2";
  });
}

function plannerApplyBatchContinuityToWeekOptions(dayOptions, template) {
  const sequenceResult = plannerFindWeeklyOptionSequence(dayOptions, template);
  const preferredSequence = sequenceResult.selected_option_by_day || {};
  const preferredDayNames = new Set(Object.keys(preferredSequence || {}));
  const selectableDayNames = (template?.days || [])
    .filter((day) => dayOptions?.[day.day]?.options?.length)
    .map((day) => day.day);
  const hasPreferredSequence = selectableDayNames.length > 0
    && selectableDayNames.every((dayName) => preferredDayNames.has(dayName));
  Object.entries(preferredSequence || {}).forEach(([dayName, optionId]) => {
    if (dayOptions[dayName]?.options?.some((option) => option.option_id === optionId)) {
      dayOptions[dayName].selected_option_id = optionId;
    }
  });
  const activeBatches = [];
  const blockedBatchRecipeIds = new Set();
  const weeklyUseCounts = {};
  const warnings = [];
  const days = template?.days || [];
  const weeklyContext = {
    recipeById: new Map(recipes().map((recipe) => [recipeKey(recipe), recipe])),
    issueCache: new Map(),
    remainingCapacityCache: new Map(),
    batchCompletionCache: new Map(),
    batchCompletionLookaheadCache: new Map(),
    remainingExpensiveBeefPotentialCache: new Map(),
  };
  days.forEach((day, dayIndex) => {
    const result = dayOptions[day.day];
    if (!result?.options?.length) {
      if (activeBatches.length && plannerActiveBatchesResolved(activeBatches)) {
        plannerRecordBatchCarryoverWarnings(result, activeBatches, warnings, day.day);
        activeBatches.splice(0, activeBatches.length);
        return;
      }
      activeBatches.forEach((batch) => {
        const warning = plannerBatchContinuityWarning(batch);
        plannerAddDayBatchWarning(result, warning, batch);
        warnings.push(`${day.day}: ${warning}`);
        blockedBatchRecipeIds.add(batch.recipe_id);
      });
      activeBatches.splice(0, activeBatches.length);
      return;
    }
    const optionChecks = result.options.map((option) => ({
      option,
      issues: plannerWeeklyOptionIssues(option, dayIndex, days, dayOptions, activeBatches, blockedBatchRecipeIds, weeklyUseCounts, {}, weeklyContext),
    }));
    if (hasPreferredSequence && !preferredDayNames.has(day.day)) {
      activeBatches.forEach((batch) => {
        const batchWarning = plannerBatchContinuityWarning(batch);
        plannerAddDayBatchWarning(result, batchWarning, batch);
        blockedBatchRecipeIds.add(batch.recipe_id);
      });
      activeBatches.splice(0, activeBatches.length);
      const warning = plannerMarkWeeklyRuleGap(result, optionChecks.map((item) => ({
        ...item,
        issues: [...new Set([...(item.issues || []), "batch_block_sequence"])],
      })), blockedBatchRecipeIds);
      if (warning) warnings.push(`${day.day}: ${warning}`);
      return;
    }
    const eligibleOptions = optionChecks.filter((item) => !item.issues.length).map((item) => item.option);
    if (!eligibleOptions.length) {
      activeBatches.forEach((batch) => {
        const batchWarning = plannerBatchContinuityWarning(batch);
        plannerAddDayBatchWarning(result, batchWarning, batch);
        blockedBatchRecipeIds.add(batch.recipe_id);
      });
      activeBatches.splice(0, activeBatches.length);
      const warning = plannerMarkWeeklyRuleGap(result, optionChecks, blockedBatchRecipeIds);
      if (warning) warnings.push(`${day.day}: ${warning}`);
      return;
    }
    result.options = eligibleOptions;
    result.stored_option_count = eligibleOptions.length;
    const preferredOption = eligibleOptions.find((item) => item.option_id === result.selected_option_id);
    const option = preferredOption || plannerBestOptionForActiveBatches(eligibleOptions, activeBatches) || eligibleOptions[0];
    result.selected_option_id = option.option_id || result.selected_option_id;
    const selectedRecipeUseCounts = plannerOptionRecipeUseCounts(option);
    activeBatches.forEach((batch) => {
      const optionUseCount = Number(selectedRecipeUseCounts[batch.recipe_id] || 0);
      if (optionUseCount > 0) {
        batch.remaining -= optionUseCount;
        batch.missed = 0;
      } else {
        batch.missed += 1;
        const warning = plannerBatchContinuityWarning(batch);
        plannerAddDayBatchWarning(result, warning, batch);
        warnings.push(`${day.day}: ${warning}`);
        blockedBatchRecipeIds.add(batch.recipe_id);
      }
    });
    for (let index = activeBatches.length - 1; index >= 0; index -= 1) {
      if (activeBatches[index].remaining <= 0 || activeBatches[index].missed > 0) activeBatches.splice(index, 1);
    }
    Object.entries(selectedRecipeUseCounts).forEach(([recipeId, optionUseCount]) => {
      const previousUseCount = Number(weeklyUseCounts[recipeId] || 0);
      weeklyUseCounts[recipeId] = previousUseCount + Number(optionUseCount || 0);
      if (blockedBatchRecipeIds.has(recipeId)) return;
      if (activeBatches.some((batch) => batch.recipe_id === recipeId)) return;
      if (previousUseCount !== 0) return;
      const recipe = plannerRecipeById(recipeId, weeklyContext.recipeById);
      const useCount = plannerRecipeBlockSize(recipe);
      if (plannerRecipeTracksBatchContinuity(recipe, useCount)) {
        const carryoverPlan = plannerLateStartBatchCarryoverPlan(option, recipeId, dayIndex, days, dayOptions, useCount, weeklyContext.recipeById);
        const remaining = useCount - Number(optionUseCount || 0);
        if (remaining > 0) activeBatches.push({
          recipe_id: recipeId,
          label: recipe?.short_title || recipe?.title || recipeId,
          remaining,
          missed: 0,
          batch_size: useCount,
          carryover_allowed: carryoverPlan.allowed,
          carryover_servings: carryoverPlan.carryover_servings,
          carryover_reason: carryoverPlan.reason,
        });
      }
    });
  });
  if (activeBatches.length && plannerActiveBatchesResolved(activeBatches)) {
    const lastDayName = [...days].reverse().find((day) => dayOptions?.[day.day]?.selected_option_id)?.day || days.at(-1)?.day || "";
    plannerRecordBatchCarryoverWarnings(dayOptions?.[lastDayName], activeBatches, warnings, lastDayName);
    activeBatches.splice(0, activeBatches.length);
  }
  return {
    warnings,
    sequence_result: sequenceResult,
  };
}

function plannerWeeklyOptionIssues(option, dayIndex, days, dayOptions, activeBatches, blockedBatchRecipeIds, weeklyUseCounts, settings = {}, context = {}) {
  const cache = context.issueCache instanceof Map ? context.issueCache : null;
  const optionKey = option?.option_id || plannerDayOptionStorageKey(option);
  const cacheKey = cache && optionKey
    ? `${dayIndex}::${optionKey}::${plannerWeeklyStateSignature(activeBatches, weeklyUseCounts, blockedBatchRecipeIds, settings)}`
    : "";
  if (cacheKey && cache.has(cacheKey)) return cache.get(cacheKey);
  const issues = [];
  const recipeIds = plannerOptionRecipeIds(option);
  const optionUseCounts = plannerOptionRecipeUseCounts(option);
  const nextWeeklyUseCountsForPackWaste = plannerWeeklyUseCountsAfterOption(weeklyUseCounts, optionUseCounts);
  const nextBeefDemand = plannerWeeklyExpensiveBeefMinceDemandFromUseCounts(nextWeeklyUseCountsForPackWaste, context.recipeById);
  if (plannerExpensiveFreshWastePolicy().block_stranded_beef_mince_pack && plannerExpensiveBeefMinceDemandWouldStrandPack(nextBeefDemand, dayIndex, days, dayOptions, context)) {
    issues.push("expensive_beef_mince_pack_waste");
  }
  const nextBeefDinnerCount = plannerWeeklyExpensiveBeefMinceDinnerCountFromUseCounts(weeklyUseCounts, context.recipeById)
    + plannerOptionExpensiveBeefMinceDinnerCount(option, context.recipeById);
  if (nextBeefDinnerCount > plannerExpensiveFreshWastePolicy().max_beef_mince_dinners_per_week) issues.push("expensive_beef_mince_dinner_fatigue");
  if (blockedBatchRecipeIds?.size && recipeIds.some((recipeId) => blockedBatchRecipeIds.has(recipeId))) issues.push("blocked_batch");
  activeBatches.forEach((batch) => {
    if (Number(optionUseCounts[batch.recipe_id] || 0) <= 0) issues.push("batch_continuity");
  });
  Object.entries(optionUseCounts).forEach(([recipeId, optionUseCount]) => {
    const recipe = plannerRecipeById(recipeId, context.recipeById);
    const previousUseCount = Number(weeklyUseCounts?.[recipeId] || 0);
    const nextUseCount = previousUseCount + Number(optionUseCount || 0);
    const maxUses = plannerRecipeWeeklyUseCap(recipe);
    if (nextUseCount > maxUses) issues.push("weekly_repeat_cap");
    const batchUseCount = plannerRecipeBlockSize(recipe);
    const alreadyActive = activeBatches.some((batch) => batch.recipe_id === recipeId);
    if (!alreadyActive && previousUseCount === 0 && plannerRecipeTracksBatchContinuity(recipe, batchUseCount)) {
      const remainingCapacity = plannerRemainingRecipeCapacity(recipeId, dayIndex, days, dayOptions, context);
      const carryoverPlan = plannerLateStartBatchCarryoverPlan(option, recipeId, dayIndex, days, dayOptions, batchUseCount, context.recipeById);
      if (remainingCapacity < batchUseCount) {
        if (!carryoverPlan.allowed) issues.push("incomplete_batch_start");
      } else if (!settings.skipBatchStartLookahead && !plannerCanCompleteStartedBatch(option, recipeId, dayIndex, days, dayOptions, activeBatches, weeklyUseCounts, context)) {
        issues.push("incomplete_batch_start");
        issues.push("batch_block_sequence");
      }
    }
  });
  const uniqueIssues = [...new Set(issues)];
  if (cacheKey) cache.set(cacheKey, uniqueIssues);
  return uniqueIssues;
}

function plannerWeeklyUseCountsAfterOption(weeklyUseCounts = {}, optionUseCounts = {}) {
  const next = { ...(weeklyUseCounts || {}) };
  Object.entries(optionUseCounts || {}).forEach(([recipeId, optionUseCount]) => {
    next[recipeId] = Number(next[recipeId] || 0) + Number(optionUseCount || 0);
  });
  return next;
}

function plannerWeeklyExpensiveBeefMinceDemandFromUseCounts(weeklyUseCounts = {}, recipeById = null) {
  return Object.entries(weeklyUseCounts || {}).reduce((sum, [recipeId, useCount]) => {
    const recipe = plannerRecipeById(recipeId, recipeById);
    if (!recipe) return sum;
    const blockSize = plannerRecipeBlockSize(recipe);
    const cookingUnits = plannerRecipeTracksBatchContinuity(recipe, blockSize)
      ? Math.max(0, Math.ceil(Number(useCount || 0) / Math.max(1, blockSize)))
      : Number(useCount || 0);
    return sum + (plannerRecipeExpensiveBeefMinceDemand(recipe) * cookingUnits);
  }, 0);
}

function plannerWeeklyExpensiveBeefMinceDinnerCountFromUseCounts(weeklyUseCounts = {}, recipeById = null) {
  return Object.entries(weeklyUseCounts || {}).reduce((sum, [recipeId, useCount]) => {
    const recipe = plannerRecipeById(recipeId, recipeById);
    if (!recipe || recipeMealCategory(recipe) !== "dinner" || plannerRecipeExpensiveBeefMinceDemand(recipe) <= 0) return sum;
    return sum + Number(useCount || 0);
  }, 0);
}

function plannerOptionExpensiveBeefMinceDinnerCount(option, recipeById = null) {
  return Object.entries(plannerOptionRecipeUseCounts(option)).reduce((sum, [recipeId, useCount]) => {
    const recipe = plannerRecipeById(recipeId, recipeById);
    if (!recipe || recipeMealCategory(recipe) !== "dinner" || plannerRecipeExpensiveBeefMinceDemand(recipe) <= 0) return sum;
    return sum + Number(useCount || 0);
  }, 0);
}

function plannerExpensiveBeefMinceDemandWouldStrandPack(amount, dayIndex, days, dayOptions, context = {}) {
  const grams = Math.max(0, Number(amount || 0));
  if (grams <= 1) return false;
  const packSize = plannerExpensiveFreshWastePolicy().beef_mince_pack_size_g;
  const remainder = grams % packSize;
  if (remainder <= 1 || packSize - remainder <= 1) return false;
  const neededToClean = packSize - remainder;
  const remainingPotential = plannerRemainingExpensiveBeefMinceDemandPotential(dayIndex + 1, days, dayOptions, context);
  return remainingPotential + 1 < neededToClean;
}

function plannerRemainingExpensiveBeefMinceDemandPotential(startIndex, days, dayOptions, context = {}) {
  const cache = context.remainingExpensiveBeefPotentialCache instanceof Map ? context.remainingExpensiveBeefPotentialCache : null;
  const cacheKey = cache ? String(Math.max(0, Number(startIndex || 0))) : "";
  if (cacheKey && cache.has(cacheKey)) return cache.get(cacheKey);
  let total = 0;
  for (let index = Math.max(0, Number(startIndex || 0)); index < (days || []).length; index += 1) {
    const result = dayOptions?.[days[index]?.day];
    const maxForDay = (result?.options || []).reduce((max, option) => (
      Math.max(max, plannerOptionExpensiveBeefMinceDemand(option, context.recipeById))
    ), 0);
    total += maxForDay;
  }
  if (cacheKey) cache.set(cacheKey, total);
  return total;
}

function plannerCanCompleteStartedBatch(option, recipeId, dayIndex, days, dayOptions, activeBatches, weeklyUseCounts, context = {}) {
  const cache = context.batchCompletionCache instanceof Map ? context.batchCompletionCache : null;
  const optionKey = option?.option_id || plannerDayOptionStorageKey(option);
  const cacheKey = cache && optionKey
    ? `${recipeId}::${dayIndex}::${optionKey}::${plannerWeeklyStateSignature(activeBatches, weeklyUseCounts, null, {})}`
    : "";
  if (cacheKey && cache.has(cacheKey)) return cache.get(cacheKey);
  const recipe = plannerRecipeById(recipeId, context.recipeById);
  const batchUseCount = plannerRecipeBlockSize(recipe);
  if (!plannerRecipeTracksBatchContinuity(recipe, batchUseCount)) {
    if (cacheKey) cache.set(cacheKey, true);
    return true;
  }
  let state = plannerAdvanceWeeklySequenceState(option, activeBatches, weeklyUseCounts, { dayIndex, days, dayOptions, recipeById: context.recipeById });
  if (!state.activeBatches.some((batch) => batch.recipe_id === recipeId)) {
    if (cacheKey) cache.set(cacheKey, true);
    return true;
  }
  const complete = plannerCanResolveBatchLookaheadState({
    recipeId,
    startIndex: dayIndex + 1,
    days,
    dayOptions,
    activeBatches: state.activeBatches,
    weeklyUseCounts: state.weeklyUseCounts,
    context,
  });
  if (cacheKey) cache.set(cacheKey, complete);
  return complete;
}

function plannerCanResolveBatchLookaheadState({ recipeId, startIndex, days, dayOptions, activeBatches, weeklyUseCounts, context = {}, depth = 0 }) {
  const blockingBatches = plannerBlockingActiveBatches(activeBatches);
  if (!blockingBatches.some((batch) => batch.recipe_id === recipeId)) return true;
  if (startIndex >= (days || []).length) return false;
  const maxDepth = Math.max(1, Math.min(5, Number(plannerOptionsPolicy().max_batch_completion_lookahead_depth || 4)));
  if (depth > maxDepth) return false;
  const cache = context.batchCompletionLookaheadCache instanceof Map ? context.batchCompletionLookaheadCache : null;
  const activeIds = blockingBatches.map((batch) => batch.recipe_id).filter(Boolean).sort();
  const cacheKey = cache
    ? `${recipeId}::${startIndex}::${plannerWeeklyStateSignature(activeBatches, weeklyUseCounts, null, { skipBatchStartLookahead: true })}`
    : "";
  if (cacheKey && cache.has(cacheKey)) return cache.get(cacheKey);
  const day = days[startIndex];
  const result = dayOptions?.[day?.day];
  if (!result?.options?.length) {
    if (cacheKey) cache.set(cacheKey, false);
    return false;
  }
  const branchLimit = Math.max(8, Number(plannerOptionsPolicy().max_batch_completion_lookahead_options || 32));
  const candidates = plannerBatchLookaheadCandidates(result.options || [], activeIds, weeklyUseCounts, context, branchLimit);
  for (const candidate of candidates) {
    const issues = plannerWeeklyOptionIssues(candidate, startIndex, days, dayOptions, activeBatches, new Set(), weeklyUseCounts, {
      skipBatchStartLookahead: true,
    }, context);
    if (issues.length) continue;
    const next = plannerAdvanceWeeklySequenceState(candidate, activeBatches, weeklyUseCounts, {
      dayIndex: startIndex,
      days,
      dayOptions,
      recipeById: context.recipeById,
    });
    if (plannerCanResolveBatchLookaheadState({
      recipeId,
      startIndex: startIndex + 1,
      days,
      dayOptions,
      activeBatches: next.activeBatches,
      weeklyUseCounts: next.weeklyUseCounts,
      context,
      depth: depth + 1,
    })) {
      if (cacheKey) cache.set(cacheKey, true);
      return true;
    }
  }
  if (cacheKey) cache.set(cacheKey, false);
  return false;
}

function plannerBatchLookaheadCandidates(options = [], activeIds = [], weeklyUseCounts = {}, context = {}, limit = 32) {
  const max = Math.max(1, Number(limit || 32));
  const activeIdSet = new Set(activeIds || []);
  const ranked = [...(options || [])]
    .filter((candidate) => (activeIds || []).every((activeRecipeId) => plannerOptionRecipeUseCount(candidate, activeRecipeId) > 0))
    .sort((a, b) => (
      plannerOptionRepeatPressure(a, weeklyUseCounts, context.recipeById) - plannerOptionRepeatPressure(b, weeklyUseCounts, context.recipeById)
      || Number(a?.score || 0) - Number(b?.score || 0)
    ));
  const selected = [];
  const selectedKeys = new Set();
  const coveredBySlot = {};
  const coveredSignatures = new Set();
  function add(option) {
    const key = option?.option_id || plannerDayOptionStorageKey(option);
    if (!key || selectedKeys.has(key) || selected.length >= max) return false;
    selected.push(option);
    selectedKeys.add(key);
    Object.entries(option?.recipe_ids_by_slot || {}).forEach(([slotId, recipeId]) => {
      if (!recipeId || activeIdSet.has(recipeId)) return;
      if (!coveredBySlot[slotId]) coveredBySlot[slotId] = new Set();
      coveredBySlot[slotId].add(recipeId);
    });
    const signature = plannerDayOptionWeeklyRouteSignature(option, context.recipeById);
    if (signature) coveredSignatures.add(signature);
    return true;
  }
  const topTarget = Math.min(max, Math.max(4, Math.ceil(max * 0.35)));
  ranked.forEach((option) => {
    if (selected.length < topTarget) add(option);
  });
  ranked.forEach((option) => {
    if (selected.length >= max) return;
    const addsSlotRecipe = Object.entries(option?.recipe_ids_by_slot || {}).some(([slotId, recipeId]) => (
      recipeId && !activeIdSet.has(recipeId) && !coveredBySlot[slotId]?.has(recipeId)
    ));
    if (addsSlotRecipe) add(option);
  });
  ranked.forEach((option) => {
    if (selected.length >= max) return;
    const signature = plannerDayOptionWeeklyRouteSignature(option, context.recipeById);
    if (signature && !coveredSignatures.has(signature)) add(option);
  });
  ranked.forEach((option) => {
    if (selected.length >= max) return;
    add(option);
  });
  return selected;
}

function plannerRemainingRecipeCapacity(recipeId, dayIndex, days, dayOptions, context = {}) {
  const cache = context.remainingCapacityCache instanceof Map ? context.remainingCapacityCache : null;
  const cacheKey = cache ? `${recipeId}:${dayIndex}` : "";
  if (cacheKey && cache.has(cacheKey)) return cache.get(cacheKey);
  let count = 0;
  for (const day of (days || []).slice(dayIndex)) {
    const result = dayOptions?.[day.day];
    const dayUseCount = (result?.options || []).reduce((max, option) => (
      Math.max(max, plannerOptionRecipeUseCount(option, recipeId))
    ), 0);
    if (dayUseCount <= 0) break;
    count += dayUseCount;
  }
  if (cacheKey) cache.set(cacheKey, count);
  return count;
}

function plannerRecipeWeeklyUseCap(recipe) {
  const blockSize = plannerRecipeBlockSize(recipe);
  if (plannerRecipeTracksBatchContinuity(recipe, blockSize)) return blockSize;
  const category = recipeMealCategory(recipe);
  if (category === "breakfast") return Number(plannerOptionsPolicy().max_weekly_breakfast_repeats || 2);
  if (category === "dinner") return Number(plannerOptionsPolicy().max_weekly_dinner_repeats || 1);
  if (category === "lunch") return Number(plannerOptionsPolicy().max_weekly_lunch_repeats || 2);
  return Number(plannerOptionsPolicy().max_weekly_recipe_repeats || 2);
}

function plannerRecipeTracksBatchContinuity(recipe, batchUseCount = plannerRecipeBlockSize(recipe)) {
  return Number(batchUseCount || 0) > 1;
}

function plannerOptionUsesBlockedBatch(option, blockedBatchRecipeIds) {
  if (!blockedBatchRecipeIds?.size) return false;
  return plannerOptionRecipeIds(option).some((recipeId) => blockedBatchRecipeIds.has(recipeId));
}

function plannerMarkBlockedBatchHardGap(result, blockedBatchRecipeIds) {
  if (!result || !blockedBatchRecipeIds?.size) return "";
  const blockedRecipeIds = [...new Set((result.options || [])
    .flatMap((option) => Object.values(option?.recipe_ids_by_slot || {}))
    .filter((recipeId) => blockedBatchRecipeIds.has(recipeId)))];
  if (!blockedRecipeIds.length) return "";
  const warning = plannerBlockedBatchHardGapWarning(blockedRecipeIds);
  result.status = "gap";
  result.status_label = "Batch gap";
  result.selected_option_id = "";
  result.options = [];
  result.stored_option_count = 0;
  result.batch_hard_gap = true;
  result.blocked_batch_recipe_ids = blockedRecipeIds;
  result.warnings = [...new Set([...(Array.isArray(result.warnings) ? result.warnings : []), warning])];
  return warning;
}

function plannerMarkWeeklyRuleGap(result, optionChecks, blockedBatchRecipeIds) {
  if (!result) return "";
  const issueCounts = {};
  (optionChecks || []).forEach((item) => {
    (item.issues || []).forEach((issue) => {
      issueCounts[issue] = Number(issueCounts[issue] || 0) + 1;
    });
  });
  const blockedWarning = plannerMarkBlockedBatchHardGap(result, blockedBatchRecipeIds);
  const warning = blockedWarning || plannerWeeklyRuleGapWarning(issueCounts);
  result.status = "gap";
  result.status_label = "Weekly rule gap";
  result.selected_option_id = "";
  result.options = [];
  result.stored_option_count = 0;
  result.weekly_rule_gap = true;
  result.weekly_rule_issues = issueCounts;
  result.warnings = [...new Set([...(Array.isArray(result.warnings) ? result.warnings : []), warning])];
  return warning;
}

function plannerWeeklyRuleGapWarning(issueCounts) {
  const counts = issueCounts || {};
  if (counts.batch_continuity) return "Active batch would be broken here";
  if (counts.incomplete_batch_start) return "Batch recipe cannot start because not enough matching slots remain";
  if (counts.batch_block_sequence) return "No complete batch block fits this day with the current week";
  if (counts.weekly_repeat_cap) return "Weekly repeat cap blocks the remaining recipe options";
  if (counts.blocked_batch) return "Blocked batch recipe would be reused";
  return "Weekly variety rules block the remaining recipe options";
}

function plannerBlockedBatchHardGapWarning(blockedRecipeIds) {
  const labels = blockedRecipeIds
    .map((recipeId) => recipes().find((item) => recipeKey(item) === recipeId))
    .map((recipe) => recipe?.short_title || recipe?.title || recipeKey(recipe))
    .filter(Boolean);
  const label = labels.length ? labels.join(", ") : "Blocked batch";
  return `${label} batch is blocked after an earlier batch break; no non-batch fallback fits this day`;
}

function plannerBatchContinuityWarning(batch) {
  const remaining = Number(batch?.remaining || 0);
  const mealWord = remaining === 1 ? "meal" : "meals";
  return `${batch.label} batch has ${remaining} ${mealWord} left but cannot continue here`;
}

function plannerBatchCarryoverWarning(batch) {
  const servings = Number(batch?.carryover_servings || batch?.remaining || 0);
  const mealWord = servings === 1 ? "meal" : "meals";
  return `${batch.label} batch carries ${servings} spare ${mealWord} into the next usable lunch window`;
}

function plannerRecordBatchCarryoverWarnings(result, activeBatches, warnings, dayName = "") {
  plannerCarryoverActiveBatches(activeBatches).forEach((batch) => {
    const warning = plannerBatchCarryoverWarning(batch);
    if (Array.isArray(warnings)) warnings.push(dayName ? `${dayName}: ${warning}` : warning);
    if (!result) return;
    result.warnings = [...new Set([...(Array.isArray(result.warnings) ? result.warnings : []), warning])];
    result.batch_carryover_warnings = [
      ...(Array.isArray(result.batch_carryover_warnings) ? result.batch_carryover_warnings : []),
      {
        recipe_id: batch.recipe_id,
        label: batch.label,
        carryover_servings: Number(batch.carryover_servings || batch.remaining || 0),
        reason: batch.carryover_reason || "",
        warning,
      },
    ];
  });
}

function plannerAddDayBatchWarning(result, warning, batch) {
  if (!result) return;
  result.warnings = [...new Set([...(Array.isArray(result.warnings) ? result.warnings : []), warning])];
  result.batch_continuity_warnings = [
    ...(Array.isArray(result.batch_continuity_warnings) ? result.batch_continuity_warnings : []),
    {
      recipe_id: batch.recipe_id,
      label: batch.label,
      remaining: Number(batch.remaining || 0),
      warning,
    },
  ];
}

function plannerBestOptionForActiveBatches(options, activeBatches) {
  if (!activeBatches.length) return options?.[0] || null;
  return [...(options || [])]
    .sort((a, b) => plannerOptionBatchContinuityScore(b, activeBatches) - plannerOptionBatchContinuityScore(a, activeBatches))
    [0] || null;
}

function plannerOptionBatchContinuityScore(option, activeBatches) {
  const continued = (activeBatches || []).reduce((sum, batch) => {
    return sum + Math.min(Number(batch.remaining || 0), plannerOptionRecipeUseCount(option, batch.recipe_id));
  }, 0);
  return (continued * 1000000) - Number(option?.score || 0);
}

function plannerRecipeBatchUseCount(recipe) {
  if (!recipe) return 1;
  return Math.max(1, collectionRecipeMealCount(recipe));
}

function plannerRecipeBlockSize(recipe) {
  if (!recipe) return 1;
  const explicit = Number(recipe.planner_block_size || recipe.block_size || recipe?.planner_block?.size || 0);
  if (Number.isFinite(explicit) && explicit > 0) return Math.max(1, Math.round(explicit));
  return plannerRecipeBatchUseCount(recipe);
}

function calculatePlannerDayOptions(day, usableRecipes, policy) {
  const slotRecords = (day.slots || []).map((slot) => ({ slot, state: plannerSlotState(slot) }));
  const frozenSlotRecords = slotRecords.filter(({ slot }) => slot.slot_type === "meal" && plannerSlotFrozen(slot));
  const recipeSlotRecords = slotRecords.filter(({ slot, state: slotState }) => (
    slot.slot_type === "meal" &&
    slotState.required &&
    slotState.slot_status === "planner_recipe" &&
    !isFinisherSlot(slot) &&
    !plannerSlotFrozen(slot)
  ));
  const externalSlotRecords = slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.slot_status === "external_meal" && !plannerSlotFrozen(slot));
  const skippedSlotRecords = slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.slot_status === "skipped" && !plannerSlotFrozen(slot));
  const finisherSlotRecords = plannerFinishersIncludedInCalculator()
    ? slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.required && isFinisherSlot(slot) && !plannerSlotFrozen(slot))
    : [];
  const finisherReserveActive = plannerDayHasFinisherReserve(slotRecords);
  const partialMacroDay = plannerDayIsPartialMacroDay(recipeSlotRecords, externalSlotRecords, [...skippedSlotRecords, ...frozenSlotRecords]);
  const inventoryContextForDay = plannerInventoryContextForDay(day);
  const ingredientTargetMapForDay = plannerIngredientTargetsForWeek(plannerActiveWeekStartKey()).by_inventory_id || {};
  const slotCandidates = recipeSlotRecords.map(({ slot, state: slotState }) => {
    const lockedRecipeId = plannerLockedRecipeForSlot(slot.slot_id);
    const candidates = usableRecipes
      .filter((recipe) => recipeMatchesPlannerSlot(recipe, slot, slotState))
      .filter((recipe) => !plannerRecipeBlockedForSlot(recipe, slot.slot_id))
      .filter((recipe) => !lockedRecipeId || recipeKey(recipe) === lockedRecipeId)
      .filter((recipe) => !plannerRecipeOnCooldown(recipe))
      .map((recipe, index) => ({
        recipe,
        index,
        use_up_scores: plannerRecipeInventoryUseScoresForSlot(recipe, day, slot, inventoryContextForDay, ingredientTargetMapForDay),
      }))
      .sort((a, b) => (
        Number(b.use_up_scores?.ingredient_target_score || 0) - Number(a.use_up_scores?.ingredient_target_score || 0)
        || Number(b.use_up_scores?.inventory_use_up_score || 0) - Number(a.use_up_scores?.inventory_use_up_score || 0)
        || plannerRecipeCandidateSortScore(a.recipe) - plannerRecipeCandidateSortScore(b.recipe)
        || a.index - b.index
      ))
      .map((entry) => entry.recipe)
      .slice(0, Number(policy.max_candidate_options_per_slot || 60));
    return {
      slot_id: slot.slot_id,
      title: slot.title || slot.role || slot.slot_id,
      meal_category: slotState.meal_category || plannerMealCategoryForSlot(slot),
      people: slotState.people,
      candidate_count: candidates.length,
      candidate_ids: candidates.map((recipe) => recipeKey(recipe)),
      candidates,
    };
  });
  const rawCombinationCount = slotCandidates.reduce((total, item) => total * Math.max(item.candidate_count, 0), recipeSlotRecords.length ? 1 : 0);
  const missingSlots = slotCandidates.filter((item) => item.candidate_count === 0).map((item) => item.title);
  const budgetBounds = plannerBudgetBoundsForSlotCandidates(slotCandidates);
  const workloadBounds = plannerWorkloadBoundsForSlotCandidates(slotCandidates);
  const baseResult = {
    day: day.day,
    short_day: day.short_day || day.day,
    status: "not_built",
    status_label: "Not built",
    raw_combination_count: rawCombinationCount,
    raw_option_count: 0,
    stored_option_count: 0,
    checked_combination_count: 0,
    combination_limit_reached: false,
    selected_option_id: "",
    recipe_slot_count: recipeSlotRecords.length,
    external_slot_count: externalSlotRecords.length,
    skipped_slot_count: skippedSlotRecords.length,
    frozen_slot_count: frozenSlotRecords.length,
    finisher_slot_count: finisherSlotRecords.length,
    finisher_reserve_active: finisherReserveActive,
    budget_bounds: budgetBounds,
    workload_bounds: workloadBounds,
    slot_candidates: slotCandidates.map(({ candidates, ...item }) => item),
    options: [],
    warnings: [],
  };
  if (!recipeSlotRecords.length) {
    return {
      ...baseResult,
      status: externalSlotRecords.length ? "reserved_external" : skippedSlotRecords.length ? "partial" : "no_recipe_slots",
      status_label: externalSlotRecords.length ? "Reserved outside meal" : skippedSlotRecords.length ? "Partial day" : "No recipe slots",
      warnings: [
        ...(skippedSlotRecords.length ? [`${day.day}: skipped meal means partial macro check`] : []),
        ...(frozenSlotRecords.length ? [`${day.day}: ${frozenSlotRecords.length} past meal${frozenSlotRecords.length === 1 ? "" : "s"} frozen`] : []),
      ],
    };
  }
  if (missingSlots.length) {
    const missingSlotVerb = missingSlots.length === 1 ? "has" : "have";
    return {
      ...baseResult,
      status: usableRecipes.length ? "gap" : "blocked_no_usable_recipes",
      status_label: usableRecipes.length ? "Recipe gap" : "No usable recipes",
      warnings: [`${day.day}: ${missingSlots.length} slot${missingSlots.length === 1 ? "" : "s"} ${missingSlotVerb} no usable recipe candidates`],
    };
  }
  const validOptions = [];
  const validOptionKeys = new Set();
  const cap = Number(policy.max_raw_valid_options || 5000);
  const combinationCap = Number(policy.max_raw_combinations_per_day || 50000);
  const scoringContext = {
    inventoryContext: inventoryContextForDay,
    ingredientTargetMap: ingredientTargetMapForDay,
    draftFatiguePenaltyByRecipe: plannerDraftFatiguePenaltyMapForActiveWeek(),
    profileByPerson: new Map((state.profileIndex?.people || []).map((profile) => [profile.person, profile])),
    recipePersonTotalsCache: new Map(),
    recipeActiveMinutesCache: new Map(),
    recipeCooldownCache: new Map(),
    dayMainRangeCache: new Map(),
    selectionContributionCache: new Map(),
  };
  let checkedCombinations = 0;
  let combinationLimitReached = false;

  function addValidOption(option) {
    const key = plannerDayOptionStorageKey(option);
    if (!key || validOptionKeys.has(key)) return false;
    validOptionKeys.add(key);
    validOptions.push(option);
    return true;
  }

  plannerCandidateCoverageSelections(plannerEnumerationSlotCandidates(slotCandidates)).forEach((selection) => {
    if (validOptions.length >= cap) return;
    const option = buildPlannerDayOption(day, selection, externalSlotRecords, [...skippedSlotRecords, ...frozenSlotRecords], finisherSlotRecords, partialMacroDay, finisherReserveActive, scoringContext);
    if (option.valid) addValidOption(option);
  });

  enumeratePlannerDayCombinations(plannerEnumerationSlotCandidates(slotCandidates), (selection) => {
    checkedCombinations += 1;
    if (checkedCombinations > combinationCap) {
      combinationLimitReached = true;
      return false;
    }
    if (validOptions.length >= cap) return false;
    const option = buildPlannerDayOption(day, selection, externalSlotRecords, [...skippedSlotRecords, ...frozenSlotRecords], finisherSlotRecords, partialMacroDay, finisherReserveActive, scoringContext);
    if (!option.valid) return true;
    addValidOption(option);
    return true;
  });
  const sortedOptions = plannerSelectStoredDayOptions(validOptions, Number(policy.max_stored_day_options || 300))
    .map((option, index) => ({
      ...option,
      option_id: `${String(day.short_day || day.day || "day").toLowerCase()}-option-${index + 1}`,
    }));
  const selected = sortedOptions[0]?.option_id || "";
  return {
    ...baseResult,
    status: sortedOptions.length ? (partialMacroDay ? "partial" : externalSlotRecords.length ? "reserved_external" : "valid") : "gap",
    status_label: sortedOptions.length ? (partialMacroDay ? "Partial options" : externalSlotRecords.length ? "Reserved outside meal" : "Valid options") : "No valid day versions",
    raw_option_count: validOptions.length,
    stored_option_count: sortedOptions.length,
    checked_combination_count: checkedCombinations,
    combination_limit_reached: combinationLimitReached,
    selected_option_id: selected,
    options: sortedOptions,
    warnings: sortedOptions.length
      ? [
          ...(frozenSlotRecords.length ? [`${day.day}: ${frozenSlotRecords.length} past meal${frozenSlotRecords.length === 1 ? "" : "s"} frozen`] : []),
          ...(combinationLimitReached ? [`${day.day}: search capped after ${number(combinationCap)} combinations`] : []),
        ]
      : [`${day.day}: slot candidates exist but no day version hit the macro rules${combinationLimitReached ? " before the search cap" : ""}`],
  };
}

function plannerSelectStoredDayOptions(validOptions, limit = 300) {
  const max = Math.max(1, Number(limit || 300));
  const sorted = [...(validOptions || [])].sort((a, b) => Number(a?.score || 0) - Number(b?.score || 0));
  const selected = [];
  const selectedIds = new Set();
  const coveredBySlot = {};
  const recipeById = new Map(recipes().map((recipe) => [recipeKey(recipe), recipe]));
  const coveredRouteKeys = new Set();
  const coveredBatchRouteKeys = new Set();
  const coveredRouteSignatures = new Set();

  function add(option) {
    const key = plannerDayOptionStorageKey(option);
    if (!key || selectedIds.has(key) || selected.length >= max) return false;
    selected.push(option);
    selectedIds.add(key);
    plannerMarkDayOptionCoverage(option, coveredBySlot);
    plannerMarkDayOptionRouteCoverage(option, coveredRouteKeys, recipeById);
    plannerMarkDayOptionBatchRouteCoverage(option, coveredBatchRouteKeys, recipeById);
    const signature = plannerDayOptionWeeklyRouteSignature(option, recipeById);
    if (signature) coveredRouteSignatures.add(signature);
    return true;
  }

  const topScoreTarget = plannerDayOptionPhaseTarget(max, 0.16);
  sorted.forEach((option) => {
    if (selected.length >= topScoreTarget) return;
    add(option);
  });

  const routeKeyTarget = plannerDayOptionPhaseTarget(max, 0.5);
  plannerDayOptionRouteKeyPriorities().forEach((routeType) => {
    sorted.forEach((option) => {
      if (selected.length >= routeKeyTarget) return;
      if (plannerDayOptionAddsRouteKeyCoverage(option, coveredRouteKeys, routeType, recipeById)) add(option);
    });
  });

  const batchRouteTarget = plannerDayOptionPhaseTarget(max, 0.84);
  plannerDayOptionBatchRouteKeyPriorities().forEach((routeType) => {
    sorted.forEach((option) => {
      if (selected.length >= batchRouteTarget) return;
      if (plannerDayOptionAddsBatchRouteCoverage(option, coveredBatchRouteKeys, routeType, recipeById)) add(option);
    });
  });

  const slotCoverageTarget = plannerDayOptionPhaseTarget(max, 0.9);
  sorted.forEach((option) => {
    if (selected.length >= slotCoverageTarget) return;
    if (plannerDayOptionAddsCoverage(option, coveredBySlot)) add(option);
  });

  sorted.forEach((option) => {
    if (selected.length >= max) return;
    const signature = plannerDayOptionWeeklyRouteSignature(option, recipeById);
    if (signature && !coveredRouteSignatures.has(signature)) add(option);
  });

  sorted.forEach((option) => {
    if (selected.length >= max) return;
    add(option);
  });
  return selected;
}

function plannerDayOptionPhaseTarget(max, ratio) {
  return Math.min(max, Math.max(1, Math.ceil(Number(max || 1) * Number(ratio || 0))));
}

function plannerDayOptionStorageKey(option) {
  return Object.entries(option?.recipe_ids_by_slot || {})
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([slotId, recipeId]) => `${slotId}:${recipeId}`)
    .join("|");
}

function plannerDayOptionAddsCoverage(option, coveredBySlot) {
  return Object.entries(option?.recipe_ids_by_slot || {}).some(([slotId, recipeId]) => {
    if (!recipeId) return false;
    return !coveredBySlot[slotId]?.has(recipeId);
  });
}

function plannerMarkDayOptionCoverage(option, coveredBySlot) {
  Object.entries(option?.recipe_ids_by_slot || {}).forEach(([slotId, recipeId]) => {
    if (!recipeId) return;
    if (!coveredBySlot[slotId]) coveredBySlot[slotId] = new Set();
    coveredBySlot[slotId].add(recipeId);
  });
}

function plannerDayOptionRouteKeyPriorities() {
  return ["use_up_target", "batch", "expensive_beef_mince_demand", "breakfast", "dinner", "lunch"];
}

function plannerDayOptionBatchRouteKeyPriorities() {
  return ["batch_set", "use_up_target", "dinner", "breakfast", "lunch"];
}

function plannerDayOptionWeeklyRouteEntries(option, recipeById = null) {
  const seen = new Set();
  const entries = [];
  function add(type, recipeId) {
    const key = `${type}:${recipeId}`;
    if (!recipeId || seen.has(key)) return;
    seen.add(key);
    entries.push({ type, recipe_id: recipeId, key });
  }
  Object.values(option?.recipe_ids_by_slot || {}).filter(Boolean).forEach((recipeId) => {
    const recipe = recipeById?.get(recipeId) || recipes().find((item) => recipeKey(item) === recipeId);
    if (!recipe) return;
    const category = recipeMealCategory(recipe);
    const blockSize = plannerRecipeBlockSize(recipe);
    if (plannerRecipeTracksBatchContinuity(recipe, blockSize)) add("batch", recipeId);
    if (category === "breakfast") add("breakfast", recipeId);
    if (category === "dinner") add("dinner", recipeId);
    if (category === "lunch") add("lunch", recipeId);
  });
  const beefDemand = plannerOptionExpensiveBeefMinceDemand(option, recipeById);
  const beefBand = plannerExpensiveBeefMinceDemandBand(beefDemand);
  add("expensive_beef_mince_demand", beefBand);
  (option?.inventory_use_up || []).forEach((use) => {
    const targetKey = use.family_id || use.sku_code || use.inventory_id || use.item_name || "";
    if (targetKey) add("use_up_target", targetKey);
  });
  return entries;
}

function plannerDayOptionAddsRouteKeyCoverage(option, coveredRouteKeys, routeType, recipeById = null) {
  return plannerDayOptionWeeklyRouteEntries(option, recipeById)
    .some((entry) => entry.type === routeType && !coveredRouteKeys.has(entry.key));
}

function plannerMarkDayOptionRouteCoverage(option, coveredRouteKeys, recipeById = null) {
  plannerDayOptionWeeklyRouteEntries(option, recipeById).forEach((entry) => coveredRouteKeys.add(entry.key));
}

function plannerDayOptionBatchRouteKeys(option, routeType, recipeById = null) {
  const entries = plannerDayOptionWeeklyRouteEntries(option, recipeById);
  const batchIds = entries
    .filter((entry) => entry.type === "batch")
    .map((entry) => entry.recipe_id)
    .sort();
  if (!batchIds.length) return [];
  const batchSet = batchIds.join("+");
  if (routeType === "batch_set") return [`batch-set:${batchSet}`];
  const batchIdSet = new Set(batchIds);
  return entries
    .filter((entry) => entry.type === routeType && !batchIdSet.has(entry.recipe_id))
    .map((entry) => `batch-route:${routeType}:${batchSet}:${entry.recipe_id}`);
}

function plannerDayOptionAddsBatchRouteCoverage(option, coveredBatchRouteKeys, routeType, recipeById = null) {
  return plannerDayOptionBatchRouteKeys(option, routeType, recipeById)
    .some((key) => !coveredBatchRouteKeys.has(key));
}

function plannerMarkDayOptionBatchRouteCoverage(option, coveredBatchRouteKeys, recipeById = null) {
  plannerDayOptionBatchRouteKeyPriorities().forEach((routeType) => {
    plannerDayOptionBatchRouteKeys(option, routeType, recipeById).forEach((key) => coveredBatchRouteKeys.add(key));
  });
}

function plannerDayOptionWeeklyRouteSignature(option, recipeById = null) {
  return plannerDayOptionWeeklyRouteEntries(option, recipeById)
    .map((entry) => entry.key)
    .sort()
    .join("|");
}

function plannerCandidateCoverageSelections(slotCandidates) {
  const slots = slotCandidates || [];
  if (!slots.length || slots.some((slotCandidate) => !slotCandidate.candidates?.length)) return [];
  const seen = new Set();
  const selections = [];

  function addSelection(selection) {
    const key = selection.map((item) => `${item.slot_id}:${recipeKey(item.recipe)}`).sort().join("|");
    if (seen.has(key)) return false;
    seen.add(key);
    selections.push(selection);
    return true;
  }

  plannerSingleBatchRouteCoverageSelections(slots).forEach(addSelection);
  plannerNonBatchFallbackCoverageSelections(slots).forEach(addSelection);
  plannerExpensiveBeefMinceCoverageSelections(slots).forEach(addSelection);

  const targetCandidateCount = Math.min(
    ...slots
      .map((slotCandidate) => Number(slotCandidate.candidate_count || slotCandidate.candidates?.length || 0))
      .filter((count) => count > 1)
  );
  if (Number.isFinite(targetCandidateCount)) {
    slots.forEach((slotCandidate, slotIndex) => {
      const candidateCount = Number(slotCandidate.candidate_count || slotCandidate.candidates.length || 0);
      if (candidateCount !== targetCandidateCount) return;
      slotCandidate.candidates.forEach((recipe) => {
        addSelection(slots.map((candidate, index) => ({
          slot_id: candidate.slot_id,
          people: candidate.people,
          recipe: index === slotIndex ? recipe : candidate.candidates[0],
        })));
      });
    });
  }
  plannerBatchPairRouteCoverageSelections(slots).forEach(addSelection);
  plannerExpensiveBeefMinceCoverageSelections(slots).forEach(addSelection);
  plannerNonBatchFallbackCoverageSelections(slots).forEach(addSelection);
  return selections;
}

function plannerExpensiveBeefMinceCoverageSelections(slots) {
  const sourceSlots = slots || [];
  if (!sourceSlots.length || sourceSlots.some((slotCandidate) => !slotCandidate.candidates?.length)) return [];
  const selections = [];
  const seen = new Set();
  const maxSelections = 420;
  const relevant = sourceSlots.map((slotCandidate) => {
    const candidates = plannerExpensiveBeefMinceCoverageCandidates(slotCandidate);
    return candidates.length ? { slotCandidate, candidates } : null;
  }).filter(Boolean);
  if (!relevant.length) return [];

  function selectionWith(overrides) {
    return sourceSlots.map((slotCandidate) => ({
      slot_id: slotCandidate.slot_id,
      people: slotCandidate.people,
      recipe: overrides.get(slotCandidate.slot_id) || slotCandidate.candidates[0],
    }));
  }

  function addSelection(overrides) {
    if (selections.length >= maxSelections) return false;
    const selection = selectionWith(overrides);
    const key = selection.map((item) => `${item.slot_id}:${recipeKey(item.recipe)}`).sort().join("|");
    if (seen.has(key)) return false;
    seen.add(key);
    selections.push(selection);
    return true;
  }

  relevant.forEach(({ slotCandidate, candidates }) => {
    candidates.forEach((recipe) => {
      addSelection(new Map([[slotCandidate.slot_id, recipe]]));
    });
  });

  const cleanOverrides = new Map();
  relevant.forEach(({ slotCandidate, candidates }) => {
    const noBeef = candidates.find((recipe) => plannerRecipeExpensiveBeefMinceDemand(recipe) <= 0);
    if (noBeef) cleanOverrides.set(slotCandidate.slot_id, noBeef);
  });
  if (cleanOverrides.size) addSelection(cleanOverrides);

  for (let left = 0; left < relevant.length && selections.length < maxSelections; left += 1) {
    for (let right = left + 1; right < relevant.length && selections.length < maxSelections; right += 1) {
      relevant[left].candidates.slice(0, 6).forEach((leftRecipe) => {
        relevant[right].candidates.slice(0, 6).forEach((rightRecipe) => {
          addSelection(new Map([
            [relevant[left].slotCandidate.slot_id, leftRecipe],
            [relevant[right].slotCandidate.slot_id, rightRecipe],
          ]));
        });
      });
    }
  }
  return selections;
}

function plannerExpensiveBeefMinceCoverageCandidates(slotCandidate) {
  const byBand = new Map();
  (slotCandidate?.candidates || []).forEach((recipe) => {
    const band = plannerExpensiveBeefMinceDemandBand(plannerRecipeExpensiveBeefMinceDemand(recipe));
    const current = byBand.get(band);
    if (!current || plannerRecipeCandidateSortScore(recipe) < plannerRecipeCandidateSortScore(current)) byBand.set(band, recipe);
  });
  const priority = ["beef-0g", "beef-750g", "beef-375g", "beef-500g", "beef-1500g", "beef-1000g", "beef-other"];
  return priority
    .map((band) => byBand.get(band))
    .filter(Boolean);
}

function plannerRecipeCandidateSortScore(recipe) {
  return Number(recipe?.planner_score || recipe?.score || recipe?.macro_score || 0);
}

function plannerNonBatchFallbackCoverageSelections(slots) {
  const batchSlots = (slots || [])
    .filter(plannerSlotCandidateHasTrackedBatch)
    .map((slotCandidate) => ({
      slotCandidate,
      candidates: plannerNonBatchFallbackCandidates(slotCandidate).slice(0, 10),
    }))
    .filter((record) => record.candidates.length);
  if (!batchSlots.length) return [];
  const selections = [];
  const maxSelections = 900;

  function selectionWith(overrides) {
    return slots.map((slotCandidate) => ({
      slot_id: slotCandidate.slot_id,
      people: slotCandidate.people,
      recipe: overrides.get(slotCandidate.slot_id) || slotCandidate.candidates[0],
    }));
  }

  function walk(index, overrides) {
    if (selections.length >= maxSelections) return;
    if (index >= batchSlots.length) {
      selections.push(selectionWith(overrides));
      return;
    }
    const { slotCandidate, candidates } = batchSlots[index];
    candidates.forEach((recipe) => {
      if (selections.length >= maxSelections) return;
      const next = new Map(overrides);
      next.set(slotCandidate.slot_id, recipe);
      walk(index + 1, next);
    });
  }

  walk(0, new Map());
  return selections;
}

function plannerNonBatchFallbackCandidates(slotCandidate) {
  return (slotCandidate?.candidates || []).filter((recipe) => {
    const batchUseCount = plannerRecipeBlockSize(recipe);
    return !plannerRecipeTracksBatchContinuity(recipe, batchUseCount);
  });
}

function plannerSingleBatchRouteCoverageSelections(slots) {
  const batchSlots = (slots || []).filter(plannerSlotCandidateHasTrackedBatch);
  if (batchSlots.length !== 1) return [];
  const batchSlot = batchSlots[0];
  const selections = [];
  const maxSelections = 120;

  function selectionWith(overrides) {
    return slots.map((slotCandidate) => ({
      slot_id: slotCandidate.slot_id,
      people: slotCandidate.people,
      recipe: overrides.get(slotCandidate.slot_id) || slotCandidate.candidates[0],
    }));
  }

  plannerTrackedBatchCandidates(batchSlot).slice(0, 24).forEach((batchRecipe) => {
    if (selections.length >= maxSelections) return;
    const baseOverrides = new Map([[batchSlot.slot_id, batchRecipe]]);
    selections.push(selectionWith(baseOverrides));
    const variantSlots = plannerRouteVariantSlots(slots)
      .filter((slotCandidate) => slotCandidate.slot_id !== batchSlot.slot_id);
    variantSlots.forEach((slotCandidate) => {
      if (selections.length >= maxSelections) return;
      plannerWeeklyRouteCandidates(slotCandidate).slice(1, 9).forEach((recipe) => {
        if (selections.length >= maxSelections) return;
        const overrides = new Map(baseOverrides);
        overrides.set(slotCandidate.slot_id, recipe);
        selections.push(selectionWith(overrides));
      });
    });
  });
  return selections;
}

function plannerBatchPairRouteCoverageSelections(slots) {
  const batchSlots = (slots || []).filter(plannerSlotCandidateHasTrackedBatch);
  if (batchSlots.length < 2) return [];
  const routeSlots = plannerRouteVariantSlots(slots);
  const selections = [];
  const maxSelections = 4500;

  function selectionWith(overrides) {
    return slots.map((slotCandidate) => ({
      slot_id: slotCandidate.slot_id,
      people: slotCandidate.people,
      recipe: overrides.get(slotCandidate.slot_id) || slotCandidate.candidates[0],
    }));
  }

  for (let leftIndex = 0; leftIndex < batchSlots.length; leftIndex += 1) {
    for (let rightIndex = leftIndex + 1; rightIndex < batchSlots.length; rightIndex += 1) {
      const leftSlot = batchSlots[leftIndex];
      const rightSlot = batchSlots[rightIndex];
      const leftCandidates = plannerTrackedBatchCandidates(leftSlot).slice(0, 18);
      const rightCandidates = plannerTrackedBatchCandidates(rightSlot).slice(0, 18);
      leftCandidates.forEach((leftRecipe) => {
        rightCandidates.forEach((rightRecipe) => {
          if (selections.length >= maxSelections) return;
          if (recipeKey(leftRecipe) === recipeKey(rightRecipe)) return;
          const baseOverrides = new Map([
            [leftSlot.slot_id, leftRecipe],
            [rightSlot.slot_id, rightRecipe],
          ]);
          selections.push(selectionWith(baseOverrides));
          const variantSlots = routeSlots.filter((slotCandidate) => !baseOverrides.has(slotCandidate.slot_id));
          const variantCount = Math.min(24, Math.max(0, ...variantSlots.map((slotCandidate) => plannerWeeklyRouteCandidates(slotCandidate).length)));
          for (let variantIndex = 1; variantIndex < variantCount && selections.length < maxSelections; variantIndex += 1) {
            const overrides = new Map(baseOverrides);
            variantSlots.forEach((slotCandidate) => {
              const candidates = plannerWeeklyRouteCandidates(slotCandidate);
              if (!candidates.length) return;
              overrides.set(slotCandidate.slot_id, candidates[variantIndex % candidates.length]);
            });
            selections.push(selectionWith(overrides));
          }
        });
      });
    }
  }
  return selections;
}

function plannerRouteVariantSlots(slots) {
  return [...(slots || [])]
    .filter(plannerSlotCandidateAffectsWeeklyRoute)
    .sort((a, b) => plannerRouteVariantSlotPriority(a) - plannerRouteVariantSlotPriority(b));
}

function plannerRouteVariantSlotPriority(slotCandidate) {
  if (plannerSlotCandidateHasTrackedBatch(slotCandidate)) return 0;
  const category = plannerValidMealCategory(slotCandidate?.meal_category || "");
  if (category === "breakfast") return 1;
  if (category === "dinner") return 2;
  if (category === "lunch") return 3;
  return 4;
}

function plannerSlotCandidateAffectsWeeklyRoute(slotCandidate) {
  const category = plannerValidMealCategory(slotCandidate?.meal_category || "");
  return category === "breakfast" || category === "dinner" || category === "lunch" || plannerSlotCandidateHasTrackedBatch(slotCandidate);
}

function plannerTrackedBatchCandidates(slotCandidate) {
  return (slotCandidate?.candidates || []).filter((recipe) => {
    const batchUseCount = plannerRecipeBlockSize(recipe);
    return plannerRecipeTracksBatchContinuity(recipe, batchUseCount);
  });
}

function plannerWeeklyRouteCandidates(slotCandidate) {
  const category = plannerValidMealCategory(slotCandidate?.meal_category || "");
  return (slotCandidate?.candidates || []).filter((recipe) => {
    const batchUseCount = plannerRecipeBlockSize(recipe);
    return plannerRecipeTracksBatchContinuity(recipe, batchUseCount) || ["breakfast", "dinner", "lunch"].includes(category);
  });
}

function plannerFinishersIncludedInCalculator() {
  return false;
}

function plannerDayHasFinisherReserve(slotRecords) {
  if (plannerFinishersIncludedInCalculator()) return false;
  return slotRecords.some(({ slot, state: slotState }) => (
    slot.slot_type === "meal" &&
    slotState.required &&
    slotState.slot_status !== "not_required" &&
    isFinisherSlot(slot)
  ));
}

function plannerDayIsPartialMacroDay(recipeSlotRecords, externalSlotRecords, skippedSlotRecords) {
  if (skippedSlotRecords.length > 0) return true;
  const plannedMealCount = recipeSlotRecords.length + externalSlotRecords.length;
  return plannedMealCount === 1;
}

function enumeratePlannerDayCombinations(slotCandidates, visit) {
  const selection = [];
  function walk(index) {
    if (index >= slotCandidates.length) return visit([...selection]);
    const slotCandidate = slotCandidates[index];
    for (const recipe of slotCandidate.candidates) {
      selection.push({ slot_id: slotCandidate.slot_id, people: slotCandidate.people, recipe });
      const keepGoing = walk(index + 1);
      selection.pop();
      if (keepGoing === false) return false;
    }
    return true;
  }
  walk(0);
}

function plannerEnumerationSlotCandidates(slotCandidates) {
  return [...(slotCandidates || [])].sort((a, b) => {
    const priorityDiff = plannerSlotCandidateEnumerationPriority(a) - plannerSlotCandidateEnumerationPriority(b);
    if (priorityDiff) return priorityDiff;
    const countDiff = Number(a.candidate_count || 0) - Number(b.candidate_count || 0);
    if (countDiff) return countDiff;
    return String(a.slot_id || "").localeCompare(String(b.slot_id || ""));
  });
}

function plannerSlotCandidateEnumerationPriority(slotCandidate) {
  if (plannerSlotCandidateHasTrackedBatch(slotCandidate)) return 0;
  const category = plannerValidMealCategory(slotCandidate?.meal_category || "");
  if (category === "lunch") return 1;
  if (category === "dinner") return 2;
  if (category === "breakfast") return 3;
  return 4;
}

function plannerSlotCandidateHasTrackedBatch(slotCandidate) {
  return (slotCandidate?.candidates || []).some((recipe) => {
    const batchUseCount = plannerRecipeBlockSize(recipe);
    return plannerRecipeTracksBatchContinuity(recipe, batchUseCount);
  });
}

function buildPlannerDayOption(day, selection, externalSlotRecords, skippedSlotRecords, finisherSlotRecords, partialMacroDay = skippedSlotRecords.length > 0, finisherReserveActive = false, scoringContext = {}) {
  const recipeIdsBySlot = Object.fromEntries(selection.map((item) => [item.slot_id, recipeKey(item.recipe)]));
  const totals = plannerDayOptionTotals(selection, externalSlotRecords, scoringContext);
  const relaxedLowerMacroBounds = partialMacroDay || externalSlotRecords.length > 0;
  const validity = plannerDayOptionValidity(totals, selection, relaxedLowerMacroBounds, finisherReserveActive || finisherSlotRecords.length > 0, scoringContext);
  const inventoryUseUp = plannerInventoryUseForSelection(day, selection, scoringContext.inventoryContext);
  const inventoryUseUpScore = plannerInventoryUseUpScore(inventoryUseUp);
  const ingredientTargetScore = plannerIngredientTargetUseScore(inventoryUseUp, scoringContext.ingredientTargetMap);
  const score = plannerDayOptionScore(totals, selection, validity, inventoryUseUpScore, ingredientTargetScore, scoringContext.draftFatiguePenaltyByRecipe, scoringContext);
  return {
    option_id: "",
    day: day.day,
    recipe_ids_by_slot: recipeIdsBySlot,
    totals_by_person: totals,
    valid: validity.valid,
    partial: partialMacroDay,
    reserved_external: externalSlotRecords.length > 0,
    finisher_reserve_active: finisherReserveActive,
    inventory_use_up: inventoryUseUp,
    inventory_use_up_score: Math.round(inventoryUseUpScore * 10) / 10,
    ingredient_target_score: Math.round(ingredientTargetScore * 10) / 10,
    score,
    issues: validity.issues,
  };
}

function plannerOptionProfileByName(person, scoringContext = {}) {
  if (scoringContext.profileByPerson instanceof Map && scoringContext.profileByPerson.has(person)) return scoringContext.profileByPerson.get(person);
  return profileByName(person);
}

function plannerOptionRecipePersonTotals(recipe, person, scoringContext = {}) {
  const recipeId = recipeKey(recipe);
  const key = `${recipeId}:${person}`;
  if (scoringContext.recipePersonTotalsCache instanceof Map && scoringContext.recipePersonTotalsCache.has(key)) {
    return scoringContext.recipePersonTotalsCache.get(key);
  }
  const row = recipePersonTotals(recipe, person);
  if (scoringContext.recipePersonTotalsCache instanceof Map) scoringContext.recipePersonTotalsCache.set(key, row);
  return row;
}

function plannerOptionRecipeActiveMinutes(recipe, scoringContext = {}) {
  const recipeId = recipeKey(recipe);
  if (scoringContext.recipeActiveMinutesCache instanceof Map && scoringContext.recipeActiveMinutesCache.has(recipeId)) {
    return scoringContext.recipeActiveMinutesCache.get(recipeId);
  }
  const minutes = recipeActiveMinutes(recipe);
  if (scoringContext.recipeActiveMinutesCache instanceof Map) scoringContext.recipeActiveMinutesCache.set(recipeId, minutes);
  return minutes;
}

function plannerOptionRecipeOnCooldown(recipe, scoringContext = {}) {
  const recipeId = recipeKey(recipe);
  if (scoringContext.recipeCooldownCache instanceof Map && scoringContext.recipeCooldownCache.has(recipeId)) {
    return scoringContext.recipeCooldownCache.get(recipeId);
  }
  const onCooldown = plannerRecipeOnCooldown(recipe);
  if (scoringContext.recipeCooldownCache instanceof Map) scoringContext.recipeCooldownCache.set(recipeId, onCooldown);
  return onCooldown;
}

function plannerOptionDayMainRange(profile, hasFinisherSlot, scoringContext = {}) {
  const key = `${profile?.person || ""}:${hasFinisherSlot ? "finisher" : "base"}`;
  if (scoringContext.dayMainRangeCache instanceof Map && scoringContext.dayMainRangeCache.has(key)) {
    return scoringContext.dayMainRangeCache.get(key);
  }
  const range = plannerDayMainRange(profile, hasFinisherSlot);
  if (scoringContext.dayMainRangeCache instanceof Map) scoringContext.dayMainRangeCache.set(key, range);
  return range;
}

function plannerSelectionItemContribution(item, scoringContext = {}) {
  const recipe = item?.recipe;
  const recipeId = recipeKey(recipe);
  const people = Array.isArray(item?.people) ? item.people : [];
  const key = `${item?.slot_id || ""}:${recipeId}:${people.join("+")}`;
  if (scoringContext.selectionContributionCache instanceof Map && scoringContext.selectionContributionCache.has(key)) {
    return scoringContext.selectionContributionCache.get(key);
  }
  const activeMinutes = plannerOptionRecipeActiveMinutes(recipe, scoringContext);
  const peopleTotals = {};
  people.forEach((person) => {
    const row = plannerOptionRecipePersonTotals(recipe, person, scoringContext);
    if (!row) return;
    peopleTotals[person] = {
      kcal: Number(row.kcal || row.energy_kcal || row.calories || 0),
      protein_g: Number(row.protein_g || row.protein || 0),
      cost_gbp: Number(row.cost_gbp || 0),
      active_minutes: activeMinutes,
    };
  });
  const contribution = { recipe_id: recipeId, people_totals: peopleTotals };
  if (scoringContext.selectionContributionCache instanceof Map) scoringContext.selectionContributionCache.set(key, contribution);
  return contribution;
}

function plannerDayOptionTotals(selection, externalSlotRecords, scoringContext = {}) {
  const totals = {};
  function ensure(person) {
    if (!totals[person]) {
      totals[person] = {
        kcal_min: 0,
        kcal_max: 0,
        protein_min_g: 0,
        protein_max_g: 0,
        cost_gbp: 0,
        active_minutes: 0,
      };
    }
    return totals[person];
  }
  selection.forEach(({ recipe, people }) => {
    const contribution = plannerSelectionItemContribution({ recipe, people }, scoringContext);
    Object.entries(contribution.people_totals || {}).forEach(([person, row]) => {
      const total = ensure(person);
      const kcal = Number(row.kcal || 0);
      const protein = Number(row.protein_g || 0);
      total.kcal_min += kcal;
      total.kcal_max += kcal;
      total.protein_min_g += protein;
      total.protein_max_g += protein;
      total.cost_gbp += Number(row.cost_gbp || 0);
      total.active_minutes += Number(row.active_minutes || 0);
    });
  });
  externalSlotRecords.forEach(({ slot, state: slotState }) => {
    slotState.people.forEach((person) => {
      const profile = plannerOptionProfileByName(person, scoringContext);
      const target = profileMealTargetForSlot(profile, slot);
      if (!target) return;
      const total = ensure(person);
      total.kcal_min += Number(target.kcal_target_min || target.kcal_hard_min || 0);
      total.kcal_max += Number(target.kcal_target_max || target.kcal_hard_max || 0);
      total.protein_min_g += Number(target.protein_target_min_g || target.protein_hard_min_g || 0);
      total.protein_max_g += Number(target.protein_target_max_g || target.protein_hard_max_g || 0);
      total.external_reserve = true;
    });
  });
  return totals;
}

function plannerDayOptionValidity(totals, selection, hasSkippedMeal, hasFinisherSlot, scoringContext = {}) {
  const duplicateRecipeIds = selection.map((item) => recipeKey(item.recipe)).filter(Boolean);
  const duplicateIssue = duplicateRecipeIds.some((recipeId, index) => duplicateRecipeIds.indexOf(recipeId) !== index);
  const issues = [];
  const hardIssues = [];
  if (duplicateIssue) {
    issues.push("duplicate recipe in same day");
    hardIssues.push("duplicate recipe in same day");
  }
  Object.entries(totals).forEach(([person, total]) => {
    const profile = plannerOptionProfileByName(person, scoringContext);
    if (!profile) return;
    const range = plannerOptionDayMainRange(profile, hasFinisherSlot, scoringContext);
    if (range.kcal_max !== "" && total.kcal_min > range.kcal_max) {
      const issue = `${person}: above kcal range`;
      issues.push(issue);
      hardIssues.push(issue);
    }
    if (!hasSkippedMeal && range.kcal_min !== "" && total.kcal_max < range.kcal_min) {
      const issue = `${person}: below kcal range`;
      issues.push(issue);
      hardIssues.push(issue);
    }
    if (!hasSkippedMeal && range.protein_min_g !== "" && total.protein_max_g < range.protein_min_g) {
      const issue = `${person}: below protein range`;
      issues.push(issue);
      hardIssues.push(issue);
    }
  });
  if (hasSkippedMeal && !issues.includes("partial_day")) issues.push("partial_day");
  return { valid: hardIssues.length === 0, issues, finisher_reserve_active: hasFinisherSlot };
}

function plannerDayMainRange(profile, hasFinisherSlot) {
  const goal = profilePresetGoal(profile, activePresetForPerson(profile.person));
  const finishers = Array.isArray(profile.finishers) ? profile.finishers : [];
  const finisherMaxKcal = hasFinisherSlot ? finishers.reduce((max, item) => Math.max(max, Number(item.kcal_per_unit || 0) * Number(item.max_units || 1)), 0) : 0;
  const finisherMaxProtein = hasFinisherSlot ? finishers.reduce((max, item) => Math.max(max, Number(item.protein_g_per_unit || 0) * Number(item.max_units || 1)), 0) : 0;
  const kcalMin = cleanMacroInput(goal.kcal_min);
  const proteinMin = cleanMacroInput(goal.protein_min_g);
  return {
    kcal_min: kcalMin === "" ? "" : Math.max(0, kcalMin - Math.round(finisherMaxKcal || 0)),
    kcal_max: cleanMacroInput(goal.kcal_max),
    protein_min_g: proteinMin === "" ? "" : Math.max(0, proteinMin - Math.round(finisherMaxProtein || 0)),
  };
}

function plannerDayOptionScore(totals, selection, validity, inventoryUseUpScore = 0, ingredientTargetScore = 0, draftFatiguePenaltyByRecipe = null, scoringContext = {}) {
  let score = validity.issues.length * 100000;
  Object.entries(totals).forEach(([person, total]) => {
    const profile = plannerOptionProfileByName(person, scoringContext);
    if (!profile) return;
    const range = plannerOptionDayMainRange(profile, Boolean(validity.finisher_reserve_active), scoringContext);
    const targetMid = range.kcal_min !== "" && range.kcal_max !== "" ? (range.kcal_min + range.kcal_max) / 2 : total.kcal_min;
    const totalMid = (total.kcal_min + total.kcal_max) / 2;
    score += Math.abs(totalMid - targetMid);
    if (range.protein_min_g !== "" && total.protein_min_g < range.protein_min_g) score += (range.protein_min_g - total.protein_min_g) * 25;
    score += total.cost_gbp * 2;
  });
  score += plannerSelectionWorkloadScore(selection, scoringContext) * 0.4;
  selection.forEach(({ recipe }) => {
    const key = recipeKey(recipe);
    if (plannerOptionRecipeOnCooldown(recipe, scoringContext)) score += 1000;
    score += draftFatiguePenaltyByRecipe && Object.prototype.hasOwnProperty.call(draftFatiguePenaltyByRecipe, key)
      ? Number(draftFatiguePenaltyByRecipe[key] || 0)
      : plannerRecipeDraftFatiguePenalty(key);
  });
  score -= Math.min(650, Number(inventoryUseUpScore || 0));
  score -= Math.min(1800, Number(ingredientTargetScore || 0));
  return Math.round(score * 10) / 10;
}

function plannerRecipeBlockedForSlot(recipe, slotId) {
  const key = recipeKey(recipe);
  const draft = normalizePlannerReviewDraft(state.plannerReviewDraft);
  const slotBlocks = draft.blocked_recipes_by_slot?.[slotId] || [];
  return draft.blocked_recipe_ids.includes(key) || slotBlocks.includes(key);
}

function plannerLockedRecipeForSlot(slotId) {
  const draft = normalizePlannerReviewDraft(state.plannerReviewDraft);
  return draft.locked_slots?.[slotId] || "";
}

function plannerRecipeOnCooldown(recipe) {
  const key = recipeKey(recipe);
  const usage = normalizePlannerRecipeUsageDraft(state.plannerRecipeUsageDraft);
  const lastUsed = usage.last_used_by_recipe_id?.[key];
  if (!lastUsed) return false;
  if (usage.last_used_week_by_recipe_id?.[key]) return plannerUsageBlocksActiveWeek(key, usage);
  const usedAt = new Date(lastUsed).getTime();
  if (!Number.isFinite(usedAt)) return false;
  const cooldownMs = Number(usage.cooldown_days || plannerOptionsPolicy().default_cooldown_days || 7) * 24 * 60 * 60 * 1000;
  return Date.now() - usedAt < cooldownMs;
}

function plannerUsageBlocksActiveWeek(recipeId, usage = normalizePlannerRecipeUsageDraft(state.plannerRecipeUsageDraft)) {
  const key = String(recipeId || "");
  const lastUsed = usage.last_used_by_recipe_id?.[key];
  if (!lastUsed) return false;
  const rawUsedWeek = usage.last_used_week_by_recipe_id?.[key] || "";
  const usedWeek = rawUsedWeek ? plannerNormalizeWeekStartKey(rawUsedWeek) : "";
  if (usedWeek && usedWeek === plannerActiveWeekStartKey()) return false;
  const usedAt = new Date(lastUsed).getTime();
  const activeStart = plannerActiveWeekStartDate().getTime();
  if (!Number.isFinite(usedAt) || !Number.isFinite(activeStart)) return false;
  if (activeStart <= usedAt) return false;
  const cooldownMs = Number(usage.cooldown_days || plannerOptionsPolicy().default_cooldown_days || 7) * 24 * 60 * 60 * 1000;
  return activeStart - usedAt < cooldownMs;
}

function plannerCooldownFingerprintForActiveWeek() {
  const usage = normalizePlannerRecipeUsageDraft(state.plannerRecipeUsageDraft);
  return Object.keys(usage.last_used_by_recipe_id || {})
    .filter((recipeId) => {
      if (usage.last_used_week_by_recipe_id?.[recipeId]) return plannerUsageBlocksActiveWeek(recipeId, usage);
      return Boolean(usage.last_used_by_recipe_id?.[recipeId]);
    })
    .map((recipeId) => `${recipeId}:${usage.last_used_by_recipe_id[recipeId]}:${usage.last_used_week_by_recipe_id?.[recipeId] || ""}`)
    .sort();
}

function plannerRecipeDraftFatiguePenalty(recipeId) {
  const key = String(recipeId || "");
  if (!key) return 0;
  const entry = plannerDraftHistoryRecipeUseMapForActiveWeek()[key];
  if (!entry) return 0;
  return plannerDraftFatiguePenaltyForEntry(entry);
}

function plannerDraftFatiguePenaltyForEntry(entry = {}) {
  const countPenalty = Number(entry.count || 0) * 360;
  const distancePenalty = Math.max(0, 5 - Number(entry.nearest_week_distance || 5)) * 90;
  return Math.min(1800, countPenalty + distancePenalty);
}

function plannerDraftFatiguePenaltyMapForActiveWeek() {
  const uses = plannerDraftHistoryRecipeUseMapForActiveWeek();
  return Object.fromEntries(Object.entries(uses).map(([recipeId, entry]) => [
    recipeId,
    plannerDraftFatiguePenaltyForEntry(entry),
  ]));
}

function plannerDraftHistoryRecipeUseMapForActiveWeek() {
  const activeWeek = plannerActiveWeekStartKey();
  const source = state.plannerWeekHistory;
  const updatedAt = source?.updated_at || "";
  const cache = plannerDraftHistoryRecipeUseMapForActiveWeek.cache;
  if (cache?.source === source && cache.active_week === activeWeek && cache.updated_at === updatedAt) return cache.map;
  const activeDate = plannerDateFromKey(activeWeek);
  const maxWindowDays = Math.max(21, Number(plannerOptionsPolicy().default_cooldown_days || 7) * 4);
  const map = {};
  Object.values(normalizePlannerWeekHistory(state.plannerWeekHistory).weeks || {}).forEach((record) => {
    const weekStart = plannerNormalizeWeekStartKey(record?.week_start || "");
    if (!weekStart || weekStart === activeWeek) return;
    const recordDate = plannerDateFromKey(weekStart);
    if (!activeDate || !recordDate) return;
    const distanceDays = Math.abs((activeDate.getTime() - recordDate.getTime()) / (24 * 60 * 60 * 1000));
    if (!Number.isFinite(distanceDays) || distanceDays > maxWindowDays) return;
    const selectedIds = Array.isArray(record.selected_recipe_ids) ? record.selected_recipe_ids : [];
    selectedIds.filter(Boolean).forEach((recipeId) => {
      const key = String(recipeId);
      const entry = map[key] || {
        recipe_id: key,
        count: 0,
        weeks: [],
        nearest_week_distance: Infinity,
      };
      entry.count += 1;
      entry.weeks.push(weekStart);
      entry.nearest_week_distance = Math.min(entry.nearest_week_distance, distanceDays / 7);
      map[key] = entry;
    });
  });
  plannerDraftHistoryRecipeUseMapForActiveWeek.cache = {
    source,
    active_week: activeWeek,
    updated_at: updatedAt,
    map,
  };
  return map;
}

function plannerDraftHistoryFingerprintForActiveWeek() {
  const map = plannerDraftHistoryRecipeUseMapForActiveWeek();
  return Object.values(map)
    .map((entry) => `${entry.recipe_id}:${entry.count}:${entry.weeks.sort().join(",")}`)
    .sort();
}

function plannerDayCache(dayName) {
  return normalizePlannerOptionsCache(state.plannerOptionsCache).day_options?.[dayName] || null;
}

function plannerSlotCache(dayResult, slotId) {
  return (dayResult?.slot_candidates || []).find((item) => item.slot_id === slotId) || null;
}

function plannerSelectedOptionForDay(dayName, options = {}) {
  const dayResult = plannerDayCache(dayName);
  if (!dayResult) return options.includeManual === false ? null : plannerManualOnlyOptionForDay(dayName);
  const selectedId = normalizePlannerReviewDraft(state.plannerReviewDraft).selected_option_by_day?.[dayName] || dayResult.selected_option_id;
  const option = (dayResult.options || []).find((item) => item.option_id === selectedId) || dayResult.options?.[0] || null;
  if (options.includeManual === false) return option;
  return plannerDayOptionWithManualRecipes(dayName, option);
}

function plannerManualOnlyOptionForDay(dayName) {
  const day = (currentPlannerTemplate()?.days || []).find((item) => item.day === dayName);
  if (!day) return null;
  const slotRecords = plannerSlotsForDay(day).map((slot) => ({ slot, state: plannerSlotState(slot) }));
  const recipeSlotRecords = slotRecords.filter(({ slot, state: slotState }) => (
    slot.slot_type === "meal" &&
    slotState.required &&
    slotState.slot_status === "planner_recipe" &&
    !isFinisherSlot(slot)
  ));
  const externalSlotRecords = slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.slot_status === "external_meal");
  const skippedSlotRecords = slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.slot_status === "skipped");
  const finisherSlotRecords = plannerFinishersIncludedInCalculator()
    ? slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.required && isFinisherSlot(slot))
    : [];
  const selection = recipeSlotRecords.map(({ slot, state: slotState }) => {
    const recipe = plannerManualRecipeForSlot(slot.slot_id);
    return recipe ? { slot_id: slot.slot_id, people: slotState.people, recipe } : null;
  }).filter(Boolean);
  if (!selection.length && !externalSlotRecords.length && !skippedSlotRecords.length) return null;
  const selectedSlotIds = new Set(selection.map((item) => item.slot_id));
  const missingRecipeSlots = recipeSlotRecords.some(({ slot }) => !selectedSlotIds.has(slot.slot_id));
  const partialMacroDay = missingRecipeSlots || plannerDayIsPartialMacroDay(recipeSlotRecords, externalSlotRecords, skippedSlotRecords);
  const finisherReserveActive = plannerDayHasFinisherReserve(slotRecords);
  return {
    ...buildPlannerDayOption(day, selection, externalSlotRecords, skippedSlotRecords, finisherSlotRecords, partialMacroDay, finisherReserveActive),
    option_id: `manual-${hashString(`${dayName}|${selection.map((item) => `${item.slot_id}:${recipeKey(item.recipe)}`).join("|")}`)}`,
    manual_overlay: true,
  };
}

function plannerSelectedRecipeForSlot(slotId) {
  const day = plannerSlotDay(slotId);
  if (!day) {
    const horizonSlot = plannerShoppingHorizonSlotRecords(state.plannerOptionsCache, plannerActiveWeekStartKey())
      .find((slot) => slot.slot_id === slotId);
    return horizonSlot?.recipe_id ? recipes().find((recipe) => recipeKey(recipe) === horizonSlot.recipe_id) || null : null;
  }
  const option = plannerSelectedOptionForDay(day.day, { includeManual: false });
  const recipeId = option?.recipe_ids_by_slot?.[slotId];
  return recipeId ? recipes().find((recipe) => recipeKey(recipe) === recipeId) || null : null;
}

function plannerManualRecipeIdsForDay(day, extraManualIds = {}) {
  const ids = {};
  plannerSlotsForDay(day).forEach((slot) => {
    const manualId = state.plannerDraft?.slot_overrides?.[slot.slot_id]?.selected_recipe_id || "";
    if (manualId) ids[slot.slot_id] = String(manualId);
  });
  Object.entries(extraManualIds || {}).forEach(([slotId, recipeId]) => {
    if (!recipeId) return;
    if (plannerSlotsForDay(day).some((slot) => slot.slot_id === slotId)) ids[slotId] = String(recipeId);
  });
  return ids;
}

function plannerDayOptionWithManualRecipes(dayName, option, extraManualIds = {}) {
  if (!option) return null;
  const day = (currentPlannerTemplate()?.days || []).find((item) => item.day === dayName);
  if (!day) return option;
  const manualIds = plannerManualRecipeIdsForDay(day, extraManualIds);
  if (!Object.keys(manualIds).length) return option;
  const slotRecords = plannerSlotsForDay(day).map((slot) => ({ slot, state: plannerSlotState(slot) }));
  const recipeSlotRecords = slotRecords.filter(({ slot, state: slotState }) => (
    slot.slot_type === "meal" &&
    slotState.required &&
    slotState.slot_status === "planner_recipe" &&
    !isFinisherSlot(slot)
  ));
  const externalSlotRecords = slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.slot_status === "external_meal");
  const skippedSlotRecords = slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.slot_status === "skipped");
  const finisherSlotRecords = plannerFinishersIncludedInCalculator()
    ? slotRecords.filter(({ slot, state: slotState }) => slot.slot_type === "meal" && slotState.required && isFinisherSlot(slot))
    : [];
  const missing = [];
  const selection = recipeSlotRecords.map(({ slot, state: slotState }) => {
    const recipeId = manualIds[slot.slot_id] || option.recipe_ids_by_slot?.[slot.slot_id] || "";
    const recipe = recipeId ? recipes().find((item) => recipeKey(item) === recipeId) || null : null;
    if (!recipe) missing.push(slot.title || slot.role || slot.slot_id);
    return { slot_id: slot.slot_id, people: slotState.people, recipe };
  }).filter((item) => item.recipe);
  if (missing.length) {
    return {
      ...option,
      manual_overlay: true,
      issues: [...(option.issues || []), `${missing.join(", ")} missing recipe`],
    };
  }
  const partialMacroDay = plannerDayIsPartialMacroDay(recipeSlotRecords, externalSlotRecords, skippedSlotRecords);
  const finisherReserveActive = plannerDayHasFinisherReserve(slotRecords);
  return {
    ...option,
    ...buildPlannerDayOption(day, selection, externalSlotRecords, skippedSlotRecords, finisherSlotRecords, partialMacroDay, finisherReserveActive),
    option_id: option.option_id,
    base_option_id: option.option_id,
    manual_overlay: true,
  };
}

function stickPlannerSlot(slotId) {
  const slot = findPlannerSlot(slotId);
  if (plannerSlotFrozen(slot)) return;
  const recipe = plannerManualRecipeForSlot(slotId) || plannerSelectedRecipeForSlot(slotId);
  if (!recipe) return;
  state.plannerReviewDraft = normalizePlannerReviewDraft(state.plannerReviewDraft);
  plannerReviewScopeSlotIds(slotId, recipe).forEach((scopeSlotId) => {
    state.plannerReviewDraft.locked_slots[scopeSlotId] = recipeKey(recipe);
  });
  state.plannerReviewDraft.updated_at = new Date().toISOString();
  savePlannerReviewDraftStore();
  recordPlannerWeekHistory("reviewing");
  refreshPlannerWeekPackFitReceipt(plannerActiveWeekStartKey(), "planner_twist_day");
  renderPlanner();
}

function twistPlannerSlot(slotId) {
  const slot = findPlannerSlot(slotId);
  if (plannerSlotFrozen(slot)) return;
  const manualRecipe = plannerManualRecipeForSlot(slotId);
  const recipe = manualRecipe || plannerSelectedRecipeForSlot(slotId);
  if (!recipe) return;
  state.plannerReviewDraft = normalizePlannerReviewDraft(state.plannerReviewDraft);
  const scopeSlotIds = plannerReviewScopeSlotIds(slotId, recipe);
  const day = plannerSlotDay(slotId);
  const option = day ? plannerSelectedOptionForDay(day.day) : null;
  if (option?.recipe_ids_by_slot) {
    Object.entries(option.recipe_ids_by_slot).forEach(([otherSlotId, recipeId]) => {
      if (!scopeSlotIds.includes(otherSlotId) && recipeId) state.plannerReviewDraft.locked_slots[otherSlotId] = recipeId;
    });
  }
  scopeSlotIds.forEach((scopeSlotId) => {
    const blocks = new Set(state.plannerReviewDraft.blocked_recipes_by_slot[scopeSlotId] || []);
    blocks.add(recipeKey(recipe));
    state.plannerReviewDraft.blocked_recipes_by_slot[scopeSlotId] = [...blocks];
    delete state.plannerReviewDraft.locked_slots[scopeSlotId];
    if (manualRecipe) clearPlannerManualRecipe(scopeSlotId);
  });
  state.plannerReviewDraft.updated_at = new Date().toISOString();
  buildPlannerOptions();
}

function blockPlannerSlotRecipe(slotId) {
  const slot = findPlannerSlot(slotId);
  if (plannerSlotFrozen(slot)) return;
  const manualRecipe = plannerManualRecipeForSlot(slotId);
  const recipe = manualRecipe || plannerSelectedRecipeForSlot(slotId);
  if (!recipe) return;
  state.plannerReviewDraft = normalizePlannerReviewDraft(state.plannerReviewDraft);
  const scopeSlotIds = plannerReviewScopeSlotIds(slotId, recipe);
  scopeSlotIds.forEach((scopeSlotId) => {
    const blocks = new Set(state.plannerReviewDraft.blocked_recipes_by_slot[scopeSlotId] || []);
    blocks.add(recipeKey(recipe));
    state.plannerReviewDraft.blocked_recipes_by_slot[scopeSlotId] = [...blocks];
    if (manualRecipe) clearPlannerManualRecipe(scopeSlotId);
  });
  state.plannerReviewDraft.updated_at = new Date().toISOString();
  savePlannerReviewDraftStore();
  recordPlannerWeekHistory("reviewing");
  buildPlannerOptions();
}

function plannerBuildSlotPockets(template = currentPlannerTemplate()) {
  const pockets = [];
  const activeBySignature = {};
  const days = template?.days || [];

  function finish(signature) {
    const pocket = activeBySignature[signature];
    if (!pocket) return;
    pocket.size = pocket.slot_ids.length;
    pocket.end_day = pocket.days[pocket.days.length - 1] || pocket.start_day;
    pocket.pocket_id = plannerPocketId(pocket);
    pockets.push(pocket);
    delete activeBySignature[signature];
  }

  days.forEach((day, dayIndex) => {
    Object.keys(activeBySignature).forEach((signature) => {
      if (Number(activeBySignature[signature].last_day_index) < dayIndex - 1) finish(signature);
    });
    plannerSlotsForDay(day).forEach((slot) => {
      const slotState = plannerSlotState(slot);
      if (!plannerSlotCanJoinPocket(slot, slotState)) return;
      const signature = plannerSlotPocketSignature(slot, slotState);
      const active = activeBySignature[signature];
      if (active && Number(active.last_day_index) === dayIndex - 1) {
        active.slot_ids.push(slot.slot_id);
        active.days.push(day.day);
        active.last_day_index = dayIndex;
        return;
      }
      finish(signature);
      activeBySignature[signature] = {
        pocket_id: "",
        signature,
        meal_track: plannerSlotMealTrack(slot, slotState),
        meal_category: slotState.meal_category || plannerMealCategoryForSlot(slot),
        people: [...(slotState.people || [])],
        required_filters: [...(slotState.chips || [])],
        max_minutes: slotState.max_minutes || "",
        max_cost: slotState.max_cost || "",
        slot_ids: [slot.slot_id],
        days: [day.day],
        start_day: day.day,
        end_day: day.day,
        start_day_index: dayIndex,
        last_day_index: dayIndex,
        size: 1,
      };
    });
  });
  Object.keys(activeBySignature).forEach(finish);
  return pockets;
}

function plannerSlotCanJoinPocket(slot, slotState = plannerSlotState(slot)) {
  return Boolean(
    slot?.slot_type === "meal" &&
    slotState.required &&
    slotState.slot_status === "planner_recipe"
  );
}

function plannerPocketId(pocket) {
  return `pocket-${hashString([
    pocket.signature,
    pocket.slot_ids?.[0] || "",
    pocket.slot_ids?.[pocket.slot_ids.length - 1] || "",
    pocket.slot_ids?.length || 0,
  ].join("|"))}`;
}

function plannerSlotPocketSignature(slot, slotState = plannerSlotState(slot)) {
  const category = slotState.meal_category || plannerMealCategoryForSlot(slot);
  const track = plannerSlotMealTrack(slot, slotState);
  const people = [...(slotState.people || [])].sort().join("+");
  const filters = [...(slotState.chips || [])].sort().join("+");
  const maxMinutes = slotState.max_minutes || "";
  const maxCost = slotState.max_cost || "";
  return [category, track, people, filters, maxMinutes, maxCost].join("|");
}

function plannerSlotMealTrack(slot, slotState = plannerSlotState(slot)) {
  const explicit = String(slot?.meal_track || slot?.planner_meal_track || "").trim();
  if (explicit) return plannerNormalizeMealSlotId(explicit);
  const category = slotState.meal_category || plannerMealCategoryForSlot(slot);
  const targets = plannerTargetMealSlotsForSlot(slot, slotState).map(plannerNormalizeMealSlotId).filter(Boolean);
  if (targets.includes("luke_lunch_1")) return "luke_lunch_1";
  if (targets.includes("luke_lunch_2")) return "luke_lunch_2";
  if (targets.includes("adult_snack")) return "adult_snack";
  if (category === "breakfast") return "breakfast";
  if (category === "dinner") return "dinner";
  if (category === "finisher") return "finisher";
  if (category === "lunch") {
    const people = new Set(slotState.people || []);
    if (people.has("Sarah") && people.has("Louis")) return "sarah_louis_lunch";
    if (people.has("Sarah")) return "sarah_lunch";
    if (people.has("Luke")) return targets[0] || "luke_lunch";
  }
  return targets[0] || category || slot?.slot_id || "meal";
}

function plannerPocketForSlot(slotId, template = currentPlannerTemplate()) {
  return plannerBuildSlotPockets(template).find((pocket) => pocket.slot_ids.includes(slotId)) || null;
}

function plannerRecipeCanOccupySlotInPocket(recipe, slot, slotState = plannerSlotState(slot)) {
  if (!recipe || !slot) return false;
  const blockSize = plannerRecipeBlockSize(recipe);
  if (blockSize <= 1) return true;
  const pocket = plannerPocketForSlot(slot.slot_id);
  if (!pocket || pocket.size < blockSize) return false;
  const slotIndex = pocket.slot_ids.indexOf(slot.slot_id);
  if (slotIndex < 0) return false;
  for (let startIndex = 0; startIndex <= pocket.slot_ids.length - blockSize; startIndex += 1) {
    if (slotIndex < startIndex || slotIndex >= startIndex + blockSize) continue;
    const segmentIds = pocket.slot_ids.slice(startIndex, startIndex + blockSize);
    if (segmentIds.every((segmentSlotId) => {
      const segmentSlot = findPlannerSlot(segmentSlotId);
      return segmentSlot && recipeMatchesPlannerSlotBase(recipe, segmentSlot, plannerSlotState(segmentSlot));
    })) return true;
  }
  return false;
}

function plannerRecipeCanStartAtSlotInPocket(recipe, slot, slotState = plannerSlotState(slot)) {
  return plannerRecipeStartPlacementSlotIds(slot.slot_id, recipe, slotState).length === plannerRecipeBlockSize(recipe);
}

function plannerRecipeCanReplaceCurrentPlacement(recipe, slot) {
  if (!recipe || !slot) return false;
  const currentRecipe = plannerManualRecipeForSlot(slot.slot_id) || plannerSelectedRecipeForSlot(slot.slot_id);
  if (!currentRecipe || !plannerRecipeTracksBatchContinuity(currentRecipe, plannerRecipeBlockSize(currentRecipe))) return false;
  const currentScope = plannerReviewScopeSlotIds(slot.slot_id, currentRecipe);
  const blockSize = plannerRecipeBlockSize(recipe);
  if (blockSize !== currentScope.length) return false;
  return currentScope.every((scopeSlotId) => {
    const scopeSlot = findPlannerSlot(scopeSlotId);
    return scopeSlot && recipeMatchesPlannerSlotBase(recipe, scopeSlot, plannerSlotState(scopeSlot));
  });
}

function plannerRecipeStartPlacementSlotIds(slotId, recipe) {
  if (!recipe) return [slotId];
  const blockSize = plannerRecipeBlockSize(recipe);
  if (blockSize <= 1) return [slotId];
  const pocket = plannerPocketForSlot(slotId);
  if (!pocket || pocket.size < blockSize) return [];
  const startIndex = pocket.slot_ids.indexOf(slotId);
  if (startIndex < 0 || startIndex + blockSize > pocket.slot_ids.length) return [];
  const segmentIds = pocket.slot_ids.slice(startIndex, startIndex + blockSize);
  return segmentIds.every((segmentSlotId) => {
    const segmentSlot = findPlannerSlot(segmentSlotId);
    return segmentSlot && recipeMatchesPlannerSlotBase(recipe, segmentSlot, plannerSlotState(segmentSlot));
  }) ? segmentIds : [];
}

function plannerSelectedPlacementSlotIds(slotId, recipe) {
  const blockSize = plannerRecipeBlockSize(recipe);
  if (!recipe || blockSize <= 1) return [slotId];
  const recipeId = recipeKey(recipe);
  const pocket = plannerPocketForSlot(slotId);
  const selectedIndex = pocket?.slot_ids.indexOf(slotId) ?? -1;
  if (!pocket || selectedIndex < 0) return [];
  const selectedIds = pocket.slot_ids.map((pocketSlotId) => {
    const selectedRecipe = plannerManualRecipeForSlot(pocketSlotId) || plannerSelectedRecipeForSlot(pocketSlotId);
    return recipeKey(selectedRecipe);
  });
  if (selectedIds[selectedIndex] !== recipeId) return [];
  let runStart = selectedIndex;
  let runEnd = selectedIndex;
  while (runStart > 0 && selectedIds[runStart - 1] === recipeId) runStart -= 1;
  while (runEnd < selectedIds.length - 1 && selectedIds[runEnd + 1] === recipeId) runEnd += 1;
  const runLength = runEnd - runStart + 1;
  if (runLength < blockSize) return [];
  const blockOffset = Math.floor((selectedIndex - runStart) / blockSize) * blockSize;
  const blockStart = runStart + blockOffset;
  if (blockStart + blockSize - 1 > runEnd) return [];
  return pocket.slot_ids.slice(blockStart, blockStart + blockSize);
}

function plannerPlacementForSlot(slotId, recipe) {
  const slotIds = plannerSelectedPlacementSlotIds(slotId, recipe);
  const startSlotIds = slotIds.length ? slotIds : plannerRecipeStartPlacementSlotIds(slotId, recipe);
  const blockSize = plannerRecipeBlockSize(recipe);
  return {
    placement_id: `placement-${hashString(`${recipeKey(recipe)}|${startSlotIds.join("+")}`)}`,
    pocket_id: plannerPocketForSlot(startSlotIds[0] || slotId)?.pocket_id || "",
    slot_ids: startSlotIds,
    recipe_id: recipeKey(recipe),
    block_size: blockSize,
  };
}

function plannerReviewScopeSlotIds(slotId, recipe) {
  if (!recipe || !plannerRecipeTracksBatchContinuity(recipe, plannerRecipeBlockSize(recipe))) return [slotId];
  const placement = plannerPlacementForSlot(slotId, recipe);
  return placement.slot_ids.length ? placement.slot_ids : [slotId];
}

function plannerManualRecipePickScopeSlotIds(slotId, recipe) {
  if (!recipe || !plannerRecipeTracksBatchContinuity(recipe, plannerRecipeBlockSize(recipe))) return [slotId];
  const currentRecipe = plannerManualRecipeForSlot(slotId) || plannerSelectedRecipeForSlot(slotId);
  if (currentRecipe && plannerRecipeTracksBatchContinuity(currentRecipe, plannerRecipeBlockSize(currentRecipe))) {
    const currentScope = plannerReviewScopeSlotIds(slotId, currentRecipe);
    if (currentScope.length > 1) return currentScope;
  }
  return plannerRecipeStartPlacementSlotIds(slotId, recipe);
}

function plannerForwardBatchScopeSlotIds(slotId, recipe) {
  if (!recipe || !plannerRecipeTracksBatchContinuity(recipe, plannerRecipeBlockSize(recipe))) return [slotId];
  return plannerRecipeStartPlacementSlotIds(slotId, recipe);
}

function plannerBatchSlotCanUseRecipe(slot, recipe, startSignature) {
  if (!slot || slot.slot_type !== "meal") return false;
  const slotState = plannerSlotState(slot);
  if (!slotState.required || slotState.slot_status !== "planner_recipe") return false;
  if (plannerBatchSlotSignature(slot, slotState) !== startSignature) return false;
  return recipeMatchesPlannerSlotSearch(recipe, slot, slotState);
}

function plannerBatchSlotSignature(slot, slotState = plannerSlotState(slot)) {
  return plannerSlotPocketSignature(slot, slotState);
}

function clearPlannerManualRecipe(slotId) {
  state.plannerDraft = normalizePlannerDraft(state.plannerDraft, currentPlannerTemplate());
  if (state.plannerDraft.slot_overrides?.[slotId]) {
    state.plannerDraft.slot_overrides[slotId].selected_recipe_id = "";
    savePlannerDraft();
  }
}

function twistPlannerDay(dayName) {
  const day = (currentPlannerTemplate()?.days || []).find((item) => item.day === dayName);
  if (day && plannerDayFrozen(day)) return;
  const dayResult = plannerDayCache(dayName);
  if (!dayResult?.options?.length) return;
  state.plannerReviewDraft = normalizePlannerReviewDraft(state.plannerReviewDraft);
  const currentId = state.plannerReviewDraft.selected_option_by_day[dayName] || dayResult.selected_option_id;
  const currentIndex = Math.max(0, dayResult.options.findIndex((option) => option.option_id === currentId));
  const nextOption = dayResult.options[(currentIndex + 1) % dayResult.options.length];
  if (!nextOption) return;
  state.plannerReviewDraft.selected_option_by_day[dayName] = nextOption.option_id;
  state.plannerReviewDraft.updated_at = new Date().toISOString();
  savePlannerReviewDraftStore();
  recordPlannerWeekHistory("reviewing");
  renderPlanner();
}

function plannerOptionsReviewPanel(optionsState = plannerOptionsState()) {
  const cache = optionsState.cache;
  const days = currentPlannerTemplate()?.days || [];
  if (!optionsState.has_cache) {
    return `
      <div class="planner-options-empty">
        <strong>Draft calendar</strong>
        <span>Edit the holes first, then press Create week. The calculator will only use accepted planner-ready recipes.</span>
      </div>
      <div class="planner-day-option-grid">
        ${days.map((day) => plannerDayOptionCard(day, null)).join("")}
      </div>
    `;
  }
  return `
    <div class="planner-options-summary ${escapeAttr(cache.status)} ${optionsState.stale ? "stale" : ""}">
      <strong>${escapeHtml(cache.status_label || optionsState.label)}</strong>
      <span>${escapeHtml(cache.built_at ? `Built ${friendlyDateTime(cache.built_at)}` : "No build time saved")}</span>
      <em>${escapeHtml(`${cache.usable_recipe_count} usable recipes; ${cache.review_only_recipe_count} review-only blocked; ${cache.total_stored_options} kept day versions`)}</em>
    </div>
    <div class="planner-day-option-grid">
      ${days.map((day) => plannerDayOptionCard(day, cache.day_options?.[day.day] || null)).join("")}
    </div>
    ${cache.warnings?.length ? plannerCollapsedDetail(`${number(cache.warnings.length)} planner note${cache.warnings.length === 1 ? "" : "s"}`, cache.warnings.slice(0, 8), "planner-options-warning") : ""}
  `;
}

function plannerDayOptionCard(day, result) {
  const label = result?.status_label || "Not built";
  const status = result?.status || "not_built";
  return `
    <article class="planner-day-option-card ${escapeAttr(status)}">
      <strong>${escapeHtml(day.short_day || day.day || "Day")}</strong>
      <span>${escapeHtml(label)}</span>
      <em>${escapeHtml(result ? `${result.stored_option_count} kept / ${result.raw_combination_count} combos` : "waiting")}</em>
    </article>
  `;
}

function friendlyDateTime(value) {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value || "";
  return date.toLocaleString("en-GB", {
    day: "2-digit",
    month: "short",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function plannerGapQueue(capacityRows = plannerCapacityRows()) {
  const weekGaps = plannerWeekBlockerGaps();
  const macroGaps = plannerMacroBandGaps(capacityRows);
  const varietyGaps = plannerVarietyGaps(capacityRows);
  const ingredientGaps = plannerIngredientCoverageGaps();
  return [...weekGaps, ...macroGaps, ...varietyGaps, ...ingredientGaps]
    .map((gap) => ({
      ...gap,
      gap_id: gap.gap_id || hashString(`${gap.category}:${gap.lane_id}:${gap.missing_band || ""}:${(gap.slot_ids || []).join(",")}`),
      near_miss_total: plannerNearMissTotal(gap.near_miss_counts),
    }))
    .sort((a, b) => b.priority_score - a.priority_score || a.request_summary.localeCompare(b.request_summary))
    .map((gap, index) => ({ ...gap, priority_rank: index + 1 }));
}

function plannerVisibleGapQueue(gapQueue) {
  const filter = plannerGapFilters().some((item) => item.id === state.plannerGapFilter) ? state.plannerGapFilter : "all";
  const filtered = gapQueue.filter((gap) => plannerGapMatchesFilter(gap, filter));
  return filtered.slice(0, filter === "all" ? 5 : 8);
}

function plannerGapMatchesFilter(gap, filter) {
  if (filter === "all") return true;
  if (filter === "near_misses") return plannerNearMissTotal(gap.near_miss_counts) > 0;
  return gap.filter === filter;
}

function plannerTopGapPackets(gapQueue) {
  return (Array.isArray(gapQueue) ? gapQueue : []).slice(0, 5);
}

function plannerSelectedGapPacketIndex(gapQueue) {
  const topGaps = plannerTopGapPackets(gapQueue);
  if (!topGaps.length) return 0;
  const rawIndex = Number(state.plannerGapPacketIndex || 0);
  if (!Number.isFinite(rawIndex)) return 0;
  return Math.max(0, Math.min(topGaps.length - 1, rawIndex));
}

function plannerGapHandoffPanel(gapQueue) {
  const topGaps = plannerTopGapPackets(gapQueue);
  if (!topGaps.length) {
    return `
      <article class="planner-handoff-panel empty">
        <div>
          <strong>No handoff needed</strong>
          <span>The current saved searches do not have a recipe request gap.</span>
        </div>
      </article>
    `;
  }
  const selectedIndex = plannerSelectedGapPacketIndex(topGaps);
  const gap = topGaps[selectedIndex];
  const packet = plannerGapHandoffPacket(gap, selectedIndex);
  const notice = state.plannerGapPacketNotice || "";
  return `
    <article class="planner-handoff-panel" data-planner-handoff-panel>
      <div class="planner-handoff-top">
        <div>
          <strong>Recipe handoff packet</strong>
          <span>${escapeHtml(packet.generator_brief)}</span>
        </div>
        <button class="planner-command-button primary" type="button" data-planner-copy-gap-packet="${escapeAttr(String(selectedIndex))}">Copy packet</button>
      </div>
      <div class="planner-handoff-selector" role="group" aria-label="Top recipe gaps">
        ${topGaps.map((item, index) => {
          const active = index === selectedIndex;
          return `
            <button class="${active ? "active" : ""}" type="button" data-planner-gap-packet-index="${escapeAttr(String(index))}" aria-pressed="${active ? "true" : "false"}">
              <strong>#${escapeHtml(String(item.priority_rank || index + 1))}</strong>
              <span>${escapeHtml(plannerGapSearchLabel(item))}</span>
            </button>
          `;
        }).join("")}
      </div>
      <div class="planner-handoff-summary">
        <div>
          <em>Saved search</em>
          <strong>${escapeHtml(packet.saved_search_label)}</strong>
        </div>
        <div class="planner-handoff-metrics">
          ${plannerMiniMetric("Band", packet.missing_band || "any")}
          ${plannerMiniMetric("Ready", String(packet.ready_count))}
          ${plannerMiniMetric("In review", String(packet.in_review_count))}
          ${plannerMiniMetric("Still needed", String(packet.still_needed))}
        </div>
      </div>
      <div class="planner-handoff-detail-grid">
        ${plannerMiniMetric("People", packet.people.join(", ") || "slot-specific")}
        ${plannerMiniMetric("Filters", packet.required_filters.join(", ") || "none")}
        ${plannerMiniMetric("Reason", packet.priority_reason)}
        ${plannerMiniMetric("Hard rules", packet.hard_exclusions.join("; ") || "profile hard rules")}
      </div>
      <details class="planner-handoff-preview" ${state.plannerGapPacketFallbackOpen ? "open" : ""}>
        <summary>Packet preview</summary>
        <textarea readonly data-planner-packet-textarea aria-label="Recipe handoff packet JSON">${escapeHtml(plannerGapPacketText(packet))}</textarea>
      </details>
      ${notice ? `<div class="planner-handoff-notice">${escapeHtml(notice)}</div>` : ""}
    </article>
  `;
}

function plannerGapHandoffPacket(gap, selectedIndex = 0) {
  if (!gap) return null;
  const lane = plannerNormalizeSavedSearch(gap.lane || {});
  const representativeSlot = Array.isArray(gap.slot_ids) && gap.slot_ids.length ? findPlannerSlot(gap.slot_ids[0]) : null;
  const representativeState = representativeSlot ? plannerSlotState(representativeSlot) : null;
  const mealCategory = plannerGapMealCategory(gap, lane, representativeSlot, representativeState);
  const people = plannerGapPeople(gap, lane, representativeState);
  const requiredFilters = plannerGapRequiredFilters(gap, lane, representativeState);
  const readyCount = Number(gap.current_count ?? gap.usable_count ?? 0);
  const inReviewCount = Number(gap.pipeline_count || 0);
  const targetCount = Number(gap.target_count || Math.max(1, Array.isArray(gap.slot_ids) ? gap.slot_ids.length : 1));
  const stillNeeded = Math.max(targetCount - readyCount - inReviewCount, 0);
  const savedSearchId = lane.search_id || gap.lane_id || "";
  const isIngredientGap = gap.category === "ingredient_coverage";
  return {
    schema_version: "v4.planner_gap_handoff_packet.1",
    packet_id: `gap-${gap.gap_id || hashString(`${savedSearchId}:${gap.missing_band || ""}`)}`,
    generated_at: new Date().toISOString(),
    priority_rank: Number(gap.priority_rank || selectedIndex + 1),
    priority_reason: gap.priority_reason || "Saved search needs more recipe coverage",
    meal_category: mealCategory,
    people,
    required_filters: requiredFilters,
    missing_band: gap.missing_band || "",
    target_range_by_person: Array.isArray(gap.target_range_by_person) ? gap.target_range_by_person : [],
    hard_exclusions: plannerHardExclusions(),
    ready_count: readyCount,
    in_review_count: inReviewCount,
    still_needed: stillNeeded,
    near_miss_counts: { ...plannerEmptyNearMissCounts(), ...(gap.near_miss_counts || {}) },
    source_slot_ids: Array.isArray(gap.slot_ids) ? gap.slot_ids : [],
    saved_search_id: savedSearchId,
    saved_search_label: plannerGapSearchLabel({ ...gap, lane: { ...lane, meal_category: mealCategory, people, required_filters: requiredFilters } }),
    generator_brief: isIngredientGap
      ? "Create one planner-ready recipe route that uses this required ingredient target. Do not make a weekly plan."
      : "Create one recipe block for this saved search. Do not make a weekly plan.",
    ingredient_targets: isIngredientGap ? (gap.ingredient_targets || []).map((target) => ({
      family_id: target.family_id || "",
      sku_code: target.sku_code || "",
      ingredient_label: target.ingredient_label || gap.ingredient_label || "",
      amount: Number(target.amount || 0),
      unit: target.unit || "",
      priority: target.priority || gap.ingredient_priority || "",
      priority_label: target.priority_label || gap.ingredient_priority_label || "",
      use_by_date: target.use_by_date || "",
      source_type: target.source_type || "",
    })) : [],
    ingredient_coverage: isIngredientGap ? {
      family_id: gap.ingredient_family_id || "",
      sku_code: gap.sku_code || "",
      ingredient_label: gap.ingredient_label || "",
      ready_recipe_count: readyCount,
      in_review_recipe_count: inReviewCount,
      target_recipe_count: targetCount,
      still_needed: stillNeeded,
      selection_rule: "when several routes can use this ingredient, prefer the one with the least recent draft and locked planner use",
      possible_recipe_options: Array.isArray(gap.possible_recipe_options) ? gap.possible_recipe_options : [],
    } : null,
    forbidden_outputs: [
      "no planner output",
      "no shopping output",
      "no calendar output",
      "no approval change",
      "no V3 factory queue write",
    ],
  };
}

function plannerGapMealCategory(gap, lane, representativeSlot, representativeState) {
  return plannerValidMealCategory(gap.meal_category || lane.meal_category || representativeState?.meal_category || plannerMealCategoryForSlot(representativeSlot || {}));
}

function plannerGapPeople(gap, lane, representativeState) {
  const people = Array.isArray(gap.people) && gap.people.length
    ? gap.people
    : Array.isArray(lane.people) && lane.people.length
      ? lane.people
      : representativeState?.people || [];
  return [...new Set(people.filter(Boolean))];
}

function plannerGapRequiredFilters(gap, lane, representativeState) {
  const filters = Array.isArray(gap.required_tags) && gap.required_tags.length
    ? gap.required_tags
    : Array.isArray(lane.required_filters) && lane.required_filters.length
      ? lane.required_filters
      : representativeState?.chips || [];
  return plannerNormalizeSlotFilterList(filters);
}

function plannerGapSearchLabel(gap) {
  if (gap?.category === "ingredient_coverage") return `Ingredient + ${gap.ingredient_label || "target"}`;
  const lane = plannerNormalizeSavedSearch(gap?.lane || {});
  const representativeSlot = Array.isArray(gap?.slot_ids) && gap.slot_ids.length ? findPlannerSlot(gap.slot_ids[0]) : null;
  const representativeState = representativeSlot ? plannerSlotState(representativeSlot) : null;
  const category = plannerGapMealCategory(gap || {}, lane, representativeSlot, representativeState);
  const categoryLabel = plannerMealCategoryOptions().find((item) => item.id === category)?.label || mealTypeLabel(category || "Meal");
  const people = plannerGapPeople(gap || {}, lane, representativeState);
  const filters = plannerGapRequiredFilters(gap || {}, lane, representativeState);
  return [categoryLabel, ...people, ...filters].filter(Boolean).join(" + ");
}

function plannerGapPacketText(packet) {
  return JSON.stringify(packet, null, 2);
}

function plannerGapFilters() {
  return [
    { id: "all", label: "All" },
    { id: "week_blockers", label: "Week blockers" },
    { id: "macro_bands", label: "Macro bands" },
    { id: "variety", label: "Variety" },
    { id: "ingredients", label: "Ingredients" },
    { id: "near_misses", label: "Near misses" },
  ];
}

function plannerGapFilterRow(gapQueue) {
  return `
    <div class="planner-gap-filter-row" role="group" aria-label="Recipe gap filters">
      ${plannerGapFilters().map((filter) => {
        const active = (state.plannerGapFilter || "all") === filter.id;
        const count = gapQueue.filter((gap) => plannerGapMatchesFilter(gap, filter.id)).length;
        return `
          <button class="${active ? "active" : ""}" type="button" data-planner-gap-filter="${escapeAttr(filter.id)}" aria-pressed="${active ? "true" : "false"}">
            <strong>${escapeHtml(filter.label)}</strong>
            <span>${escapeHtml(String(count))}</span>
          </button>
        `;
      }).join("")}
    </div>
  `;
}

function plannerGapCards(visibleGaps, allGaps) {
  if (!allGaps.length) {
    return `
      <div class="planner-gap-empty">
        <strong>No recipe gaps</strong>
        <span>Planner stock is at the starter target for this filter.</span>
      </div>
    `;
  }
  const filter = state.plannerGapFilter || "all";
  const filteredCount = allGaps.filter((gap) => plannerGapMatchesFilter(gap, filter)).length;
  return `
    ${visibleGaps.map((gap) => plannerGapCard(gap)).join("")}
    ${filteredCount > visibleGaps.length ? `
      <div class="planner-gap-more">
        Showing ${escapeHtml(String(visibleGaps.length))} of ${escapeHtml(String(filteredCount))}. Saved search scoreboard below keeps the full count visible.
      </div>
    ` : ""}
  `;
}

function plannerGapCard(gap) {
  return `
    <article class="planner-gap-card ${escapeAttr(gap.category)}">
      <div class="planner-gap-rank">
        <strong>#${escapeHtml(String(gap.priority_rank || ""))}</strong>
        <span>${escapeHtml(plannerGapCategoryLabel(gap))}</span>
      </div>
      <div class="planner-gap-main">
        <div class="planner-gap-title-row">
          <strong>${escapeHtml(gap.request_summary)}</strong>
          <em>${escapeHtml(plannerGapBandLabel(gap))}</em>
        </div>
        <p>${escapeHtml(gap.priority_reason)}</p>
        <div class="planner-gap-tag-row">
          <span class="planner-icon-row">${plannerIconChips(gap.required_tags, 6)}</span>
          <span>${escapeHtml(plannerChipLabels(gap.required_tags).join(", ") || "no required filters")}</span>
        </div>
        <div class="planner-gap-meta-grid">
          ${plannerMiniMetric("People", gap.people.join(", ") || "slot-specific")}
          ${plannerMiniMetric("Target", plannerGapTargetSummary(gap))}
          ${plannerMiniMetric("Usable", `${gap.usable_count} ready`)}
          ${plannerMiniMetric("In review", `${gap.pipeline_count || 0} reserved`)}
        </div>
        <div class="planner-gap-hard-rules">Hard rules: ${escapeHtml(plannerGapHardExclusionSummary())}</div>
        ${plannerNearMissPills(gap.near_miss_counts)}
      </div>
    </article>
  `;
}

function plannerGapCategoryLabel(gap) {
  if (gap.category === "week_blocker") return "Week blocker";
  if (gap.category === "macro_band") return "Macro band";
  if (gap.category === "variety") return "Variety";
  if (gap.category === "ingredient_coverage") return "Ingredient";
  return "Gap";
}

function plannerWeekBlockerGaps() {
  const groups = new Map();
  (currentPlannerTemplate()?.days || []).forEach((day) => {
    (day.slots || []).forEach((slot) => {
      const slotState = plannerSlotState(slot);
      if (slot.slot_type !== "meal" || !slotState.required || slotState.slot_status !== "planner_recipe") return;
      if (plannerSlotMatchingCount(slot, slotState) > 0) return;
      if (plannerSlotPipelineCount(slot, slotState) > 0) return;
      const lane = plannerLaneForSlot(slot, slotState);
      const bandId = plannerPrimaryBandForSlot(slot, slotState);
      const key = [
        "week",
        lane.lane_id,
        bandId,
        [...slotState.people].sort().join("+"),
        [...slotState.chips].sort().join("+"),
      ].join("|");
      if (!groups.has(key)) {
        groups.set(key, {
          category: "week_blocker",
          filter: "week_blockers",
          lane,
          lane_id: lane.lane_id,
          missing_band: bandId,
          required_tags: [...slotState.chips],
          people: [...slotState.people],
          slot_ids: [],
          slot_labels: [],
          usable_count: 0,
          near_miss_counts: plannerEmptyNearMissCounts(),
        });
      }
      const group = groups.get(key);
      group.slot_ids.push(slot.slot_id);
      group.slot_labels.push(`${day.day} ${plannerSlotShortRole(slot)}`.trim());
      group.usable_count += plannerSlotMatchingCount(slot, slotState);
      group.near_miss_counts = plannerMergeNearMissCounts([
        group.near_miss_counts,
        plannerNearMissCountsForSlot(slot, slotState, bandId),
      ]);
    });
  });

  return [...groups.values()].map((gap) => {
    const slotCount = gap.slot_ids.length;
    const firstLabel = gap.slot_labels[0] || gap.lane.label || "slot";
    const representativeSlot = findPlannerSlot(gap.slot_ids[0]);
    const representativeState = representativeSlot ? plannerSlotState(representativeSlot) : null;
    const nearMissCounts = representativeSlot && representativeState ? plannerNearMissCountsForSlot(representativeSlot, representativeState, gap.missing_band) : gap.near_miss_counts;
    const bandCounts = gap.missing_band && gap.missing_band !== "finisher" ? plannerLaneBandCounts(gap.lane, plannerUsableRecipes())?.[gap.missing_band] : null;
    const currentCount = typeof bandCounts?.current_count === "number" ? bandCounts.current_count : gap.usable_count;
    const pipelineCount = typeof bandCounts?.pipeline_count === "number" ? bandCounts.pipeline_count : 0;
    const effectiveCount = typeof bandCounts?.effective_count === "number" ? bandCounts.effective_count : currentCount + pipelineCount;
    const targetCount = typeof bandCounts?.target_count === "number" ? bandCounts.target_count : Math.max(1, slotCount);
    const slotWeight = gap.missing_band === "finisher" ? 15 : 70;
    const requestSummary = gap.missing_band === "finisher" ? (gap.lane.label || gap.lane_id) : `${plannerBandLabel(gap.missing_band)} ${gap.lane.label || gap.lane_id}`;
    const priorityReason = slotCount === 1
      ? `${firstLabel} cannot find matches`
      : `${slotCount} ${gap.lane.label || "meal"} holes cannot find matches`;
    return {
      ...gap,
      request_summary: requestSummary,
      priority_reason: priorityReason,
      target_range_by_person: plannerGapTargetRanges({ slot: findPlannerSlot(gap.slot_ids[0]), lane: gap.lane, people: gap.people, bandId: gap.missing_band }),
      near_miss_counts: nearMissCounts,
      current_count: currentCount,
      pipeline_count: pipelineCount,
      effective_count: effectiveCount,
      target_count: targetCount,
      priority_score: 10000 + plannerLanePriorityScore(gap.lane_id) + plannerBandPriorityScore(gap.missing_band) + (slotCount * slotWeight) + plannerNearMissBoost(nearMissCounts),
    };
  });
}

function plannerMacroBandGaps(capacityRows) {
  const gaps = [];
  capacityRows.forEach((row) => {
    plannerBandPriorityOrder().forEach((bandId) => {
      const counts = row.band_counts?.[bandId];
      if (!counts?.gap) return;
      const nearMissCounts = plannerNearMissCountsForLane(row.lane, bandId);
      gaps.push({
        category: "macro_band",
        filter: "macro_bands",
        lane: row.lane,
        lane_id: row.lane.lane_id,
        slot_ids: [],
        people: plannerLanePeopleArray(row.lane),
        required_tags: row.lane.request_tags || [],
        missing_band: bandId,
        current_count: counts.current_count,
        pipeline_count: counts.pipeline_count,
        effective_count: counts.effective_count,
        target_count: counts.target_count,
        usable_count: row.current_count,
        near_miss_counts: nearMissCounts,
        target_range_by_person: plannerGapTargetRanges({ lane: row.lane, people: plannerLanePeopleArray(row.lane), bandId }),
        request_summary: `${plannerBandLabel(bandId)} ${row.lane.label || row.lane.lane_id}`,
        priority_reason: `${plannerBandLabel(bandId)} coverage is ${counts.effective_count}/${counts.target_count} including recipes in review`,
        priority_score: 7000 + plannerLanePriorityScore(row.lane.lane_id) + plannerBandPriorityScore(bandId) + (counts.gap * 90) + plannerNearMissBoost(nearMissCounts),
      });
    });
  });
  return gaps;
}

function plannerVarietyGaps(capacityRows) {
  return capacityRows
    .filter((row) => (row.search?.variety || row.lane?.variety || row.seed_stage === "later") && row.gap > 0)
    .map((row) => {
      const bandId = plannerPrimaryBandGapId(row) || "";
      const nearMissCounts = plannerNearMissCountsForLane(row.lane, bandId);
      return {
        category: "variety",
        filter: "variety",
        lane: row.lane,
        lane_id: row.lane.lane_id,
        slot_ids: [],
        people: plannerLanePeopleArray(row.lane),
        required_tags: row.lane.request_tags || [],
        missing_band: bandId,
        current_count: row.current_count,
        pipeline_count: row.pipeline_count,
        effective_count: row.effective_count,
        target_count: row.target_count,
        usable_count: row.current_count,
        near_miss_counts: nearMissCounts,
        target_range_by_person: plannerGapTargetRanges({ lane: row.lane, people: plannerLanePeopleArray(row.lane), bandId }),
        request_summary: row.lane.label || row.lane.lane_id,
        priority_reason: `${row.lane.label || row.lane.lane_id} stock is ${row.effective_count}/${row.target_count} including recipes in review`,
        priority_score: 5200 + plannerLanePriorityScore(row.lane.lane_id) + (row.gap * 60) + plannerNearMissBoost(nearMissCounts),
      };
    });
}

function plannerIngredientCoverageGaps() {
  const groupedTargets = plannerGroupedIngredientTargets();
  const usable = plannerUsableRecipes();
  const pipeline = plannerPipelineRecipes();
  return groupedTargets.map((group) => {
    const usableCount = usable.filter((recipe) => plannerRecipeUsesIngredientTarget(recipe, group)).length;
    const pipelineCount = pipeline.filter((recipe) => plannerRecipeUsesIngredientTarget(recipe, group)).length;
    const targetCount = plannerIngredientCoverageTargetCount(group);
    const effectiveCount = usableCount + pipelineCount;
    const gap = Math.max(targetCount - effectiveCount, 0);
    if (!gap) return null;
    const possibleRecipeOptions = plannerIngredientPossibleRecipeOptions(group, usable);
    const laneId = `ingredient:${group.target_key}`;
    const lane = plannerNormalizeSavedSearch({
      search_id: laneId,
      lane_id: laneId,
      label: `Use ${group.ingredient_label}`,
      target_count: targetCount,
      meal_category: "",
      people: [],
      required_filters: [],
      target_meal_slots: [],
    });
    return {
      category: "ingredient_coverage",
      filter: "ingredients",
      lane,
      lane_id: laneId,
      slot_ids: [],
      people: [],
      required_tags: [],
      missing_band: "",
      current_count: usableCount,
      pipeline_count: pipelineCount,
      effective_count: effectiveCount,
      target_count: targetCount,
      usable_count: usableCount,
      near_miss_counts: plannerEmptyNearMissCounts(),
      target_range_by_person: [{
        person: "",
        label: `${shoppingAmountLabel(group.total_amount, group.unit)} ${group.ingredient_label} target stock`,
      }],
      ingredient_family_id: group.family_id,
      sku_code: group.sku_code,
      ingredient_label: group.ingredient_label,
      ingredient_priority: group.priority,
      ingredient_priority_label: group.priority_label,
      ingredient_target_count: group.targets.length,
      ingredient_target_amount: group.total_amount,
      ingredient_target_unit: group.unit,
      ingredient_targets: group.targets,
      possible_recipe_options: possibleRecipeOptions,
      request_summary: `More recipes that use ${group.ingredient_label}`,
      priority_reason: `${group.ingredient_label} is a ${group.priority_label} target, but only ${effectiveCount}/${targetCount} ready or in-review recipes use it`,
      priority_score: 6600 + (Number(group.priority_rank || 1) * 620) + (gap * 120) + plannerInventoryUseWeight(group.total_amount, group.unit),
    };
  }).filter(Boolean);
}

function plannerGroupedIngredientTargets() {
  const groups = new Map();
  (plannerIngredientTargetsForWeek(plannerActiveWeekStartKey()).targets || []).forEach((target) => {
    const targetKey = target.family_id || target.sku_code;
    if (!targetKey) return;
    const key = target.family_id ? `family:${target.family_id}` : `sku:${target.sku_code}`;
    const current = groups.get(key) || {
      target_key: targetKey,
      family_id: target.family_id || "",
      sku_code: target.sku_code || "",
      ingredient_label: target.ingredient_label,
      unit: target.unit,
      total_amount: 0,
      priority: target.priority,
      priority_label: target.priority_label,
      priority_rank: target.priority_rank,
      targets: [],
    };
    if (shoppingNormalizeAmountUnit(current.unit) === shoppingNormalizeAmountUnit(target.unit)) {
      current.total_amount += Number(target.amount || 0);
    }
    if (Number(target.priority_rank || 0) > Number(current.priority_rank || 0)) {
      current.priority = target.priority;
      current.priority_label = target.priority_label;
      current.priority_rank = target.priority_rank;
    }
    current.targets.push(target);
    groups.set(key, current);
  });
  return [...groups.values()].sort((a, b) => (
    b.priority_rank - a.priority_rank
    || a.ingredient_label.localeCompare(b.ingredient_label)
  ));
}

function plannerIngredientCoverageTargetCount(group = {}) {
  if (Number(group.priority_rank || 0) >= 3) return 4;
  if (Number(group.priority_rank || 0) >= 2) return 3;
  return 2;
}

function plannerIngredientPossibleRecipeOptions(group = {}, usableRecipes = plannerUsableRecipes()) {
  return (Array.isArray(usableRecipes) ? usableRecipes : [])
    .filter((recipe) => plannerRecipeUsesIngredientTarget(recipe, group))
    .map((recipe) => {
      const recipeId = recipeKey(recipe);
      return {
        recipe_id: recipeId,
        title: recipe.short_title || recipe.title || recipeId,
        meal_category: recipeMealCategory(recipe),
        recent_use_penalty: plannerRecipeDraftFatiguePenalty(recipeId),
      };
    })
    .sort((a, b) => (
      Number(a.recent_use_penalty || 0) - Number(b.recent_use_penalty || 0)
      || a.title.localeCompare(b.title)
    ))
    .slice(0, 12);
}

function plannerRecipeUsesIngredientTarget(recipe, group = {}) {
  return plannerInventoryRecipeRowInfos(recipe).some((rowInfo) => {
    if (group.family_id && rowInfo.family_id === group.family_id) return true;
    if (group.sku_code && rowInfo.sku_code === group.sku_code) return true;
    return false;
  });
}

function plannerLaneForSlot(slot, slotState) {
  return plannerSearchForSlot(slot, slotState);
}

function plannerLaneById(laneId) {
  return plannerSavedSearches().find((search) => search.search_id === laneId || search.lane_id === laneId) || plannerNormalizeSavedSearch({
    search_id: laneId,
    label: laneId.replace(/_/g, " "),
    target_count: 0,
    meal_category: "",
    people: [],
    required_filters: [],
    target_meal_slots: [],
  });
}

function plannerPrimaryBandForSlot(slot, slotState) {
  if (isFinisherSlot(slot)) return "finisher";
  const person = plannerPrimaryPerson(slotState.people);
  const profile = profileByName(person);
  return profile ? suggestedBandForSlot(slot, profile) : "standard";
}

function plannerPrimaryPerson(people) {
  const list = Array.isArray(people) ? people : [];
  if (list.includes("Luke")) return "Luke";
  return list[0] || "Luke";
}

function plannerBandPriorityOrder() {
  return ["heavy", "standard", "light"];
}

function plannerPrimaryBandGapId(row) {
  return plannerBandPriorityOrder().find((bandId) => row.band_counts?.[bandId]?.gap > 0) || "";
}

function plannerLanePeopleArray(lane) {
  const people = plannerNormalizeSavedSearch(lane || {}).people;
  return Array.isArray(people) ? people : [];
}

function plannerLanePriorityScore(laneId) {
  const scores = {
    dinner_quick_family: 940,
    dinner_quick_fakeaway_family: 920,
    dinner_fakeaway_family: 900,
    dinner_adult_only: 860,
    dinner_family: 820,
    evening_finisher: 500,
    evening_finishers: 500,
    breakfast: 650,
    breakfasts: 650,
    luke_lunch_1: 640,
    luke_lunch_2: 630,
    sarah_wfh_lunch: 620,
    sarah_lunch: 600,
    sarah_louis_shared_lunch: 610,
    dinner_fish: 560,
    dinner_oily_fish: 540,
  };
  return scores[laneId] || 400;
}

function plannerBandPriorityScore(bandId) {
  const scores = { heavy: 190, standard: 130, light: 100, finisher: 40 };
  return scores[bandId] || 0;
}

function plannerDirectSlotGap(slot, slotState) {
  const lane = plannerLaneForSlot(slot, slotState);
  const bandId = plannerPrimaryBandForSlot(slot, slotState);
  const pipelineCount = plannerSlotPipelineCount(slot, slotState);
  return {
    category: "week_blocker",
    filter: "week_blockers",
    lane,
    lane_id: lane.lane_id,
    missing_band: bandId,
    required_tags: slotState.chips || [],
    people: slotState.people || [],
    slot_ids: [slot.slot_id],
    usable_count: plannerSlotMatchingCount(slot, slotState),
    pipeline_count: pipelineCount,
    near_miss_counts: plannerNearMissCountsForSlot(slot, slotState, bandId),
    target_range_by_person: plannerGapTargetRanges({ slot, lane, people: slotState.people || [], bandId }),
    request_summary: bandId === "finisher" ? (lane.label || lane.lane_id) : `${plannerBandLabel(bandId)} ${lane.label || lane.lane_id}`,
    priority_reason: `${plannerSlotDay(slot.slot_id)?.day || ""} ${plannerSlotShortRole(slot)} cannot find matches`.trim(),
    priority_score: 0,
  };
}

function plannerGapForSlot(gapQueue, slotId) {
  return (gapQueue || []).find((gap) => Array.isArray(gap.slot_ids) && gap.slot_ids.includes(slotId)) || null;
}

function plannerGapTargetRanges({ slot = null, lane = null, people = [], bandId = "" }) {
  const targetPeople = people.length ? people : plannerLanePeopleArray(lane || {});
  return targetPeople.map((person) => {
    const profile = profileByName(person);
    const target = slot ? profileMealTargetForSlot(profile, slot) : profileMealTargetForLane(profile, lane || {});
    if (!profile || !target) return { person, label: `${person}: use saved profile target` };
    if (bandId === "finisher") {
      const kcalMin = cleanMacroInput(target.kcal_target_min);
      const kcalMax = cleanMacroInput(target.kcal_target_max);
      const proteinMin = cleanMacroInput(target.protein_target_min_g);
      const proteinMax = cleanMacroInput(target.protein_target_max_g);
      return {
        person,
        band_id: "finisher",
        kcal_min: kcalMin,
        kcal_max: kcalMax,
        protein_min_g: proteinMin,
        protein_max_g: proteinMax,
        label: `${person}: ${rangeLabel(kcalMin, kcalMax, "kcal") || "kcal target"}, ${rangeLabel(proteinMin, proteinMax, "g protein") || "protein target"}`,
      };
    }
    const band = macroBandsForMealTarget(target).find((item) => item.band_id === bandId);
    return {
      person,
      band_id: band?.band_id || bandId || "",
      kcal_min: band ? cleanMacroInput(band.kcal_min) : "",
      kcal_max: band ? cleanMacroInput(band.kcal_max) : "",
      protein_min_g: band ? cleanMacroInput(band.protein_min_g) : "",
      protein_max_g: band ? cleanMacroInput(band.protein_max_g) : "",
      label: band ? `${person}: ${band.kcal_label}, ${band.protein_label}` : `${person}: use saved profile target`,
    };
  });
}

function plannerGapTargetSummary(gap) {
  if (gap.category === "ingredient_coverage") {
    return `${shoppingAmountLabel(gap.ingredient_target_amount, gap.ingredient_target_unit)} ${gap.ingredient_label}`;
  }
  const ranges = Array.isArray(gap.target_range_by_person) ? gap.target_range_by_person : [];
  return ranges.map((range) => range.label).slice(0, 2).join(" | ") || plannerLaneTargetSummary(gap.lane || {});
}

function plannerGapBandLabel(gap) {
  if (gap.category === "ingredient_coverage") {
    const current = typeof gap.current_count === "number" ? gap.current_count : 0;
    const pipeline = typeof gap.pipeline_count === "number" ? gap.pipeline_count : 0;
    const effective = typeof gap.effective_count === "number" ? gap.effective_count : current + pipeline;
    return `Ingredient ${effective}/${gap.target_count || 0}`;
  }
  if (gap.missing_band === "finisher") return "Finisher gap";
  if (!gap.missing_band) return "Search stock";
  const current = typeof gap.current_count === "number" ? gap.current_count : 0;
  const pipeline = typeof gap.pipeline_count === "number" ? gap.pipeline_count : 0;
  const effective = typeof gap.effective_count === "number" ? gap.effective_count : current + pipeline;
  const target = typeof gap.target_count === "number" ? gap.target_count : "";
  return `${plannerBandLabel(gap.missing_band)}${target !== "" ? ` ${effective}/${target}` : ""}${pipeline ? " incl review" : ""}`;
}

function plannerEmptyNearMissCounts() {
  return {
    review_only: 0,
    accepted_not_planner_allowed: 0,
    repair_needed: 0,
    wrong_people: 0,
    wrong_meal_role: 0,
    wrong_tag: 0,
    wrong_macro_band: 0,
    cooldown_blocked: 0,
  };
}

function plannerMergeNearMissCounts(items) {
  return items.reduce((merged, counts) => {
    Object.entries(plannerEmptyNearMissCounts()).forEach(([key]) => {
      merged[key] = Number(merged[key] || 0) + Number(counts?.[key] || 0);
    });
    return merged;
  }, plannerEmptyNearMissCounts());
}

function plannerNearMissCountsForSlot(slot, slotState, bandId) {
  const counts = plannerEmptyNearMissCounts();
  recipes().forEach((recipe) => {
    const reason = plannerNearMissReasonForSlot(recipe, slot, slotState, bandId);
    if (reason) counts[reason] += 1;
  });
  return counts;
}

function plannerNearMissCountsForLane(lane, bandId) {
  const counts = plannerEmptyNearMissCounts();
  recipes().forEach((recipe) => {
    const reason = plannerNearMissReasonForLane(recipe, lane, bandId);
    if (reason) counts[reason] += 1;
  });
  return counts;
}

function plannerNearMissReasonForSlot(recipe, slot, slotState, bandId) {
  const mealTypes = plannerMealTypesForSlot(slot);
  if (mealTypes.length && !mealTypes.includes(recipe.meal_type)) return "";
  const people = Array.isArray(recipe.people) ? recipe.people : [];
  if (!plannerPeopleSetMatches(slotState.people || [], people)) return "wrong_people";
  if (!plannerRecipeMatchesTargetMealSlots(recipe, plannerTargetMealSlotsForSlot(slot, slotState), slotState.meal_category || plannerMealCategoryForSlot(slot))) return "wrong_meal_role";
  if (slotState.chips?.includes("adult-only") && people.includes("Louis")) return "wrong_people";
  if (plannerRecipeFailsSlotTags(recipe, slotState)) return "wrong_tag";
  if (bandId && bandId !== "finisher" && !recipeMatchesSlotMacroBand(recipe, slot, slotState)) return "wrong_macro_band";
  return plannerRecipeGateNearMissReason(recipe);
}

function plannerNearMissReasonForLane(recipe, lane, bandId) {
  const search = plannerNormalizeSavedSearch(lane || {});
  if (search.meal_category && recipeMealCategory(recipe) !== search.meal_category) return "";
  const people = Array.isArray(recipe.people) ? recipe.people : [];
  if (search.people.length && !plannerPeopleSetMatches(search.people, people)) return "wrong_people";
  if (!plannerRecipeMatchesTargetMealSlots(recipe, search.target_meal_slots, search.meal_category)) return "wrong_meal_role";
  if ((search.required_filters || []).some((filterId) => !plannerRecipeMatchesFilter(recipe, filterId))) return "wrong_tag";
  if (bandId && bandId !== "finisher" && !recipeMatchesLaneMacroBand(recipe, search, bandId)) return "wrong_macro_band";
  return plannerRecipeGateNearMissReason(recipe);
}

function plannerRecipeFailsSlotTags(recipe, slotState) {
  const chips = slotState.chips || [];
  return chips.some((filterId) => !plannerRecipeMatchesFilter(recipe, filterId));
}

function plannerRecipeGateNearMissReason(recipe) {
  if (plannerRecipeOnCooldown(recipe)) return "cooldown_blocked";
  if (hasRepairDebt(recipe)) return "repair_needed";
  if (recipe.status === "needs_review") return "review_only";
  if (recipe.status === "approved" && hasAcceptedPlannerReviewStatus(recipe) && recipe.algorithmic_planning_allowed !== true) return "accepted_not_planner_allowed";
  return "";
}

function plannerNearMissTotal(counts) {
  return Object.values(counts || {}).reduce((total, value) => total + Number(value || 0), 0);
}

function plannerNearMissBoost(counts) {
  return Math.min(260, (Number(counts?.review_only || 0) * 12) + (Number(counts?.accepted_not_planner_allowed || 0) * 24) + (Number(counts?.repair_needed || 0) * 8));
}

function plannerNearMissPills(counts) {
  const labels = [
    ["review_only", "review-only"],
    ["accepted_not_planner_allowed", "accepted gated"],
    ["repair_needed", "repair"],
    ["wrong_people", "wrong people"],
    ["wrong_meal_role", "wrong meal"],
    ["wrong_tag", "wrong tag"],
    ["wrong_macro_band", "wrong band"],
    ["cooldown_blocked", "cooldown later"],
  ];
  return `
    <div class="planner-near-miss-row" aria-label="Near miss reasons">
      ${labels.map(([key, label]) => `
        <span class="${Number(counts?.[key] || 0) ? "active" : ""}">
          ${escapeHtml(label)} ${escapeHtml(String(counts?.[key] || 0))}
        </span>
      `).join("")}
    </div>
  `;
}

function plannerCapacityRows() {
  const usable = plannerUsableRecipes();
  const pipeline = plannerPipelineRecipes();
  return plannerSavedSearches().map((search) => {
    const currentCount = usable.filter((recipe) => recipeMatchesSavedSearch(recipe, search)).length;
    const pipelineCount = pipeline.filter((recipe) => recipeMatchesSavedSearch(recipe, search)).length;
    const effectiveCount = currentCount + pipelineCount;
    const targetCount = Number(search.target_count || 0);
    const bandCounts = plannerLaneBandCounts(search, usable, pipeline);
    return {
      search,
      lane: search,
      current_count: currentCount,
      pipeline_count: pipelineCount,
      effective_count: effectiveCount,
      target_count: targetCount,
      band_counts: bandCounts,
      gap: Math.max(targetCount - effectiveCount, 0),
    };
  });
}

function recipeMatchesPlannerLane(recipe, lane) {
  return recipeMatchesSavedSearch(recipe, lane);
}

function recipeMatchesSavedSearch(recipe, search) {
  const savedSearch = plannerNormalizeSavedSearch(search || {});
  if (savedSearch.meal_category && recipeMealCategory(recipe) !== savedSearch.meal_category) return false;
  const people = Array.isArray(recipe.people) ? recipe.people : [];
  if (savedSearch.people.length && !plannerPeopleSetMatches(savedSearch.people, people)) return false;
  if (!plannerRecipeMatchesTargetMealSlots(recipe, savedSearch.target_meal_slots, savedSearch.meal_category)) return false;
  return (savedSearch.required_filters || []).every((filterId) => plannerRecipeMatchesFilter(recipe, filterId));
}

function plannerPeopleSetMatches(requiredPeople = [], recipePeople = []) {
  const required = [...new Set((requiredPeople || []).filter(Boolean))].sort();
  const actual = [...new Set((recipePeople || []).filter(Boolean))].sort();
  return required.length === actual.length && required.every((person, index) => person === actual[index]);
}

function plannerRecipeMatchesTargetMealSlots(recipe, targetMealSlots = [], category = "") {
  const targets = (Array.isArray(targetMealSlots) ? targetMealSlots : []).map(plannerNormalizeMealSlotId).filter(Boolean);
  if (!targets.length) return true;
  const recipeSlot = plannerNormalizeMealSlotId(recipe?.meal_slot || "");
  const recipeCategory = recipeMealCategory(recipe);
  const searchCategory = plannerValidMealCategory(category) || recipeCategory;
  if (!recipeSlot) return true;
  if (recipeSlot && targets.includes(recipeSlot)) return true;
  if (recipeCategory === "breakfast" && targets.includes("breakfast")) return true;
  if (recipeCategory === "dinner" && targets.includes("dinner")) return true;
  if (recipeCategory === "finisher" && (targets.includes("finisher") || targets.includes("adult_snack"))) return true;
  if (recipeCategory === "lunch") {
    if (!recipeSlot) return targets.includes("lunch");
    if (targets.includes("sarah_lunch") && ["sarah_lunch_home", "sarah_lunch_work"].includes(recipeSlot)) return true;
    return false;
  }
  return !searchCategory || searchCategory === recipeCategory;
}

function plannerNormalizeMealSlotId(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

function recipeMealCategory(recipe) {
  const direct = String(recipe?.meal_category || "").toLowerCase();
  if (["breakfast", "lunch", "dinner", "finisher"].includes(direct)) return direct;
  return plannerCategoryFromMealType(recipe?.meal_type || "");
}

function plannerRecipeMatchesFilter(recipe, filterId) {
  const filter = plannerNormalizeFilterId(filterId);
  if (!filter) return true;
  const explicitFilters = plannerRecipeExplicitFilters(recipe);
  if (filter === "superquick") return plannerRecipeActiveMinutesAtMost(recipe, 15);
  if (explicitFilters.size) return explicitFilters.has(filter);
  if (!plannerFilterIsRegistered(filter)) return false;
  return plannerRecipeMatchesLegacyFilter(recipe, filter);
}

function plannerRecipeActiveMinutesAtMost(recipe, maxMinutes) {
  const minutes = recipeActiveMinutes(recipe);
  return Boolean(minutes) && minutes <= maxMinutes;
}

function plannerRecipeMatchesLegacyFilter(recipe, filter) {
  const people = Array.isArray(recipe.people) ? recipe.people : [];
  const text = recipePlannerSearchText(recipe);
  const activeMinutes = recipeActiveMinutes(recipe);
  if (filter === "normal") return !activeMinutes || activeMinutes > 35;
  if (filter === "superquick") return plannerRecipeActiveMinutesAtMost(recipe, 15);
  if (filter === "quick") return !activeMinutes || activeMinutes <= 35;
  if (filter === "no-cook") return /(no-cook|no cook|cold|salad|wrap|pitta|sandwich|box|fresh|wfh|sarah-wfh)/i.test(text);
  if (filter === "fakeaway") return /(fakeaway|takeaway|burger|kebab|taco|wrap|curry|noodle|quesadilla|pizza)/i.test(text);
  if (filter === "adult-only") return recipe.meal_type === "adult_snack" || (!people.includes("Louis") && (people.includes("Luke") || people.includes("Sarah")));
  if (filter === "family") return ["Luke", "Sarah", "Louis"].every((person) => people.includes(person));
  if (filter === "sarah-only") return people.length === 1 && people.includes("Sarah");
  if (filter === "luke-only") return people.length === 1 && people.includes("Luke");
  if (filter === "sarah-louis") return people.length === 2 && people.includes("Sarah") && people.includes("Louis");
  if (filter === "protein:fish") return /(fish|salmon|cod|hake|white fish|mackerel|sardine)/i.test(text) && !/(prawn|shrimp|tuna)/i.test(text);
  if (filter === "protein:oily-fish") return /(salmon|mackerel|sardine)/i.test(text);
  if (filter === "protein:prawn") return /(prawn|shrimp)/i.test(text);
  if (filter === "protein:tuna") return /tuna/i.test(text);
  if (filter === "protein:chicken") return /chicken/i.test(text);
  if (filter === "protein:beef") return /(beef|steak|mince)/i.test(text);
  if (filter === "protein:pork") return /(pork|ham|sausage|chorizo|bacon)/i.test(text);
  if (filter === "protein:egg") return /(egg|eggs|omelette|scrambled)/i.test(text);
  if (filter === "protein:beans") return /\b((black|kidney|baked|mixed|cannellini|butter|borlotti|pinto|haricot|refried) beans?|bean salsa|bean chilli|lentils?|chickpeas?|hummus|dhal|dal)\b/i.test(text);
  if (filter === "protein:dairy") return /(yoghurt|yogurt|cheese|mozzarella|cheddar|feta|cottage cheese)/i.test(text);
  if (filter === "prep-ahead") return /(prep-ahead|prep ahead|batch|two-day|2-day|make ahead)/i.test(text);
  if (filter === "batch") return /(batch|two-day|2-day|three-day|3-day|tubs|pots)/i.test(text);
  if (filter === "work") return /(work-lunch|work lunch|luke_lunch_1|luke_lunch_2|lunch box|packed)/i.test(text);
  if (filter === "home") return /(home lunch|sarah_lunch_home|wfh|nonwork|non-working|sarah-nonwork|sarah-wfh|sarah_louis_saturday_lunch)/i.test(text);
  if (filter === "not-working") return /(nonwork|non-working|sarah-nonwork)/i.test(text);
  if (filter === "shared") return people.includes("Sarah") && people.includes("Louis");
  if (filter === "protein-led") return plannerRecipeHasProteinProof(recipe);
  if (filter === "fruit-veg-floor") return plannerRecipeHasFruitVegProof(recipe);
  if (filter === "warm") return /\b(warm|hot|microwave|baked|toast|omelette|soup|dhal|dal|cook|pan|hob|oven)\b/i.test(text);
  if (filter === "freezer-friendly") return /(freezer|freeze)/i.test(text);
  if (filter === "comfort") return /(comfort|mash|pie|burger|casserole|toast|potato|cheesy|melt)/i.test(text);
  if (filter === "salad") return /(salad|slaw|leaves|rocket)/i.test(text);
  if (filter === "soup") return /soup/i.test(text);
  if (filter === "wrap") return /(wrap|pitta|flatbread|tortilla)/i.test(text);
  if (filter === "pasta") return /(pasta|penne|spaghetti|fusilli|macaroni|noodle)/i.test(text);
  if (filter === "bowl") return /(bowl|pot|tub)/i.test(text);
  if (filter === "traybake") return /(traybake|tray bake|sheet pan)/i.test(text);
  if (filter === "one-pan") return /(one-pan|one pan|skillet|stir-fry|stir fry)/i.test(text);
  if (filter.startsWith("cuisine:")) return recipeCuisineMatchesLegacyText(recipe, filter.replace("cuisine:", ""), text);
  if (filter === "light" || filter === "standard" || filter === "heavy") return Array.isArray(recipe.macro_bands) ? recipe.macro_bands.includes(filter) : false;
  if (filter === "simple-cook") return plannerRecipeMatchesFilter(recipe, "warm") && activeMinutes <= 30;
  return false;
}

function plannerRecipeExplicitFilters(recipe) {
  const values = [
    ...(Array.isArray(recipe?.planner_filters) ? recipe.planner_filters : []),
    ...(Array.isArray(recipe?.filters) ? recipe.filters : []),
    ...(Array.isArray(recipe?.tags) ? recipe.tags : []),
    ...(Array.isArray(recipe?.planner_tags) ? recipe.planner_tags : []),
  ];
  return new Set(values.map((value) => plannerNormalizeFilterId(value)).filter(Boolean));
}

function recipeCuisineMatchesLegacyText(recipe, cuisineId, text) {
  if (String(recipe?.cuisine || "").toLowerCase() === cuisineId) return true;
  const patterns = {
    british: /(british|sourdough|toast|jacket potato|potato|mash|sausages|breakfast)/i,
    indian: /\b(indian|curry|dhal|dal|tikka|tandoori|masala|korma|jalfrezi|bhuna|saag|chutney)\b/i,
    mexican: /(mexican|fajita|burrito|enchilada|quesadilla|taco|salsa)/i,
    korean: /(korean|gochujang|kimchi)/i,
    italian: /(italian|pasta|penne|pizza|pesto|mozzarella|romesco)/i,
    "middle-eastern": /(middle eastern|moroccan|shawarma|kofta|kibbeh|harissa|couscous|apricot)/i,
    greek: /(souvlaki|greek salad|greek plate)/i,
    american: /(american|burger|smash|smokehouse|ranch|cajun|bbq|barbecue)/i,
    chinese: /(chinese|stir-fry|stir fry|soy|ginger|noodle)/i,
    thai: /thai/i,
    japanese: /(japanese|teriyaki|ramen)/i,
    mediterranean: /(mediterranean|lemon|olive|feta|tomato cucumber)/i,
    fusion: /fusion/i,
    none: /^$/,
  };
  return patterns[cuisineId]?.test(text) || false;
}

function plannerRecipeHasProteinProof(recipe) {
  const people = Array.isArray(recipe.people) ? recipe.people : [];
  return people.some((person) => {
    const totals = recipePersonTotals(recipe, person);
    return Number(totals?.protein_g || totals?.protein || 0) > 0;
  });
}

function plannerRecipeHasFruitVegProof(recipe) {
  const people = Array.isArray(recipe.people) ? recipe.people : [];
  return people.some((person) => {
    const totals = recipePersonTotals(recipe, person);
    return Number(totals?.fruit_veg_portions || totals?.fruitveg_portions || totals?.fruit_veg_grams || 0) > 0;
  });
}

function recipeActiveMinutes(recipe) {
  const timing = recipe?.timing || {};
  const direct = Number(timing.total_active_minutes || timing.active_minutes || 0);
  if (Number.isFinite(direct) && direct > 0) return direct;
  const prep = Number(timing.prep_active_minutes || timing.prep_ahead_active_minutes || 0);
  const cook = Number(timing.cook_serve_active_minutes || 0);
  const total = prep + cook;
  if (Number.isFinite(total) && total > 0) return total;
  const fallback = Number(timing.total_minutes || 0);
  return Number.isFinite(fallback) ? fallback : 0;
}

function recipePlannerSearchText(recipe) {
  const source = recipe?.source || {};
  return [
    recipe.title,
    recipe.short_title,
    recipe.summary,
    recipe.meal_type,
    recipe.meal_slot,
    recipe.review_note,
    recipe.source_idea_code,
    source.queue_file,
    source.idea_code,
    source.notes,
    ...(Array.isArray(recipe.planner_filters) ? recipe.planner_filters : []),
    ...(Array.isArray(recipe.filters) ? recipe.filters : []),
    ...(Array.isArray(recipe.tags) ? recipe.tags : []),
    ...(Array.isArray(recipe.planner_tags) ? recipe.planner_tags : []),
    Object.keys(recipe.flags || {}).join(" "),
    Object.keys(source.flags || {}).join(" "),
  ].filter(Boolean).join(" ").toLowerCase();
}

function plannerLaneBandCounts(lane, usable, pipeline = plannerPipelineRecipes()) {
  const targets = state.macroPolicyData?.lane_band_targets || { light: 3, standard: 4, heavy: 3 };
  return Object.fromEntries(Object.entries(targets).map(([bandId, targetCount]) => {
    const currentCount = usable.filter((recipe) => recipeMatchesPlannerLane(recipe, lane) && recipeMatchesLaneMacroBand(recipe, lane, bandId)).length;
    const pipelineCount = pipeline.filter((recipe) => recipeMatchesPlannerLane(recipe, lane) && recipeMatchesLaneMacroBand(recipe, lane, bandId)).length;
    const effectiveCount = currentCount + pipelineCount;
    return [bandId, {
      current_count: currentCount,
      pipeline_count: pipelineCount,
      effective_count: effectiveCount,
      target_count: Number(targetCount || 0),
      gap: Math.max(Number(targetCount || 0) - effectiveCount, 0),
    }];
  }));
}

function recipeMatchesLaneMacroBand(recipe, lane, bandId) {
  const search = plannerNormalizeSavedSearch(lane || {});
  const people = plannerLaneRequiredPeople(search, recipe);
  if (!people.length) return false;
  let checkedTargets = 0;
  const matchedKnownTargets = people.every((person) => {
    const profile = profileByName(person);
    const target = profileMealTargetForLane(profile, search);
    if (!target) return true;
    checkedTargets += 1;
    const totals = recipePersonTotals(recipe, person);
    const kcal = Number(totals?.kcal || totals?.energy_kcal || 0);
    return macroBandForKcal(kcal, macroBandsForMealTarget(target)) === bandId;
  });
  return checkedTargets > 0 && matchedKnownTargets;
}

function plannerLaneRequiredPeople(lane, recipe = null) {
  const search = plannerNormalizeSavedSearch(lane || {});
  const people = search.people;
  if (Array.isArray(people) && people.length) return people;
  return Array.isArray(recipe?.people) ? recipe.people : [];
}

function profileMealTargetForLane(profile, lane) {
  const slots = plannerLaneMealSlots(lane);
  const targets = Array.isArray(profile?.meal_targets) ? profile.meal_targets : [];
  return targets.find((target) => slots.includes(target.meal_slot)) || null;
}

function plannerLaneCard(row) {
  const percent = row.target_count ? Math.min(100, Math.round((row.effective_count / row.target_count) * 100)) : 0;
  const search = row.search || row.lane;
  const filters = search.required_filters || search.request_tags || [];
  return `
    <article class="planner-lane-card">
      <div>
        <strong>${escapeHtml(search.label || search.search_id || search.lane_id)}</strong>
        <span>${escapeHtml(filters.join(", ") || "all recipes in category")}</span>
      </div>
      <div class="planner-lane-progress" aria-label="${escapeAttr(search.label || search.search_id || search.lane_id)} saved search coverage">
        <span style="width: ${percent}%"></span>
      </div>
      <div class="planner-lane-count">
        <strong>${escapeHtml(String(row.effective_count))}/${escapeHtml(String(row.target_count))}</strong>
        <em>${escapeHtml(`${row.current_count} ready, ${row.pipeline_count} in review${row.gap ? `, ${row.gap} needed` : ""}`)}</em>
      </div>
      <div class="planner-band-count-row">
        ${plannerLaneBandBadges(row)}
      </div>
    </article>
  `;
}

function plannerLaneBandBadges(row) {
  return Object.entries(row.band_counts || {}).map(([bandId, counts]) => `
    <span class="${counts.gap ? "" : "ready"}">
      ${escapeHtml(plannerBandShortLabel(bandId))} ${escapeHtml(String(counts.effective_count))}/${escapeHtml(String(counts.target_count))}${counts.pipeline_count ? escapeHtml(` (+${counts.pipeline_count})`) : ""}
    </span>
  `).join("");
}

function plannerRequestGuidePreview(capacityRows) {
  const gaps = capacityRows.filter((row) => row.gap > 0).slice(0, 6);
  if (!gaps.length) return `<div class="empty">No request gaps. Planner stock is at starter target.</div>`;
  return gaps.map((row) => {
    const people = plannerLanePeople(row.lane);
    const targets = plannerLaneTargetSummary(row.lane);
    const bandGap = plannerLanePrimaryBandGap(row);
    return `
      <article class="planner-request-card">
        <strong>${escapeHtml(row.lane.label || row.lane.lane_id)}</strong>
        <span>People: ${escapeHtml(people)}</span>
        <span>Required filters: ${escapeHtml((row.lane.required_filters || row.lane.request_tags || []).join(", ") || "all recipes in category")}</span>
        <span>Band gap: ${escapeHtml(bandGap)}</span>
        <span>Targets: ${escapeHtml(targets)}</span>
        <span>Hard exclusions: ${escapeHtml(plannerHardExclusions().join("; ") || "profile hard rules")}</span>
        <em>${escapeHtml(`${row.current_count} ready, ${row.pipeline_count} in review, ${row.gap} still needed`)}</em>
      </article>
    `;
  }).join("");
}

function plannerLanePrimaryBandGap(row) {
  const missing = Object.entries(row.band_counts || {}).find(([, counts]) => counts.gap > 0);
  if (!missing) return "none";
  const [bandId, counts] = missing;
  return `${plannerBandLabel(bandId)} ${counts.effective_count}/${counts.target_count}${counts.pipeline_count ? ` including ${counts.pipeline_count} in review` : ""}`;
}

function plannerLanePeople(lane) {
  const people = plannerNormalizeSavedSearch(lane || {}).people;
  if (Array.isArray(people) && people.length) return people.join(", ");
  return "slot-specific";
}

function plannerLaneTargetSummary(lane) {
  const mealSlots = plannerLaneMealSlots(lane);
  const people = plannerNormalizeSavedSearch(lane || {}).people;
  const profiles = (state.profileIndex?.people || []).filter((profile) => !Array.isArray(people) || people.includes(profile.person));
  const summaries = profiles.map((profile) => plannerProfileMealTarget(profile, mealSlots)).filter(Boolean).slice(0, 3);
  return summaries.join(" | ") || "use profile meal target ranges";
}

function plannerLaneMealSlots(lane) {
  const search = plannerNormalizeSavedSearch(lane || {});
  if (Array.isArray(search.target_meal_slots) && search.target_meal_slots.length) return search.target_meal_slots;
  const id = search.search_id || search.lane_id || "";
  if (id === "breakfast") return ["breakfast"];
  if (id === "breakfasts") return ["breakfast"];
  if (id === "luke_lunch_1") return ["luke_lunch_1"];
  if (id === "luke_lunch_2") return ["luke_lunch_2"];
  if (id === "sarah_wfh_lunch" || id === "sarah_work_lunch") return ["sarah_lunch_work", "sarah_lunch_home", "sarah_lunch"];
  if (id === "sarah_lunch" || id === "sarah_home_lunch") return ["sarah_lunch_home", "sarah_lunch"];
  if (id === "sarah_louis_shared_lunch") return ["sarah_louis_saturday_lunch", "sarah_louis_lunch", "sarah_lunch"];
  if (id === "evening_finisher" || id === "evening_finishers") return ["adult_snack"];
  if (id.includes("dinner") || id.includes("fakeaway") || id.includes("fish")) return ["dinner"];
  return [];
}

function plannerProfileMealTarget(profile, mealSlots) {
  const target = (profile.meal_targets || []).find((item) => mealSlots.includes(item.meal_slot));
  if (!target) return "";
  const kcal = rangeLabel(target.kcal_target_min, target.kcal_target_max, "kcal");
  const protein = rangeLabel(target.protein_target_min_g, target.protein_target_max_g, "g protein");
  return `${profile.person}: ${[kcal, protein].filter(Boolean).join(", ")}`;
}

function plannerHardExclusions() {
  const rules = (state.profileIndex?.people || []).flatMap((profile) => profile.food_rules || []);
  const hardRules = rules
    .filter((rule) => rule.severity === "hard")
    .map((rule) => rule.planner_impact || rule.rule_text || rule.target_label || rule.notes)
    .filter(Boolean);
  return [...new Set(hardRules)]
    .sort((a, b) => Number(/rice/i.test(b)) - Number(/rice/i.test(a)))
    .slice(0, 4);
}

function plannerGapHardExclusionSummary() {
  const rules = plannerHardExclusions();
  if (!rules.length) return "profile hard rules";
  const shown = rules.slice(0, 2);
  const remaining = Math.max(rules.length - shown.length, 0);
  return `${shown.join("; ")}${remaining ? ` +${remaining} more` : ""}`;
}

function recipes() {
  return state.recipeIndex?.recipes || [];
}

function approvedRecipes() {
  return recipes().filter((recipe) => recipe.status === "approved" && !hasBlockingRepair(recipe));
}

function reviewQueue() {
  return recipes().filter((recipe) => isImportableRecipe(recipe) && recipeDecision(recipe).send_status !== "sent");
}

function repairQueue() {
  return recipes().filter((recipe) => hasRepairDebt(recipe));
}

function sentDecisionQueue() {
  return recipes().filter((recipe) => isImportableRecipe(recipe) && recipeDecision(recipe).send_status === "sent");
}

function isImportableRecipe(recipe) {
  const reviewStatus = recipe?.review_status || "";
  return (
    recipe?.status === "needs_review" &&
    ["ready_for_luke_review", "needs_review", "ready_for_review"].includes(reviewStatus) &&
    !hasBlockingRepair(recipe)
  );
}

function hasBlockingRepair(recipe) {
  if (!recipe) return true;
  if (["needs_repair", "blocked", "stopped"].includes(recipe.status)) return true;
  if (isCompletedRepair(recipe)) return false;
  if (String(recipe.review_status || "").startsWith("blocked_")) return true;
  if (Array.isArray(recipe.person_food_rule_blocks) && recipe.person_food_rule_blocks.length) return true;
  if (Array.isArray(recipe.dinner_fruit_veg_blocks) && recipe.dinner_fruit_veg_blocks.length && !recipe.legacy_approved_before_dinner_fruit_veg_gate) return true;
  if (recipe.rice_route_decision?.dinner_status === "needs_repair") return true;
  if (Array.isArray(recipe.adult_only_lane_blocks) && recipe.adult_only_lane_blocks.length) return true;
  if (Array.isArray(recipe.fruit_veg_band_warnings) && recipe.fruit_veg_band_warnings.length) return true;
  return false;
}

function hasRepairDebt(recipe) {
  if (!recipe) return false;
  if (isCompletedRepair(recipe)) return false;
  if (recipe.status === "stopped") return false;
  if (["needs_repair", "blocked"].includes(recipe.status)) return true;
  if (recipe.review_status === "changes_requested_by_luke") return true;
  if (recipe.legacy_approved_before_dinner_fruit_veg_gate) return true;
  return hasBlockingRepair(recipe);
}

function isCompletedRepair(recipe) {
  const repairStatus = String(recipe?.repair_queue_status || "");
  const reviewStatus = String(recipe?.review_status || "");
  return (
    recipe?.status === "needs_review" &&
    ["ready_for_luke_review", "needs_review", "ready_for_review"].includes(reviewStatus) &&
    (
      repairStatus === "completed" ||
      repairStatus === "completed_repair_returned_to_review" ||
      repairStatus === "completed_returned_to_review" ||
      repairStatus === "repaired_returned_to_review"
    )
  );
}

function repairReasons(recipe) {
  const reasons = [];
  if (recipe.review_status === "changes_requested_by_luke") reasons.push("Luke requested changes");
  if (Array.isArray(recipe.person_food_rule_blocks) && recipe.person_food_rule_blocks.length) reasons.push("Person rule repair");
  if (Array.isArray(recipe.dinner_fruit_veg_blocks) && recipe.dinner_fruit_veg_blocks.length) reasons.push("Fruit/veg repair");
  if (Array.isArray(recipe.fruit_veg_band_warnings) && recipe.fruit_veg_band_warnings.length) reasons.push("Veg overfill check");
  if (Array.isArray(recipe.adult_only_lane_blocks) && recipe.adult_only_lane_blocks.length) reasons.push("Adult-only role repair");
  if (recipe.rice_route_decision?.dinner_status === "needs_repair") reasons.push("Rice repair");
  if (recipe.legacy_approved_before_dinner_fruit_veg_gate) reasons.push("Planner repair advisory");
  if (recipe.status === "needs_repair" && !reasons.length) reasons.push("Needs repair");
  return reasons;
}

function readyDecisions() {
  return reviewQueue()
    .map((recipe) => ({ recipe, decision: recipeDecision(recipe) }))
    .filter(({ decision }) => decision.decision && decision.send_status !== "sent" && decisionHasRequiredNotes(decision));
}

function decisionRequiresNotes(decision) {
  return decision?.decision === "change";
}

function decisionHasAnyNotes(decision) {
  return cleanDecisionNotes(decision?.notes || "").length > 0;
}

function decisionHasRequiredNotes(decision) {
  return !decisionRequiresNotes(decision) || decisionHasAnyNotes(decision);
}

function cleanDecisionNotes(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function currentCollectionRecipe(list = approvedRecipes()) {
  return list.find((recipe) => recipeKey(recipe) === state.selectedCollectionId) || list[0] || null;
}

function currentProfile() {
  return (state.profileIndex?.people || []).find((profile) => profile.person === state.selectedProfile) || state.profileIndex?.people?.[0] || null;
}

function recipeKey(recipe) {
  return recipe?.recipe_id || recipe?.run_slug || "";
}

function recipeMatches(recipe, key) {
  return recipe?.recipe_id === key || recipe?.run_slug === key;
}

function recipeDecision(recipe) {
  const decision = state.decisions?.[recipe?.recipe_id] || {};
  return isStaleRecipeDecision(recipe, decision) ? {} : decision;
}

function pruneStaleRecipeDecisions() {
  if (!state.decisions || typeof state.decisions !== "object") return;
  let changed = false;
  recipes().forEach((recipe) => {
    const decision = state.decisions[recipe.recipe_id];
    if (!decision || !isStaleRecipeDecision(recipe, decision)) return;
    delete state.decisions[recipe.recipe_id];
    changed = true;
  });
  if (changed) saveLocalJson(DECISION_KEY, state.decisions);
}

function isStaleRecipeDecision(recipe, decision) {
  if (!recipe || !decision || typeof decision !== "object") return false;
  if (!decision.decision && !decision.send_status) return false;
  const currentRevision = recipeCardVersion(recipe);
  if (!currentRevision) return false;
  const decisionRevision = decision.review_revision || decision.recipe_review_revision || "";
  if (decisionRevision) return decisionRevision !== currentRevision;
  const decisionTime = parseDateMs(decision.sent_at || decision.updated_at || decision.reviewed_at);
  const currentTime = parseDateMs(currentRevision);
  return Boolean(decisionTime && currentTime && decisionTime < currentTime);
}

function parseDateMs(value) {
  const ms = Date.parse(String(value || ""));
  return Number.isFinite(ms) ? ms : 0;
}

function postboxConfigured() {
  return state.postboxConfig?.status === "active" && state.postboxConfig.endpoint_url;
}

async function postboxSubmit(payload) {
  if (!postboxConfigured()) throw new Error("Postbox is not configured.");
  let response;
  try {
    response = await fetch(state.postboxConfig.endpoint_url, {
      method: "POST",
      headers: { "Content-Type": "text/plain;charset=utf-8" },
      body: JSON.stringify({ ...payload, shared_token: state.postboxConfig.shared_token }),
    });
  } catch (error) {
    throw new Error(friendlyPostboxError(error?.message || "Local decision inbox is not reachable."));
  }
  const rawBody = await response.text().catch(() => "");
  let body = null;
  try {
    body = rawBody ? JSON.parse(rawBody) : null;
  } catch {
    body = null;
  }
  if (!response.ok) {
    throw new Error(postboxHttpErrorMessage(response, body, rawBody));
  }
  return body;
}

function postboxHttpErrorMessage(response, body, rawBody = "") {
  const text = String(rawBody || "");
  if ([404, 405, 501].includes(Number(response?.status)) || /Unsupported method|Error response/i.test(text)) {
    return "Local decision inbox is not available. Start the V4 local app server, not plain http.server.";
  }
  return body?.message || body?.status || `Postbox HTTP ${response.status}`;
}

function friendlyPostboxError(message) {
  const text = String(message || "").trim();
  if (/Failed to fetch|NetworkError|Load failed|not reachable/i.test(text)) {
    return "Local decision inbox is not reachable. Start the V4 local app server, then resend.";
  }
  if (/plain http\.server|Local decision inbox is not available|Postbox HTTP (404|405|501)/i.test(text)) {
    return "Local decision inbox is not available. Start the V4 local app server, then resend.";
  }
  return text || "Decision send failed.";
}

function heroImage(recipe) {
  const visual = recipe?.review_visual;
  const assetPath = String(typeof visual === "string" ? visual : visual?.asset_path || "").trim();
  if (assetPath) {
    if (/^(https?:|data:|file:|\/)/i.test(assetPath)) return assetPath;
    return versionedRecipeImage(`./${assetPath.replace(/^(\.\/)+/, "")}`, recipe);
  }
  const slug = recipe?.run_slug || "";
  return versionedRecipeImage(slug ? `./assets/v4-${slug}.png` : "./assets/v4-chicken-fajitas.png", recipe);
}

function versionedRecipeImage(url, recipe) {
  const version = recipeCardVersion(recipe);
  if (!version || /^(https?:|data:|file:|\/)/i.test(url)) return url;
  return `${url}${url.includes("?") ? "&" : "?"}v=${encodeURIComponent(version)}`;
}

function firstParagraph(markdown, fallback) {
  const text = String(markdown || "")
    .split(/\n+/)
    .map((line) => line.replace(/^#+\s*/, "").trim())
    .filter((line) => line && !line.startsWith("-"))[1];
  return text || fallback;
}

function mealTypeLabel(value) {
  const text = String(value || "recipe").replace(/_/g, " ");
  return text.charAt(0).toUpperCase() + text.slice(1);
}

function timingLabel(recipe) {
  const timing = recipe?.timing || {};
  const minutes = Number(timing.active_minutes || timing.total_active_minutes || timing.total_minutes || 0);
  if (!minutes) return "Time saved";
  return `${minutes} min`;
}

function statusLabel(recipe) {
  const labels = {
    approved: "Approved",
    needs_review: "Needs review",
    needs_repair: "Needs repair",
    blocked: "Blocked",
  };
  return labels[recipe?.status] || "Saved";
}

function nutritionHeadline(recipe) {
  const totals = Array.isArray(recipe?.person_totals) ? recipe.person_totals : [];
  const luke = totals.find((row) => row.person === "Luke") || totals[0];
  if (!luke) return "Macros saved";
  const kcal = luke.kcal || luke.calories || luke.kcal_total;
  const protein = luke.protein_g || luke.protein;
  return [kcal ? `${number(kcal)} kcal` : "", protein ? `${number(protein)}g protein` : ""].filter(Boolean).join(" - ") || "Macros saved";
}

function recipePersonTotals(recipe, person) {
  const totalSources = [
    ...(Array.isArray(recipe?.person_totals) ? recipe.person_totals : []),
    ...(Array.isArray(recipe?.nutrition_and_cost) ? recipe.nutrition_and_cost : []),
  ];
  return totalSources.find((row) => row.person === person)
    || totalSources.find((row) => String(row.person || "").toLowerCase().startsWith(`${String(person || "").toLowerCase()} `))
    || null;
}

function recipeMacroBandCards(recipe) {
  const totals = Array.isArray(recipe?.person_totals) && recipe.person_totals.length ? recipe.person_totals : (recipe?.nutrition_and_cost || []);
  if (!totals.length) return `<div class="empty">No per-person macro totals saved.</div>`;
  return totals
    .filter((row, index, list) => row.person && list.findIndex((item) => item.person === row.person) === index)
    .map((row) => {
      const profile = profileByName(row.person);
      const fit = recipeMacroBandFit(recipe, row.person);
      const kcal = row.kcal || row.energy_kcal || row.calories || "";
      const protein = row.protein_g || row.protein || "";
      return `
        <article class="recipe-macro-card">
          <strong>${escapeHtml(row.person)}</strong>
          <span>${escapeHtml([kcal ? `${number(kcal)} kcal` : "", protein ? `${number(protein)}g protein` : ""].filter(Boolean).join(" - ") || "Macros saved")}</span>
          <em>${escapeHtml(profile ? fit : "No profile target")}</em>
        </article>
      `;
    }).join("");
}

function recipeMacroBandFit(recipe, person) {
  const profile = profileByName(person);
  const totals = recipePersonTotals(recipe, person);
  if (!profile || !totals) return "No band fit saved";
  const mealTargets = (profile.meal_targets || []).filter((target) => recipeMealTypeMatchesTarget(recipe.meal_type, target.meal_slot));
  if (!mealTargets.length) return "No matching meal target";
  const kcal = Number(totals.kcal || totals.energy_kcal || totals.calories || 0);
  const fits = mealTargets.map((target) => {
    const bandId = macroBandForKcal(kcal, macroBandsForMealTarget(target));
    return bandId ? `${mealTypeLabel(target.meal_slot)}: ${plannerBandLabel(bandId)}` : `${mealTypeLabel(target.meal_slot)}: outside bands`;
  });
  const optionNote = Array.isArray(recipe.portion_options) && recipe.portion_options.length ? "portion options saved" : "no proved add/drop options yet";
  return `${fits.slice(0, 2).join("; ")} - ${optionNote}`;
}

function recipeMealTypeMatchesTarget(mealType, mealSlot) {
  if (mealType === "dinner") return mealSlot === "dinner";
  if (mealType === "breakfast") return mealSlot === "breakfast";
  if (mealType === "adult_snack") return mealSlot === "adult_snack";
  if (mealType === "lunch") return /lunch/.test(String(mealSlot || ""));
  return false;
}

function recipeCost(recipe) {
  const value = collectionRecipeCostValue(recipe);
  return value || value === 0 ? `${money(value)} per meal` : "Not saved";
}

function metric(label, value) {
  return `<div class="metric"><span>${escapeHtml(label)}</span><strong>${escapeHtml(value || "Not saved")}</strong></div>`;
}

function money(value) {
  if (value === "" || value === null || value === undefined) return "";
  const parsed = Number(value);
  return Number.isFinite(parsed) ? `GBP ${parsed.toFixed(2)}` : String(value);
}

function number(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed.toFixed(1).replace(/\.0$/, "") : String(value);
}

function rangeLabel(minValue, maxValue, suffix) {
  const min = minValue === "" || minValue === null || minValue === undefined ? "" : number(minValue);
  const max = maxValue === "" || maxValue === null || maxValue === undefined ? "" : number(maxValue);
  if (min && max) return `${min}-${max} ${suffix}`;
  if (min) return `${min}+ ${suffix}`;
  if (max) return `up to ${max} ${suffix}`;
  return "";
}

function groupBy(rows, getKey) {
  return rows.reduce((groups, row) => {
    const key = getKey(row);
    groups[key] = groups[key] || [];
    groups[key].push(row);
    return groups;
  }, {});
}

function hashString(value) {
  const text = String(value || "");
  let hash = 2166136261;
  for (let index = 0; index < text.length; index += 1) {
    hash ^= text.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return `h${(hash >>> 0).toString(16)}`;
}

function makeSubmissionId(recipe, suffix) {
  return `${recipeKey(recipe) || "recipe"}-${suffix}-${Date.now()}`.replace(/[^a-zA-Z0-9-]/g, "-");
}

function bindRouteLinks() {
  app.querySelectorAll("a[href^='#/']").forEach((link) => {
    link.addEventListener("click", (event) => {
      event.preventDefault();
      setHash(link.getAttribute("href"));
    });
  });
}

async function copyText(text) {
  try {
    const clipboard = window.navigator?.clipboard;
    if (clipboard?.writeText) {
      await clipboard.writeText(text);
      return;
    }
    throw new Error("Clipboard API unavailable");
  } catch {
    const textarea = document.createElement("textarea");
    textarea.value = text;
    textarea.style.position = "fixed";
    textarea.style.left = "-1000px";
    document.body.appendChild(textarea);
    textarea.focus();
    textarea.select();
    const copied = document.execCommand("copy");
    textarea.remove();
    if (!copied) throw new Error("Fallback copy failed");
  }
}

function loadLocalJson(key, fallback) {
  try {
    return JSON.parse(localStorage.getItem(key) || JSON.stringify(fallback));
  } catch {
    return fallback;
  }
}

function saveLocalJson(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {
    // Local storage can be unavailable in some embedded preview contexts.
  }
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function escapeAttr(value) {
  return escapeHtml(value);
}

init();

